"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[712],{5014:function(e,a,o){o.d(a,{LocaleProvider:function(){return s},b:function(){return l}});var i=o(7437),n=o(2265),t=o(6754);let r=(0,n.createContext)(t.a);function s(e){let{locale:a,children:o}=e;return(0,n.useEffect)(()=>{document.documentElement.lang=a},[a]),(0,i.jsx)(r.Provider,{value:a,children:o})}function l(){return(0,n.useContext)(r)}},6754:function(e,a,o){o.d(a,{a:function(){return i}});let i="en"},5746:function(e,a,o){o.d(a,{DT:function(){return ef},Kj:function(){return eg},N0:function(){return ev},ml:function(){return ew},QM:function(){return ey},If:function(){return eb}});var i={};o.r(i),o.d(i,{cardTitles:function(){return g},developmentalMeanings:function(){return y},jungianMeanings:function(){return f},numberMeanings:function(){return m},suitDescriptions:function(){return p}});var n={};o.r(n),o.d(n,{courtCardData:function(){return x},elementNames:function(){return z},rankDescriptions:function(){return S},rankElements:function(){return T},rankNames:function(){return k},rankOrder:function(){return L},suitElements:function(){return q},suitNames:function(){return E},suitOrder:function(){return j}});var t={};o.r(t),o.d(t,{mbtiForCard:function(){return A},mbtiTypes:function(){return P},rankAttitudes:function(){return C},suitFunctions:function(){return M}});var r={};o.r(r),o.d(r,{cardTitles:function(){return I},developmentalMeanings:function(){return N},jungianMeanings:function(){return G},numberMeanings:function(){return W},suitDescriptions:function(){return R}});var s={};o.r(s),o.d(s,{elements:function(){return V},zodiacDescriptions:function(){return F},zodiacElements:function(){return H},zodiacSymbols:function(){return D}});var l={};o.r(l),o.d(l,{chaldeanOrder:function(){return J},getPlanetBySlug:function(){return Q},getPlanetsInChaldeanOrder:function(){return O},planetSymbols:function(){return B},planetsData:function(){return Y}});var d={};o.r(d),o.d(d,{modalityDescriptions:function(){return X},numerologyMeanings:function(){return U},signsCardData:function(){return $},signsDates:function(){return _},signsModality:function(){return K},signsRulingPlanet:function(){return Z}});var c={};o.r(c),o.d(c,{courtCardData:function(){return el},elementNames:function(){return et},rankDescriptions:function(){return ei},rankElements:function(){return ea},rankNames:function(){return eo},rankOrder:function(){return es},suitElements:function(){return ee},suitNames:function(){return en},suitOrder:function(){return er}});var u={};o.r(u),o.d(u,{mbtiForCard:function(){return eh},mbtiTypes:function(){return eu},rankAttitudes:function(){return ec},suitFunctions:function(){return ed}});var h=o(5014);let m={2:"The number of duality, partnership, and choice. Two represents balance, cooperation, and the interaction between opposing forces. It speaks to decisions, relationships, and the need to find harmony between different aspects.",3:"The number of creation and growth. Three represents the synthesis of opposing forces creating something new. It speaks to creativity, self-expression, collaboration, and the manifestation of ideas into form.",4:"The number of stability and foundation. Four represents order, structure, and solid foundations. It speaks to manifestation in the material world, establishing boundaries, and creating lasting security.",5:"The number of change and disruption. Five represents instability, conflict, and necessary changes. It speaks to freedom, adventure, and the challenges that lead to growth and learning.",6:"The number of harmony and balance. Six represents equilibrium, love, and beauty. It speaks to nurturing, healing, responsibility, and finding solutions that benefit all.",7:"The number of wisdom and spirituality. Seven represents inner knowing, analysis, and spiritual awareness. It speaks to seeking deeper truth, introspection, and understanding beyond the material.",8:"The number of power and manifestation. Eight represents material success, authority, and personal power. It speaks to achievement, strength, and the ability to make things happen in the physical world.",9:"The number of completion and fulfillment. Nine represents achievement, culmination, and wisdom gained through experience. It speaks to reaching goals, spiritual awareness, and preparing for new cycles.",10:"The number of completion and new beginnings. Ten represents the end of a cycle and the potential for new starts. It speaks to manifestation, finality, and the accumulation of all previous numbers' energies."},p={Wands:"The suit of fire, passion, creativity, and ambition. Wands represent spiritual energy, inspiration, determination, strength, intuition, creativity, ambition and expansion, original thought and the seeds through which life springs forth.",Cups:"The suit of water, emotions, intuition, and relationships. Cups represent feelings, emotions, intuition, relationships, love, healing, and the soul's journey through the waters of life.",Swords:"The suit of air, intellect, thought, and action. Swords represent the mind, thoughts, communication, conflict, power, change, force, and the intellectual aspects of consciousness.",Pentacles:"The suit of earth, material concerns, and practicality. Pentacles represent manifestation, reality, physical matter, career, money, home, body, and the tangible results of our efforts in the material world."},g={"2 of Wands":{title:"Lord of Dominion",description:"Future planning and decisions, taking the first steps towards manifesting your goals."},"3 of Wands":{title:"Lord of Established Strength",description:"Expansion, foresight, and leadership in ventures that are beginning to show results."},"4 of Wands":{title:"Lord of Perfected Work",description:"Celebration, harmony, and the completion of a significant phase bringing joy and stability."},"5 of Wands":{title:"Lord of Strife",description:"Competition, conflict, and creative tension that drives growth through challenge."},"6 of Wands":{title:"Lord of Victory",description:"Success, recognition, and triumph after putting in the necessary effort."},"7 of Wands":{title:"Lord of Valor",description:"Standing your ground, defending your position, and maintaining courage under pressure."},"8 of Wands":{title:"Lord of Swiftness",description:"Rapid movement, swift action, and messages arriving with important news."},"9 of Wands":{title:"Lord of Great Strength",description:"Resilience, perseverance, and maintaining defensive positions while gathering inner strength."},"10 of Wands":{title:"Lord of Oppression",description:"Burden, responsibility, and the weight of success that may be becoming too heavy to bear."},"2 of Cups":{title:"Lord of Love",description:"Partnership, romance, and the harmonious union of forces in perfect balance."},"3 of Cups":{title:"Lord of Abundance",description:"Celebration, friendship, and the joyful sharing of emotional abundance."},"4 of Cups":{title:"Lord of Luxury or Blended Pleasure",description:"Contemplation, reevaluation, and possible dissatisfaction despite emotional security."},"5 of Cups":{title:"Lord of Loss in Pleasure",description:"Disappointment, emotional loss, but with hope remaining if you look beyond the spilled cups."},"6 of Cups":{title:"Lord of Pleasure",description:"Nostalgia, innocent happiness, and the pure joy of sharing with others."},"7 of Cups":{title:"Lord of Illusionary Success",description:"Choices, fantasies, and the need to distinguish between dreams and reality."},"8 of Cups":{title:"Lord of Abandoned Success",description:"Moving on, seeking deeper meaning, and leaving behind what no longer serves."},"9 of Cups":{title:"Lord of Material Happiness",description:"Contentment, emotional satisfaction, and the fulfillment of wishes."},"10 of Cups":{title:"Lord of Perpetual Success",description:"Harmony, lasting happiness, and the achievement of emotional fulfillment."},"2 of Swords":{title:"Lord of Peace Restored",description:"Decision making, temporary peace through avoidance, and the need for balance."},"3 of Swords":{title:"Lord of Sorrow",description:"Heartbreak, painful truth, and the necessary process of emotional release."},"4 of Swords":{title:"Lord of Rest from Strife",description:"Recovery, meditation, and the need for contemplation and rest."},"5 of Swords":{title:"Lord of Defeat",description:"Conflict, defeat, and the hollow victory of winning at all costs."},"6 of Swords":{title:"Lord of Earned Success",description:"Transition, moving forward, and leaving troubled waters for calmer shores."},"7 of Swords":{title:"Lord of Unstable Effort",description:"Strategy, deception, and the careful evaluation of risks and ethics."},"8 of Swords":{title:"Lord of Shortened Force",description:"Restriction, self-imposed limitations, and the need to see beyond apparent barriers."},"9 of Swords":{title:"Lord of Despair and Cruelty",description:"Anxiety, nightmares, and the weight of worried thoughts in the dark night."},"10 of Swords":{title:"Lord of Ruin",description:"Painful endings, rock bottom, and the promise of light after darkness."},"2 of Pentacles":{title:"Lord of Harmonious Change",description:"Balance, adaptability, and juggling multiple responsibilities with grace."},"3 of Pentacles":{title:"Lord of Material Works",description:"Craftsmanship, collaboration, and the mastery of practical skills."},"4 of Pentacles":{title:"Lord of Earthly Power",description:"Security, control, and the need to balance material stability with generosity."},"5 of Pentacles":{title:"Lord of Material Trouble",description:"Hardship, spiritual poverty, and the need to seek help during difficult times."},"6 of Pentacles":{title:"Lord of Material Success",description:"Generosity, prosperity, and the balanced flow of giving and receiving."},"7 of Pentacles":{title:"Lord of Success Unfulfilled",description:"Assessment, patience, and the evaluation of long-term investments."},"8 of Pentacles":{title:"Lord of Prudence",description:"Skill development, dedication, and the careful attention to detail in your work."},"9 of Pentacles":{title:"Lord of Material Gain",description:"Independence, luxury, and the fruits of disciplined effort and refinement."},"10 of Pentacles":{title:"Lord of Wealth",description:"Legacy, inheritance, and the establishment of lasting material abundance."}},f={"2 of Wands":"Represents the tension between safety and adventure, the first step in individuation where one must choose between the familiar and the unknown.","3 of Wands":"Symbolizes the expansion of consciousness through active engagement with the world, representing the ego's growing awareness of its potential.","4 of Wands":"Reflects the establishment of a stable ego structure, celebrating the foundation needed for further psychological growth.","5 of Wands":"Represents the inner conflicts and competing aspects of the psyche that must be integrated for personal growth.","6 of Wands":"Symbolizes the triumph of the conscious mind in achieving recognition and validating the self's journey.","7 of Wands":"Represents the courage to maintain one's individual path despite opposition from collective forces.","8 of Wands":"Symbolizes the swift movement of psychic energy when barriers between conscious and unconscious are temporarily lifted.","9 of Wands":"Reflects the defensive structures built by the ego after experiencing challenges, showing both protection and potential limitation.","10 of Wands":"Represents the burden of consciousness and responsibility that comes with greater psychological awareness.","2 of Cups":"Symbolizes the initial recognition of the anima/animus, the first step in understanding the soul's need for emotional connection.","3 of Cups":"Represents the celebration of emotional wholeness and the integration of different aspects of the psyche.","4 of Cups":"Reflects a state of emotional stagnation where the psyche needs to recognize new possibilities for growth.","5 of Cups":"Symbolizes the necessary experience of loss and grief in the process of psychological transformation.","6 of Cups":"Represents reconnection with the inner child and the pure, unconditioned aspects of the psyche.","7 of Cups":"Symbolizes the encounter with the shadow self through illusions and projections of the unconscious.","8 of Cups":"Represents the courage to abandon old emotional patterns in search of deeper psychological truth.","9 of Cups":"Reflects the state of emotional fulfillment that comes from successful integration of conscious and unconscious elements.","10 of Cups":"Symbolizes the achievement of psychological wholeness and emotional completion.","2 of Swords":"Represents the mind's attempt to maintain balance through denial or avoidance of psychological conflict.","3 of Swords":"Symbolizes the necessary pain of becoming conscious of repressed emotional truths.","4 of Swords":"Reflects the need for psychological retreat and integration of difficult realizations.","5 of Swords":"Represents the inner conflicts and power struggles within the psyche.","6 of Swords":"Symbolizes the journey of transitioning from one state of consciousness to another.","7 of Swords":"Represents the trickster archetype and the ways we deceive ourselves.","8 of Swords":"Reflects self-imposed limitations and the fear of facing one's own shadow.","9 of Swords":"Symbolizes the night sea journey through the unconscious and confrontation with deep fears.","10 of Swords":"Represents the death of old thought patterns and the potential for psychological rebirth.","2 of Pentacles":"Represents the dynamic balance needed between material and spiritual aspects of life in the individuation process.","3 of Pentacles":"Symbolizes the integration of different aspects of the self into meaningful work.","4 of Pentacles":"Reflects the ego's attempt to maintain control and security, sometimes at the cost of growth.","5 of Pentacles":"Represents the experience of material or spiritual poverty that often precedes transformation.","6 of Pentacles":"Symbolizes the exchange between different aspects of the psyche, giving and receiving in balance.","7 of Pentacles":"Reflects the patience required in the process of psychological growth and transformation.","8 of Pentacles":"Represents the disciplined work of crafting one's individual path of individuation.","9 of Pentacles":"Symbolizes the achievement of psychological independence and self-reliance.","10 of Pentacles":"Represents the manifestation of the Self and the achievement of psychological wholeness in the material world."},y={"2 of Wands":{powerGods:"You hold the world in your hands, warrior. Two paths, two kingdoms—but you cannot conquer both at once. The weak deliberate forever; the strong choose and strike. Which realm will feel your fire first? Let hesitation be for lesser souls. Your hunger is sacred—feed it.",traditional:"Two paths unfold before you, faithful one, and the scriptures speak to both. Seek the counsel of your elders, for they have walked where you now stand. The right choice is the one that serves not your fleeting desires, but your sacred duty. Pray for discernment—the Divine reveals the proper way to those who ask with humble hearts.",modern:"Strategic decision point identified. You have gathered the data; now model the outcomes. Which path optimizes for your defined success metrics? Analysis paralysis is inefficient—set a decision deadline and commit. The opportunity cost of hesitation compounds daily. Choose the venture with the best risk-adjusted returns and execute.",postModern:"Feel into both possibilities—what does your body tell you? This choice is not just about outcomes but about who you are becoming. Consider how each path affects your relationships, your community, the web of beings touched by your decision. There is no objectively right answer; there is only the choice that honors your authentic truth in this moment.",metaModern:"Ah, the eternal crossroads—how delicious! Notice how your inner warrior wants to seize, your traditionalist seeks the proper path, your strategist calculates, and your heart feels for connection. All of them are you, all of them are wise in context. The choice itself matters less than the consciousness you bring to choosing. What if both paths lead home?"},"3 of Wands":{powerGods:"Your ships are on the horizon, returning with spoils. This is what happens when you dare greatly—the world rewards the bold. But do not rest yet, dragon. New territories await beyond that sea. You were not made to tend a single garden; you were made to blaze across continents.",traditional:"Your faithful efforts bear fruit upon the horizon—this is the reward of righteous labor. The order you serve extends its reach through your steady hands. Stand watchful at your post, for you are a steward of something greater than yourself. What returns to you belongs first to the tradition that sent it forth.",modern:"Your investments are showing returns—the strategy is validated. Now leverage this proof of concept. Scale what works, document the methodology, prepare for expansion into adjacent markets. You have first-mover advantage; capitalize on it before competitors catch up. Growth awaits those who execute on momentum.",postModern:"What returns on the horizon carries stories of everywhere it has been and everyone who touched it. Your vision expanding into the world creates ripples you cannot fully trace. Hold this power with awareness—whose voices were included in shaping this dream? Expansion can be generative or extractive; let yours honor all it encounters.",metaModern:"You stand at the edge of what you have set in motion, watching it return transformed. This is the magic of sending intention into complexity—what comes back is never quite what you expected. The expansion serves your growth, serves collective evolution, serves the cosmos playing with itself. Hold your vision lightly; let it teach you what it has learned."},"4 of Wands":{powerGods:"Tonight we feast! You have built something that stands, claimed ground that is now yours. Let them celebrate you—you have earned every raised cup and roaring cheer. But mark this: the castle is not the conquest. It is merely the throne from which you plan the next war.",traditional:"The temple stands complete, and now we gather in sacred celebration. This joy is holy because it is shared—your community rejoices with you beneath the proper banners. Honor the rituals of thanksgiving, for ceremony transforms mere success into blessed milestone. You have built according to the ancient patterns, and they have held true.",modern:"Milestone achieved—take the win. Celebrating success is strategic: it boosts team morale, attracts talent, and signals market confidence. Document what worked for the case study. But schedule this celebration; then get back to the roadmap. Success is a platform for the next objective, not a destination.",postModern:"This celebration belongs to everyone who helped weave it into being. Notice who is in the circle and who was left out. True joy is inclusive, held in community, amplified through sharing. Let this be a homecoming for all parts of yourself and all members of your chosen family. We build better together.",metaModern:"What a magnificent ritual of arrival! The structure stands, the community gathers, and the moment crystallizes. This celebration is simultaneously personal victory, tribal belonging, strategic milestone, and collective healing—all true, all dancing. Let the joy be unironic and complete. This is what we build worlds for."},"5 of Wands":{powerGods:"The arena calls and your blood sings in answer! Here among the clash of rivals is where legends are forged. Do not shrink from this chaos—wade into it with teeth bared. Every scar is a story of survival, every victory proof of your might. Let the weak seek peace; you seek glory.",traditional:"This conflict troubles you, but know that even strife has its proper place in the divine order. Test your beliefs against others—not to dominate, but to strengthen your faith through the friction. Return to the teachings when chaos swirls; they are your anchor. Let the elders judge who strays from the righteous path.",modern:"Competitive pressure is market validation—if others are fighting for this space, it has value. Analyze your competitors' strategies, identify their weaknesses, differentiate your offering. Conflict sharpens innovation. Use this friction to stress-test your approach and emerge with a stronger value proposition.",postModern:"This conflict holds multiple truths colliding—and each perspective has validity in its own context. Before seeking to win, seek to understand. What is everyone really fighting for beneath the surface? Sometimes apparent competition dissolves when deeper needs are heard. Facilitation might serve better here than victory.",metaModern:"The creative friction of perspectives clashing—what music emerges from this chaos? Each combatant carries a partial truth, a developmental gift, a piece of the puzzle. Sometimes you need the warrior's fire, sometimes the diplomat's grace. What does this moment call for? Play all positions; be attached to none. The game itself evolves."},"6 of Wands":{powerGods:"Rise up and receive what you are owed! The crowd roars your name because you have done what they could not. This moment—the laurels, the adulation—drink it deep. You have proven yourself apex among predators. Let this triumph fuel your legend and terrify your enemies.",traditional:"Accept this honor with humility, for your victory serves the greater glory. The laurel crown belongs not to you alone, but to the lineage of masters who trained you, the order that guides you, the Divine that works through you. Let your triumph inspire the faithful and demonstrate that righteousness prevails.",modern:"Recognition achieved—this validates your methodology. Leverage this win for your personal brand and professional positioning. Update the resume, share the success story, let the market know your track record. Success attracts success: clients, investors, and opportunities flow toward demonstrated competence.",postModern:"How does this recognition land in your body? Can you receive it without inflating or deflecting? Remember the collective that lifted you here—success is always relational. Use this visibility to amplify voices less heard, to share the platform. Let your triumph serve as proof of what we can build together.",metaModern:"Receive the laurels with full presence—you are simultaneously the achiever earned recognition, the humble servant of larger forces, the brand building strategic momentum, and the collective being celebrated. All perspectives true, none complete. Victory is sweeter when held lightly, shared freely, and seen as one note in a larger symphony."},"7 of Wands":{powerGods:"They come for you because you stand on the mountain they covet. Good. Let them come. You did not climb this high to surrender the peak to lesser wolves. Your fire burns hotter than their envy. Stand your ground and make them pay for every inch in blood and regret.",traditional:"You are tested, but the righteous do not yield when duty demands they stand. The ground beneath your feet was consecrated by those who came before—to abandon it would dishonor their sacrifice. Hold fast to the eternal truths. Those who assail you may be many, but you have the ancestors at your back.",modern:"You hold the high ground—defend your market position. Competitors challenge you because you have built something valuable. Analyze their attack vectors, shore up your advantages, innovate faster than they can copy. Being worth attacking means you are worth defending. Protect your competitive moat strategically.",postModern:"Before defending your position, examine it. Is this truly your ground, or are you holding space that belongs to others? What is being protected, and what is the cost of this conflict to all involved? Sometimes the bravest act is opening dialogue with those who challenge you. Boundaries can be held with compassion.",metaModern:"The challenge comes—now what response does this moment truly require? Sometimes fierce defense, sometimes graceful yielding, sometimes creative transcendence that makes the conflict irrelevant. Your task is not to always win but to always respond appropriately. What level is this being fought on? Can you shift the game?"},"8 of Wands":{powerGods:"Strike now! The winds favor the swift and fortune favors the bold. This is no time for plans and councils—this is the moment when momentum becomes unstoppable. You are the arrow loosed from the bow, and nothing can call you back. Pierce straight to the heart of your desire.",traditional:"The message flies swift and true, as ordained. When the Divine sets events in motion, the faithful must be ready to receive and act. This acceleration is not chaos—it is Providence working through aligned channels. Trust the trajectory; it follows ancient laws even as it blazes new paths.",modern:"Velocity is your advantage now. When momentum builds, ride it—rapid iteration beats perfect planning. Ship fast, gather feedback, iterate. The market rewards speed-to-execution. Clear the blockers, streamline the process, and move. First mover advantage evaporates if you hesitate.",postModern:"Energy is moving rapidly—feel the current and let it carry you. This momentum connects you to larger flows of collective intention. What messages are arriving? What communications want to move through you? Stay present even at speed; awareness prevents harm that haste can cause. Trust the process of emergence.",metaModern:"The universe accelerates through you—delightful! This swiftness is arrow, is providence, is strategy, is flow, all at once. The wizard rides the lightning without grasping it. You are not in control of this momentum; you are its instrument. Enjoy the ride while maintaining the awareness that allows graceful course correction."},"9 of Wands":{powerGods:"You are bloodied but unbroken, warrior. They thought you would fall—they were fools. Every wound you carry is proof that you cannot be destroyed. Gather your fury one more time. The final battle approaches, and you have not come this far to be defeated at the threshold of victory.",traditional:"Your wounds are marks of devotion, faithful guardian. The vigil is long, but abandoning your post is unthinkable—not when so much depends on your steadfastness. Draw strength from the martyrs who endured far worse. One final watch remains. Your duty will be remembered in the eternal ledger.",modern:"You are near the finish line but running on reserves. This is when discipline separates the successful from the almost-successful. Review your resources, optimize for the final sprint, cut non-essential efforts. The sunk costs are real, but so is the goal. Perseverance through the last 10% captures 90% of the value.",postModern:"Your weariness is valid; your wounds tell true stories. Resilience does not require denying your exhaustion. Lean on your community—you were never meant to guard this threshold alone. What would it mean to be held while you persist? Vulnerability and strength can coexist. Ask for what you need.",metaModern:"Here at the edge of endurance, notice what each voice within you says: fight on, surrender, optimize, rest. All carry wisdom; none is complete. The deepest resilience comes not from pushing through but from expanding to include the exhaustion without being defeated by it. You can be both wounded and unbreakable."},"10 of Wands":{powerGods:"This weight you carry—it is the price of your conquests. Every burden was once a prize you seized. But hear this: even the mightiest dragon can be crushed beneath its own hoard. Power means knowing when to drop what slows you. Shed what you must to keep your fire burning.",traditional:"This burden is your sacred charge, and to carry it is to serve. Yet even the most devoted servant must recognize when duty becomes crushing weight. Seek counsel from your superiors—perhaps this load was meant to be shared among the faithful. Martyrdom through exhaustion serves no one. The order needs you whole.",modern:"You are over-capacity—this is a resourcing problem, not a character test. Audit your commitments, delegate or automate what you can, drop what does not serve your core objectives. Burnout destroys productivity; sustainable performance requires load management. Optimize the portfolio of your energy.",postModern:"This burden was not meant for one person alone—the weight reveals a systemic problem, not a personal failing. What would it look like to share this load, to redistribute rather than simply endure? Your exhaustion is information about imbalance in the collective. Rest is resistance; care is revolutionary.",metaModern:"What a fascinating overload—carrying the conquests, the duties, the projects, and the systemic weight all at once! Here is the developmental question: which burdens serve growth, and which are mere accumulation? The wizard neither hoards nor martyrs but dances with load and release. Lay down what you must. The unburdening is also the work."},"2 of Cups":{powerGods:"Here is one who meets your gaze without flinching—a rare creature. Not a subject, but an ally forged in mutual fire. Together you could be unstoppable, a force that doubles rather than divides. But choose wisely: only the strong deserve to stand at your side. Weakness is contagious.",traditional:"Here is sacred union, blessed by the eternal laws of love and covenant. This bond is not mere feeling—it is vow, witnessed by the Divine and community alike. Honor this connection with the gravity it deserves. Two souls joining in proper ceremony become a pillar upon which families and traditions are built.",modern:"Strategic partnership identified. This alliance offers mutual value creation—complementary skills, shared networks, synergistic goals. Evaluate the terms carefully, but recognize that the right partnership compounds both parties' success. Negotiate clearly, document expectations, and invest in the relationship infrastructure.",postModern:"Two hearts recognizing each other—this mirroring creates a container for mutual becoming. Real relationship requires seeing and being seen without masks. Can you hold space for their wholeness, including what challenges you? Love is not possession but co-creation, a dance where both are transformed.",metaModern:"Here is the miracle of true meeting—two whole beings choosing to become a we. This union contains the power alliance, the sacred vow, the strategic synergy, and the authentic seeing, all dancing together. The deepest partnerships integrate all dimensions. Let this connection evolve you both. Love at this level is conscious co-creation."},"3 of Cups":{powerGods:"Your warband celebrates! These are the ones who have proven their loyalty in battle, who have bled beside you. Keep them close and reward them fiercely—a generous lord commands the most savage devotion. Tonight, let the mead flow. Tomorrow, you hunt as a pack.",traditional:"Rejoice with your spiritual family, for community joy is holy joy. These celebrations—baptisms, harvest feasts, holy days—are the threads that weave us into one tapestry. Your place among the faithful is a gift of belonging. Raise your cup in thanksgiving for the congregation that holds you.",modern:"Network value in action—your professional and personal relationships are paying dividends. These connections are assets; nurture them strategically. Collaborative celebrations build social capital and team cohesion. The research is clear: strong networks correlate with success. Invest in your relationship portfolio.",postModern:"This is the joy of found family, of chosen belonging that transcends blood and obligation. In this circle, every voice matters and everyone is celebrated. Notice who is included and gently widen the welcome. Collective joy heals what isolation wounds. We rise by lifting each other.",metaModern:"The three cups raised together contain tribal loyalty, sacred communion, network value, and inclusive love—all true, all present. This celebration ripples across developmental altitudes. Joy shared consciously becomes medicine for the collective soul. Dance with your people at whatever level the moment calls for. The party is sacred."},"4 of Cups":{powerGods:"Why do the offerings bore you? You have won and won again, yet the fire gutters. Beware, warrior—this restlessness is either the death of ambition or the birth of a greater hunger. The universe offers you a new cup. Will you swat it away, or recognize it as the next horizon calling?",traditional:"This discontent whispers of spiritual drought, faithful one. When the old rituals feel empty, do not abandon them—deepen them. The Divine offers renewal, but you must open your eyes to receive it. Perhaps you have drifted from the practices that once nourished you. Return to the well of tradition; it has not run dry.",modern:"Motivation metrics are down—diagnose the cause. Are you optimizing for the wrong goals? Has success shifted your values? That new opportunity being offered deserves objective analysis, not reflexive dismissal. Recalibrate your success criteria. Sometimes the next level requires redefining what you are playing for.",postModern:"This withdrawal is not failure but invitation to go inward. What are you really longing for beneath the surface apathy? Perhaps the cups offered do not match your authentic needs. Feel into the disconnection without rushing to fix it. Sometimes the soul needs space before it can know what it truly wants.",metaModern:"This sacred boredom is the chrysalis before transformation. You have outgrown what used to satisfy—not failure but development. The new cup appearing may be your next stage calling. Or perhaps the invitation is to appreciate what is already present. Both truths coexist. Sit with the not-knowing until clarity emerges."},"5 of Cups":{powerGods:"You rage at what was taken from you, fixated on the spilled cups. But hear this: grief is a luxury for those with nothing left to win. Behind you stand cups still full, battles still waiting. Will you waste your fury on the irretrievable, or turn it toward fresh conquest?",traditional:"Grieve as the scriptures teach—with faith that loss has meaning in the greater design. What has spilled was perhaps not meant for you, or serves a purpose you cannot yet perceive. The cups that remain are blessings still. Turn toward them with gratitude. The Divine does not abandon the faithful in sorrow.",modern:"Loss acknowledged—now conduct the post-mortem. What failed and why? Extract the learnable lessons, then redirect focus to remaining assets. Dwelling on sunk costs is irrational. Emotionally process what you must, then pivot your energy toward the opportunities that remain. Recovery is a strategic choice.",postModern:"Your grief is sacred and deserves full expression. Do not rush past the mourning—what is lost was loved, and that love matters. Let yourself be held by others in this sorrow. When you are ready, and only then, you will notice what remains. Healing is not linear, and there is no timeline but your own.",metaModern:"Grief lives in the body alongside possibility; you need not choose between them. Honor what was lost while remaining open to what remains. The warrior must eventually move, the faithful trust meaning, the strategist learns, and the heart fully feels—all in their own time, all part of the healing. Integration includes the sorrow."},"6 of Cups":{powerGods:"Remember when the fire first awoke in you? Before the scars, before the throne—when power was pure possibility? That fierce child still lives in you, uncomplicated and hungry. Return to that primal spark. It will remind you why you fight, when politics and burden cloud your purpose.",traditional:"Return to the innocence of early faith, when the mysteries filled you with wonder. The traditions you learned at your elders' knees carry wisdom you may have forgotten. This nostalgia is not weakness—it is the soul seeking its roots. Honor where you came from; it is the soil from which your devotion grows.",modern:"Nostalgia can be mined for insight—what drove you before the complications set in? That original motivation may reveal values obscured by success metrics. Beginner's mind has strategic value: it sees opportunities expertise overlooks. Reconnect with your foundational drivers to realign current trajectory.",postModern:"That inner child still lives in you, holding memories of wonder and wounds alike. What does that young one need to feel safe now? Healing often means returning to offer comfort to past selves. Nostalgia can be escape or integration—let it be the latter. Parent yourself with the tenderness you deserved.",metaModern:"The past lives in you as resource and wound, power and innocence, tradition and trauma. All your ages are present—the fierce child, the faithful youth, the achieving adult, the healing heart. Return to any era that calls you, not to regress but to reclaim and integrate. Wholeness includes all of who you have been."},"7 of Cups":{powerGods:"Visions and phantoms swirl before you—kingdoms, lovers, treasures beyond measure. Tempting, yes. But a true warrior knows the difference between dreams and prey. Some of these visions are snares set by your enemies; others are distractions from your true desire. Choose with your gut, not your greed.",traditional:"Beware the temptations that masquerade as visions, faithful one. Not every shimmering promise comes from the Divine—some are sent to test or mislead you. Measure each choice against the teachings. That which contradicts sacred law, however beautiful, is illusion. Seek counsel from those wiser in discernment.",modern:"Multiple options present—avoid analysis paralysis and fantasy thinking. Which of these choices have viable paths to execution? Apply due diligence: market research, feasibility analysis, resource requirements. Dreams without actionable plans are distractions. Select the opportunity with the best probability-weighted outcome.",postModern:"These visions arise from your psyche—all of them are you, speaking in symbols. Do not judge them as temptations but explore them as messages. What do these fantasies reveal about unmet needs, shadow desires, unlived possibilities? Imagination is the soul's language. Listen before you choose.",metaModern:"What a spectacular display the psyche offers! Each cup is a possibility, a shadow, a projection, a genuine option—and you cannot know which is which until you engage. The wizard neither grasps nor dismisses but holds all visions lightly, letting deeper knowing sort signal from noise. The choice will clarify through attention."},"8 of Cups":{powerGods:"You turn your back on what you have built. They will call you mad, but you know the truth: this victory has become a cage. A dragon cannot thrive in a den it has outgrown. The mountains ahead are taller, the glory greater. Walk away from the small to claim the magnificent.",traditional:"Sometimes the sacred path leads away from what we have built. This departure is pilgrimage, not abandonment—a journey toward deeper truth. The mystics walked into deserts seeking the Divine. If your soul calls you onward, go with blessing, but carry the teachings with you. The tradition travels in your heart.",modern:"Strategic pivot indicated. When current returns diminish despite investment, the rational move is reallocation. Do not let sunk cost fallacy trap you in declining positions. The courage to walk away from what no longer serves your goals is an underrated success skill. New ventures await your proven capabilities.",postModern:"This leaving is an act of self-honoring. Something in you knows that staying would be slow suffocation. Trust that knowing, even when others do not understand. The journey inward requires releasing what no longer fits your becoming. What you seek cannot be found in what you already have. Walk toward yourself.",metaModern:"This departure contains the dragon seeking greater glory, the pilgrim seeking deeper truth, the strategist reallocating resources, and the soul seeking itself. All are present in the walking away. What makes this metamodern is knowing you take everything with you—nothing is truly left behind. The journey is integration in motion."},"9 of Cups":{powerGods:"Sit upon your throne of fulfilled desires, mighty one. You wished and you won—this abundance is the fruit of your fire. Enjoy it without apology. The universe bends to those with the will to demand and the power to take. You have both. Savor the proof of your supremacy.",traditional:"Your prayers have been answered, faithful one—receive this abundance with humble gratitude. The Divine rewards the righteous, and your contentment is earned through devotion. Share news of this blessing so others may be encouraged in faith. Let your satisfaction be testimony to the goodness of the sacred order.",modern:"Goals achieved—success metrics satisfied. This is the payoff for strategic planning and disciplined execution. Document what worked; this methodology is now proven. Enjoy the satisfaction of optimized outcomes. Well-being research confirms: savoring success is not indulgence, it is performance-sustaining psychology.",postModern:"Let yourself feel this satisfaction fully, without guilt or deflection. You are allowed to be happy, to have your needs met, to experience enough. Notice if old narratives try to diminish this contentment. You do not need to earn rest or justify joy. This moment of fullness is a gift to simply receive.",metaModern:"Satisfaction achieved—and all the ways you got here are valid. You conquered, you prayed, you strategized, you healed. The contentment is real at every level. The wizard knows that genuine fulfillment is neither grasping nor dismissing this moment, but receiving it as both earned and gifted, deserved and miraculous."},"10 of Cups":{powerGods:"Behold what your conquests have built: not just victory, but legacy. A kingdom that reflects your fire, a bloodline that will carry your strength forward. This is power that transcends your mortal span. You have won the game that matters most—eternity will remember your name.",traditional:"Behold the blessing of a righteous household—this is the promise fulfilled for the faithful. Generations united under sacred covenant, the rainbow of divine blessing arching overhead. You have built according to holy design, and what you have built will endure. This harmony is heaven touching earth through proper living.",modern:"Optimal life outcomes achieved across multiple domains: family, career, relationships, well-being. This is what integrated success looks like. The compound interest of smart choices has matured into sustainable abundance. Protect and maintain these systems; they represent peak life optimization.",postModern:"This vision of wholeness includes everyone—notice the full spectrum, the rainbow embracing all colors equally. This is not about the nuclear family achieved but about belonging that transcends structure. However your people are configured, let them be seen and celebrated. Love is the home we build together.",metaModern:"The rainbow contains all colors, all developmental hues—this is wholeness that transcends and includes. The family is dynasty, covenant, optimized system, and chosen belonging, simultaneously. Heaven touches earth when we stop choosing between levels and let them all dance. This is what integrated flourishing looks like."},"2 of Swords":{powerGods:"You sit blindfolded with crossed blades, refusing to choose. Enough! Indecision is its own defeat. You know what you want—the darkness behind your eyes holds the answer. Trust your predator instincts. Cut through the paralysis with action. Any choice made boldly beats stagnation.",traditional:"You are caught between competing duties, faithful one. When two paths seem equally right, seek the wisdom of scripture and elder counsel. The blindfold suggests you are relying too much on your own understanding—remove it through prayer and meditation. The proper choice will align with eternal law.",modern:"Decision deadlock—you need more data or a better framework. Remove the blindfold of emotional interference and assess objectively. If both options test equally, you need different evaluation criteria. Set a deadline; the cost of indecision is measurable. Sometimes progress requires choosing imperfectly and iterating.",postModern:"The blindfold is there because some truths are too painful to face. What are you protecting yourself from knowing? This impasse holds wisdom—perhaps the dilemma is false, or perhaps you are not yet ready. Sit with the discomfort. The heart knows things the mind defends against. Let feeling inform the thinking.",metaModern:"What if the blindfold is also a gift? Sometimes we must choose without complete seeing. The instincts, the tradition, the data, the heart—each blade contains partial truth. The metamodern move is neither to force decision nor to paralyze indefinitely but to hold the tension until something new emerges. Trust the process of not-yet-knowing."},"3 of Swords":{powerGods:"The blade has found your heart. Someone has wounded you—and now you must decide: will this pain break you or forge you? A warrior transforms every wound into wisdom, every betrayal into battle-knowledge. Let the blood remind you to trust fewer and strike first next time.",traditional:"This sorrow pierces deep, but suffering has sacred purpose in the divine economy. The heart that breaks open can receive more grace. Seek comfort in the rituals of mourning your tradition provides—they exist because others have walked this path before. Pain shared with the faithful is pain diminished.",modern:"Painful truth received—process it efficiently. Denial is expensive; better to integrate difficult information quickly than to let it fester. This data changes your model of reality; update accordingly. The faster you metabolize hard truths, the sooner you can recalculate and move forward strategically.",postModern:"This heartbreak is valid and real; let it be witnessed without fixing. Grief is not a problem to solve but an experience to move through with companions. Who can hold space for your sorrow? The heart that breaks is the heart that loved. That capacity for love remains, even through the pain.",metaModern:"The pierced heart holds all the responses to pain—the forging, the sacred suffering, the efficient processing, the witnessed grief. You do not need to choose one way to hurt. Let the tears flow while the lessons integrate while the meaning unfolds while the presence of others holds you. Heartbreak itself is a teacher of wholeness."},"4 of Swords":{powerGods:"Even the fiercest beast must den to lick its wounds. This is not weakness; this is strategy. Rest now so you may rise more terrible than before. Your enemies think you are finished—let them. When you emerge, their complacency will be their destruction.",traditional:"The knight lies in sacred rest within the sanctuary—this is holy retreat, not abandonment. Even the most devoted need seasons of contemplation. Enter the chapel of your inner temple and pray. The vigil candles burn while you restore your spirit. Service will call again when you are ready.",modern:"Recovery period required—schedule it strategically. Peak performance research confirms: rest is not optional but essential for sustained output. Use this downtime for reflection and planning. Mental maintenance is an investment in future productivity. Return to action refreshed and with enhanced clarity.",postModern:"Rest is not earned through exhaustion; it is your birthright. The constant demand to produce is a cultural wound, not a virtue. Let yourself simply be, without justification. In stillness, the psyche integrates what activity cannot process. This sanctuary is not escape but essential return to self.",metaModern:"The knight rests—strategically, sacredly, productively, and simply because rest is good. All reasons for rest are valid; you need not choose. The integration that happens in stillness serves every dimension: the warrior recovers, the soul communes, the mind clarifies, the body heals. Rest is the work. The work is rest."},"5 of Swords":{powerGods:"You have won, but look at the cost strewn around you. Victory without spoils is hollow glory. Consider this: have you defeated enemies, or merely created them? The cunning warrior claims triumph and keeps allies. Raw domination without strategy breeds only endless vengeance.",traditional:"This victory feels hollow because it was won by straying from the code. Look at the defeated—are they enemies of the faith, or merely those who disagreed? The righteous warrior fights with honor, for the manner of winning matters as much as victory itself. Seek reconciliation where the rules permit.",modern:"Pyrrhic victory analysis—was the win worth the cost? Damaged relationships and burned bridges are real liabilities that compound over time. Smart competitors win sustainably. Assess whether your tactics served short-term ego or long-term success. Reputation is a strategic asset; calculate accordingly.",postModern:"What was really won here, and at whose expense? This conflict may have served systems that benefit no one. Can the defeated be heard? Can repair be offered? Victory built on another's diminishment is hollow for everyone. Consider what collaborative outcome might have served all voices.",metaModern:"This hollow victory invites examination at every level. When winning feels like losing, the game itself may be flawed. What would it mean to transcend the conflict entirely—not bypass it, but include all perspectives in a larger resolution? Sometimes the metamodern move is redesigning the game."},"6 of Swords":{powerGods:"You leave the battlefield for calmer waters—not in retreat, but in tactical advance. Sometimes the greatest power is knowing when a fight is not worth your fire. Carry the lessons from troubled shores; they will arm you for the conflicts that truly matter ahead.",traditional:"You journey toward sanctuary, leaving troubles behind—this is not flight but faithful passage. Sometimes the Divine calls us away from storms we cannot calm. Accept the guidance of those who ferry you; they serve a sacred purpose. Calmer waters await where you can rebuild according to proper form.",modern:"Strategic relocation in progress. Exiting unfavorable conditions for better operating environments is rational resource management. Document the lessons from the turbulent situation. The calm waters ahead offer better conditions for your next venture. Sometimes the winning move is changing the game board.",postModern:"This transition honors what cannot be healed by staying. Notice who journeys with you; you need not make this crossing alone. The troubled waters behind taught something, even through pain. Gentler shores await, but do not rush the passage. The journey itself is part of the healing.",metaModern:"The crossing contains retreat and advance, divine guidance and rational choice, solitary journey and held passage. The ferryman knows the waters; you need not navigate alone. What you leave behind becomes part of what you carry forward—transformed. Every shore holds what you need for the next stage of becoming."},"7 of Swords":{powerGods:"The trickster knows that not all wars are won with frontal assault. Stealth, cunning, misdirection—these too are weapons of the mighty. Let the honorable fools announce their attacks; you will take what you need while they posture. Victory belongs to the clever as much as the strong.",traditional:"Beware the path of cunning, for it often leads away from righteousness. The ends do not justify means that violate sacred law. If you must be strategic, let your strategy serve the greater good, not mere personal gain. The Divine sees all—what is hidden from others is never hidden from above.",modern:"Unconventional tactics may be required—asymmetric strategy has its place. But calculate reputational risk carefully. Short-term gains from clever maneuvers can create long-term liabilities. In transparent markets, information travels fast. Ensure your methods can withstand disclosure.",postModern:"Something needs reclaiming that cannot be asked for directly—perhaps your own power, your own truth. Not all stealth is deception; sometimes it is protection from systems that would deny your needs. But examine: who is harmed if you proceed this way? Cleverness used for liberation differs from exploitation.",metaModern:"The trickster archetype holds its own developmental path—sometimes cunning serves evolution when direct confrontation cannot. The question is not whether to be clever but what cleverness serves. When strategy, ethics, self-protection, and systemic awareness align, the unconventional path may be the most integral one."},"8 of Swords":{powerGods:"You stand bound and blindfolded, but look closer—the ropes are loose, the guards are phantoms. You have caged yourself with imagined limits. A true power recognizes no prison it cannot burn through. Open your eyes, flex your might, and walk out of this self-made trap.",traditional:"You feel trapped, but examine whether these bonds are true constraints or self-imposed limitations. Sometimes we cage ourselves through rigid interpretation rather than faithful understanding. Seek guidance from those who know the tradition deeply—there may be pathways within the law you have not seen.",modern:"Constraint analysis required—which limitations are real and which are assumed? Test your hypotheses about what is impossible. Many barriers are mental models, not market realities. Hire a coach or consultant with fresh eyes. Innovation often comes from questioning the constraints everyone else accepts.",postModern:"These bonds were placed by systems, beliefs, and stories you did not choose. Some are internalized oppression, not personal failure. What voices told you that you were trapped? Whose interests does your captivity serve? Liberation often requires community—others can see the exit you cannot. Ask for help.",metaModern:"The bindings are simultaneously self-created, systemically imposed, strategically testable, and requiring collective liberation—all true. Freedom comes not from choosing one analysis but from seeing how they interweave. The loosening happens when you stop being the prisoner and become the one who witnesses. Step out of the frame."},"9 of Swords":{powerGods:"The demons come in the night, when your sword arm rests. These fears speak of threats you have not yet conquered—and so they haunt you. Rise up and face them! Name your terrors and hunt them into the dawn. A warrior does not hide from shadows; a warrior becomes the thing darkness fears.",traditional:"The night terrors come, and faith feels far away. This is the dark night of the soul the mystics warned of—but it is not abandonment. Light your candle, speak the old prayers, clutch the sacred symbols close. Dawn follows darkness by divine decree. You are never as alone as fear whispers.",modern:"Anxiety spike detected—is this signal or noise? Distinguish between productive concern about real risks and catastrophic thinking patterns. If real threats, build contingency plans. If cognitive distortions, address with evidence-based techniques. Worry without action is expensive; convert concern into risk mitigation.",postModern:"The nightmares that wake you carry messages from the unconscious. What is too frightening to face by day comes visiting at night. You do not have to face these terrors alone. Reach out—call someone, speak the fears aloud, let them lose power through sharing. The body that holds anxiety needs soothing.",metaModern:"In the 3AM darkness, every developmental voice has counsel: fight the fears, surrender to faith, analyze the threats, hold the frightened one with compassion. All are medicine; none is complete. The metamodern move is to witness the night terror with compassionate awareness—holding yourself across all dimensions until the dawn that always comes."},"10 of Swords":{powerGods:"You lie with ten blades in your back, utterly destroyed. Or so it seems. But look—the dawn breaks on the horizon. This death is not your end; it is the annihilation of who you were so that something fiercer may rise. Even now, your enemies should tremble at what is being born.",traditional:"This is the deepest trial, the complete undoing—yet look where the light breaks. The tradition speaks of deaths that precede resurrection, of the seed that must be buried before it blooms. Surrender to the process. The dawn is promised, and the Divine keeps its promises to the faithful.",modern:"Total failure scenario—but rock bottom provides a stable foundation. This is a forced reset; use it strategically. When old models fail completely, you have permission to rebuild from first principles. The dawn on the horizon is real: new ventures await. Failure data is still data; learn and pivot.",postModern:"This ending is absolute, and your grief at it is valid. Do not rush to find the silver lining—let the devastation be witnessed fully. Something genuinely died here, and it deserves mourning. When you are ready—not before—the dawn will still be waiting. For now, just breathe. Just survive.",metaModern:"Pinned by all the blades of finality—and yet. The dawn breaks regardless of readiness. This death is fiercer rebirth, sacred process, strategic reset, and valid devastation, all at once. You need not understand it to survive it. The ten swords are complete; nothing more can fall. From this rock bottom, every direction is up."},"2 of Pentacles":{powerGods:"You juggle your prizes, keeping all your schemes aloft. This dance of balance is a display of skill—let them marvel at your dexterity. But remember: the strong do not juggle forever. Choose which treasure to clutch close and which to let fall. Decisiveness is its own wealth.",traditional:"Life asks you to balance many duties—to family, to faith, to labor. This is the dance of the devoted, and it is sacred choreography. Do not resent the juggling; it is the rhythm of righteous living. Seek the order within the chaos; there is divine pattern here if you look.",modern:"Portfolio management in action—multiple projects, dynamic allocation. This juggling is a feature, not a bug; diversification manages risk. But monitor your bandwidth metrics. Sustainable multitasking requires systems. If you are dropping balls, automate, delegate, or strategically deprioritize.",postModern:"This constant juggling may be a symptom of systems that demand too much. What would it mean to simply let some things fall? Your worth is not measured by how much you can carry. The dance can be joyful, but only if you choose the rhythm. What truly matters to you, beneath the busyness?",metaModern:"The infinite dance of dynamic balance—sometimes you juggle for power, sometimes for duty, sometimes for strategy, sometimes you question the dance itself. All valid, all partial. The wizard juggles lightly, knowing that flow and release are both part of the pattern. What wants to rise? What wants to fall? Trust the movement."},"3 of Pentacles":{powerGods:"Even the lone wolf recognizes when pack tactics serve the hunt. Here, others bring skills you lack—let them build while you conquer. A clever warlord uses every tool available. Take credit for the cathedral if you must, but ensure the builders know whose vision drives the stone.",traditional:"The cathedral rises through the harmonious labor of many hands, each knowing their proper role. This is sacred work—when craft serves the Divine, even the mason becomes a priest. Know your place in the great work and fulfill it with devotion. What we build together outlasts what we build alone.",modern:"Cross-functional collaboration delivering results. The complex project requires diverse expertise—architecture, execution, stakeholder management. Clarify roles, establish communication protocols, align incentives. Team output exceeds individual capacity when properly orchestrated. Invest in process; it scales.",postModern:"Notice how each person's contribution is essential—the architect, the craftsperson, the patron. Hierarchy here is function, not worth. What would it mean to truly value every voice in this collaboration? The cathedral is beautiful because difference was honored. Build spaces where all gifts are seen.",metaModern:"The cathedral rises from pack tactics, sacred roles, optimized collaboration, and honored differences—all at once. The metamodern master builder holds all frames, applying each where it serves. Sometimes hierarchy helps; sometimes it hinders. Read the moment, build with all available wisdom. The great work transcends any single approach."},"4 of Pentacles":{powerGods:"You clutch your gold with white-knuckled grip, letting no one near your hoard. Good—what you have won is yours to defend. But ask yourself: is this hoarding strength, or is it fear wearing the mask of power? The dragon who sits too long on their treasure becomes indistinguishable from it.",traditional:"Prudent stewardship is a virtue, but examine your grip on these worldly goods. The tradition teaches that wealth is held in trust for greater purposes. Security is blessed; hoarding that harms the community is not. Can you protect your household without closing your heart to sacred obligations of charity?",modern:"Capital preservation has value, but assess opportunity cost. Is this security or stagnation? Conservative positions sacrifice growth for stability—ensure that trade-off aligns with your goals. Consider: wealth static loses to inflation; wealth deployed strategically compounds. Balance protection with productive investment.",postModern:"What wound creates this grip? Scarcity is real, but hoarding often stems from old fears wearing present-day masks. True security comes through connection, not accumulation. What would it mean to trust the web of community to hold you? Generosity might heal what possession cannot protect.",metaModern:"The grip itself contains information—what is it protecting? Security is sometimes wisdom, sometimes wound, sometimes strategy, sometimes missed connection. The wizard neither hoards nor scatters carelessly but holds wealth as energy to be moved appropriately. What does this moment actually require? Trust your read."},"5 of Pentacles":{powerGods:"You walk wounded through the snow, locked outside the warmth. This is temporary exile, not final defeat. Let the cold fuel your fury. Remember every door that closed against you—when your power returns, you will decide which of them burns. Survival now; vengeance later.",traditional:"You suffer in the cold, but look—the sanctuary window glows nearby. Have you wandered from the fold, or has misfortune found you still faithful? Either way, the temple doors remain open. The congregation exists for times like these. Swallow pride and seek the help your tradition commands us to give.",modern:"Resource scarcity situation—access available support systems. Pride is expensive when survival is at stake. Network leverage exists for times like these. Identify assistance programs, negotiate payment terms, explore alternative income streams. This is a temporary cash flow problem with solutions; execute on them.",postModern:"This suffering is not a personal failing but a systemic wound. Many walk in this cold; you are not alone. The shame capitalism attaches to need is a lie. Reach toward those walking beside you—mutual aid exists. The stained glass window represents institutions that often fail to truly help. Build community that actually includes everyone.",metaModern:"The cold is real, and every voice offers warmth: the fury that fuels survival, the sanctuary that waits, the systems to be leveraged, the companions who walk beside you. All are true resources; none is complete. In this difficulty, draw from every altitude that serves. The metamodern path through scarcity integrates all available support."},"6 of Pentacles":{powerGods:"You hold the scales, deciding who receives and who is denied. This is power in its purest form—the power to give and to withhold. Use it wisely: generosity creates loyalty, but never let them forget who holds the gold. A gift from you is a chain of gratitude, and chains are useful.",traditional:"Whether you give or receive, this exchange is sacred commerce operating within divine law. Charity is commanded; receiving with gratitude is equally holy. The scales must balance fairly—justice is a pillar of righteous society. Let generosity flow through proper channels, and blessings will return measured and true.",modern:"Resource distribution optimization—whether allocating capital or receiving investment. Fair exchange creates sustainable relationships and market reputation. Philanthropy done well is also strategic: it builds goodwill, networks, and brand equity. Calculate the total return on generosity, including intangibles.",postModern:"Examine the power dynamics in this exchange. Is this true generosity or charity that maintains hierarchy? The receiver kneeling perpetuates imbalance. What would mutual aid look like instead? Resources flowing freely, without debt or diminishment. Give in ways that elevate rather than obligate. Receive without shame.",metaModern:"The scales measure something different at each level—power, sacred balance, strategic value, mutual flow. All are present in every exchange. The metamodern giver and receiver attend to all dimensions: maintaining appropriate structure while dissolving unnecessary hierarchy, being strategic while being genuinely generous. Let resources flow where they are most alive."},"7 of Pentacles":{powerGods:"You survey what you have planted, impatient for the harvest. The waiting burns, does it not? But even the fiercest conqueror cannot make fruit ripen by roaring at it. Channel your restless energy into planning the next campaign. This garden will yield when it yields.",traditional:"Patient cultivation is the farmer's faith made visible. You have planted according to the old ways, in proper season, with proper blessing—now trust the process. The harvest comes when the Divine wills it. Your role is tending, not forcing. Continue faithful labor and the yield will prove your devotion.",modern:"Investment maturation period—returns require time. Review your metrics, but respect the timeline inherent to the asset class. Impatience leads to premature harvesting and lost compounding. While waiting, optimize other variables: reduce costs, improve processes, prepare for scaling when the yield arrives.",postModern:"This pause invites reflection beyond productivity. What is growing here, really? Is it aligned with your deeper values? The garden does not need your anxiety; it needs your presence. Perhaps the invitation is to tend with attention rather than expectation. Growth cannot be rushed, only witnessed with care.",metaModern:"The assessment moment holds all dimensions: the impatience that fuels, the faith that waits, the metrics that measure, the presence that witnesses. Growth follows its own timeline across all levels of development. Your task is to tend what you have planted with the consciousness each stage requires. The harvest will integrate everything."},"8 of Pentacles":{powerGods:"The hammer strikes, again and again. Here is a truth the proud overlook: mastery is its own form of dominance. While others fumble, your skill becomes a weapon sharper than any sword. Let them mock the craftsman—you will own markets they cannot even enter.",traditional:"Sacred is the labor of skilled hands when work is offered as worship. The apprentice who masters their craft glorifies the tradition that taught them. Each stroke of the tool is a prayer, each finished piece an offering. This devotion to excellence is devotion to the Divine expressed through matter.",modern:"Skill development is career capital accumulation. Deliberate practice, measured improvement, progressive mastery—this is how expertise compounds. The 10,000 hours principle applies. Invest in your capabilities; they are assets with appreciating returns. Mastery opens markets that competence cannot access.",postModern:"There is meditation in this focused making. But ask: for whom do you craft? Is this labor alienated or aligned with purpose? Mastery for its own sake can be beautiful, but consider the use to which your skill is put. Let your craft serve connection, not just production. Work that matters is work that helps.",metaModern:"The hammer strikes as power move, as prayer, as skill investment, as meditation—all integrated in the craftsperson's rhythm. Mastery at the metamodern level serves multiple purposes simultaneously without contradiction. Let your practice be fierce and sacred and strategic and connected. Each pentacle created carries all of who you are becoming."},"9 of Pentacles":{powerGods:"Survey your domain, magnificent one. The falcon on your wrist, the gardens at your feet—all earned by your own fire. You answer to no one. This independence is the sweetest form of victory. Let those who chose safety and servitude envy what boldness has built.",traditional:"This abundance is the fruit of disciplined living according to sacred principles. You have followed the path of righteousness and it has led to beautiful gardens. Enjoy these blessings with gratitude, knowing they flow from proper conduct. Let your prosperity testify to the rewards of faithful stewardship.",modern:"Financial independence achieved—the passive income covers the lifestyle. This is the compound interest of discipline and smart decisions. You have optimized for autonomy and it has paid off. Enjoy the ROI on your strategic choices. This is what winning at the long game looks like.",postModern:"This solitary abundance is beautiful, but notice who is absent from the garden. Independence can become isolation if we are not careful. What would it mean to share this sanctuary, to open the gates? Prosperity in community nourishes differently than prosperity alone. Let your garden be a gathering place.",metaModern:"The solitary figure in the abundant garden—simultaneously fierce sovereign, faithful steward, strategic winner, and potential isolate. All true. The metamodern question is: how do you hold this prosperity consciously, enjoying genuine independence while remaining in generative relationship? The falcon both hunts alone and returns home. So do you."},"10 of Pentacles":{powerGods:"A dynasty rises from your conquests—wealth that will flow through generations carrying your name. This is immortality in gold and stone. You have won not just for yourself but for your bloodline eternal. Let the ancestors watch and the descendants inherit. Your legend is secured.",traditional:"Behold the fullness of generational blessing—ancestors, elders, children, and grandchildren united under one sacred covenant. This is the promise to the faithful fulfilled in stone and lineage. You have built not for yourself alone but for the continuity of tradition. The old ways, honored, bear fruit through time.",modern:"Generational wealth established—legacy assets, family enterprise, institutional capital. This is multi-generational financial optimization. Estate planning, tax strategy, succession protocols—ensure the structure supports the vision. You have built not just for yourself but for sustained dynastic advantage.",postModern:"This image of legacy invites questions: whose labor built these walls? Who is included in the inheritance, and who is excluded? True wealth is measured in belonging, not bloodline. Expand the definition of family; expand who receives. Build systems that share abundance rather than concentrate it.",metaModern:"The ten pentacles represent dynasty, covenant, optimized legacy, and expanded belonging—all dancing in the generational field. The metamodern inheritance includes material wealth and wisdom, tradition and transformation, structure and liberation. Build systems that honor ancestors while evolving beyond their limitations. True legacy serves all futures."}};var b=o(7157),v=o(8358),w=o(5162);let q={Wands:"Fire",Cups:"Water",Swords:"Air",Pentacles:"Earth"},T={king:"Fire",queen:"Water",knight:"Air",page:"Earth"},k={rws:{king:"King",queen:"Queen",knight:"Knight",page:"Page"},thoth:{king:"Knight",queen:"Queen",knight:"Prince",page:"Princess"}},S={king:"The Fire aspect of the suit — active, projective, and commanding. This figure initiates, leads, and embodies the pure yang expression of the elemental force.",queen:"The Water aspect of the suit — receptive, reflective, and nurturing. This figure internalises the elemental force, expressing it through feeling, intuition, and depth.",knight:"The Air aspect of the suit — mobile, intellectual, and changeable. This figure moves the elemental force outward through thought, communication, and swift action.",page:"The Earth aspect of the suit — grounded, studious, and potential-bearing. This figure holds the elemental force in latent form, representing learning, messages, and new beginnings."},E={Wands:"Wands",Cups:"Cups",Swords:"Swords",Pentacles:"Pentacles"},z={Fire:"Fire",Water:"Water",Air:"Air",Earth:"Earth"},j=["Wands","Cups","Swords","Pentacles"],L=["king","queen","knight","page"],x={"king-of-wands":{suit:"Wands",rank:"king",mbti:"ENTJ",title:"Lord of the Flame and Lightning",description:"The King of Wands is Fire of Fire — the pure archetype of inspired leadership and creative will. He is the entrepreneur, the visionary, and the natural born leader who acts from conviction rather than calculation. His authority comes not from position but from an inner fire that others feel compelled to follow. He is bold, magnanimous, and sometimes reckless in the pursuit of his grand designs.",jungian:"Represents the fully individuated masculine principle operating through the Will — the Self expressed as creative authority. Psychologically, this figure embodies the integration of the animus at its most commanding, where personal vision aligns with archetypal purpose. The shadow is tyranny, where the drive for dominion eclipses empathy.",powerGods:"The warlord king whose conquest is righteous because he believes wholly in his cause. Power expressed as dominance, the subjugation of weaker wills to a single blazing vision. Victory at all costs.",traditional:"The patriarch blessed by divine fire — a leader who rules through God-given authority and moral rectitude. His flame is sacred, his word law. He protects and provides, demanding loyalty and obedience in return.",modern:"The visionary CEO or founder who disrupts industries through charisma and tenacity. He builds empires through sheer will, inspires fierce loyalty, and tolerates nothing that dims his momentum. Success validates the method.",postModern:"A critique of the lone genius myth — whose flame casts shadows on those who fuel it? The king's fire consumes resources, relationships, and the labour of countless unseen others. Leadership must be questioned as a social construction.",metaModern:"The conscious leader who wields fiery vision while remaining accountable to the larger ecosystem. Sovereignty earned through integrity, not dominion. The flame shared rather than hoarded — illuminating rather than consuming."},"queen-of-wands":{suit:"Wands",rank:"queen",mbti:"ENFJ",title:"Queen of the Thrones of Flame",description:"The Queen of Wands is Water of Fire — passionate feeling channelled into radiant personal magnetism. She is the sunflower queen, warm and self-assured, who draws others to her simply by being fully herself. Creative, loyal, and fiercely independent, she knows what she wants and pursues it with warmth rather than force. Her authority is earned through genuine presence and undeniable vitality.",jungian:"Embodies the anima archetype fully at home in the world — the feminine principle expressed through creative confidence rather than receptivity. She is the individuated self who needs no external validation. Her shadow is vanity and possessiveness, a fire that scorches what it claims to love.",powerGods:"The sun goddess whose approval must be won, whose radiance blesses or burns. Power wielded through social dominance and the withholding of warmth. Loyalty secured by making others feel chosen.",traditional:"The matriarch whose household blazes with life and purpose. She is the hearth fire — sustainer of family, community, and tradition. Her passion is expressed through devoted service to what she loves.",modern:"The force-of-nature entrepreneur or artist — confident, self-promoting, and magnetically productive. She owns her ambition unapologetically. Her creative output is prolific, her network wide, her personal brand impeccable.",postModern:'Who decides which passions are legitimate? The queen\'s confidence often rests on social privilege. Examining what it means to be "naturally" magnetic when magnetism is shaped by race, class, and gender politics.',metaModern:"The fully expressed creative self who celebrates others' flames rather than competing with them. Confidence grounded in genuine self-knowledge, magnetism rooted in authentic presence. Fire that warms rather than consumes."},"knight-of-wands":{suit:"Wands",rank:"knight",mbti:"INTJ",title:"Lord of the Winds and Breezes",description:"The Knight of Wands is Air of Fire — the mercurial adventurer who charges into every horizon with infectious enthusiasm. He is the eternal quest personified: restless, daring, and impossible to pin down. His energy is explosive and creative, capable of igniting entire movements with a single passionate speech. The challenge is follow-through; he is often gone before the fire he started is tended.",jungian:"The puer aeternus archetype — the eternal youth who refuses limitation and commitment. Psychologically, he represents the creative impulse before it has been disciplined by the ego's need for completion. Integrating this figure means finding ways to sustain the fire without losing the spark.",powerGods:"The conqueror on horseback who destroys and moves on, leaving transformation in his wake whether welcome or not. Power through speed and shock — arrive, ignite, depart before the consequences catch up.",traditional:"The crusading knight who rides for a sacred cause with absolute faith and no hesitation. His valor is genuine even if his wisdom is undeveloped. God and glory point the same direction; he asks no more.",modern:"The serial entrepreneur, the nomadic creative, the disruptor who thrives in chaos. He launches projects with brilliant energy and exceptional pitch decks, then loses interest once the initial excitement fades. Failure and success both bore him equally.",postModern:"The restless adventurer whose freedom is often predicated on others holding still. Who cleans up the fires he starts? Nomadism and disruption as privilege — the ability to move on is unevenly distributed.",metaModern:"The inspired initiator who has learned to hand the torch to skilled sustainers before riding to the next horizon. His fire is a gift, not a claim. Speed balanced with enough wisdom to know when to slow down."},"page-of-wands":{suit:"Wands",rank:"page",mbti:"INFJ",title:"Princess of the Shining Flame",description:"The Page of Wands is Earth of Fire — creative potential in its most fertile, unformed state. She is the spark before it becomes a flame, the idea before it becomes a project. Enthusiastic, curious, and fearlessly experimental, she approaches the world as one enormous creative playground. Messages of inspiration, sudden excitement about a new direction, and the thrilling first days of a creative venture all belong to her.",jungian:"Represents the earliest stage of creative individuation — the nascent Self beginning to stoke its own fire. Psychologically, this is the inner child who has not yet learned to censor its enthusiasm. Her shadow is scattered energy and the inability to commit.",powerGods:"The wild child whose raw power is precisely her unpredictability. She has not yet been socialized into deference — her fire may burn anything, and that potency is itself a form of authority.",traditional:"The young acolyte before the sacred flame, learning the rituals of devotion and creative service. Enthusiasm disciplined into practice. The beginner's mind held within a structure that gives it direction.",modern:"The junior creative, the intern with big ideas, the student who hasn't learned to hold back yet. Her energy is infectious and sometimes exhausting. The system doesn't always know what to do with her.",postModern:"The perpetual beginner as a response to expertise culture — resisting the pressure to become an authority. Refusing to be domesticated. The page who will not become a knight on anyone else's timeline.",metaModern:"The beginner's mind preserved consciously and with intention. Fresh enthusiasm held alongside growing wisdom. She learns the craft while keeping the flame alive — neither naive nor cynical, but genuinely alight."},"king-of-cups":{suit:"Cups",rank:"king",mbti:"ESTP",title:"Lord of the Waves and Waters",description:"The King of Cups is Fire of Water — will and authority expressed through emotional mastery and compassionate understanding. He governs the realm of feeling without being swept away by it. A counsellor, healer, or spiritual guide, he holds space for the depths of human experience while remaining centred and warm. His power comes from having navigated his own emotional underworld and returned with hard-won wisdom.",jungian:"The archetype of the Wise Old Man or the healed healer — the shadow integrated, the depths explored, the anima understood. He has done the inner work and now holds the container for others. The shadow is emotional manipulation, using empathy as leverage.",powerGods:"The priest-king whose authority rests on his perceived access to divine waters — healing, cursing, knowing. Power through emotional intelligence weaponised: the one who knows what you need and controls its dispensation.",traditional:"The spiritual director, confessor, or shaman whose compassion is genuine but whose role is strictly defined by tradition. He heals within a sacred structure. Wisdom is passed down, not invented. Boundaries protect both giver and receiver.",modern:"The therapist, the emotionally intelligent executive, the creative director who leads through empathy rather than hierarchy. He understands what motivates people and creates conditions for their best work. Feelings are data.",postModern:"Whose emotions are permitted to be mastered? The calm emotional authority of the king often rests on structures that suppress certain feelings as chaotic or dangerous. Emotional labour is unevenly distributed.",metaModern:"The integrated emotional leader who holds both depth and stability — neither suppressing feelings nor drowning in them. He models that emotional intelligence is not about control but about honest, grounded presence."},"queen-of-cups":{suit:"Cups",rank:"queen",mbti:"ESFP",title:"Queen of the Thrones of Water",description:"The Queen of Cups is Water of Water — pure emotional receptivity and psychic depth. She is the mirror of the soul, capable of reflecting back what others most need to see. Intuitive, empathic, and profoundly interior, she lives in the borderlands between the seen and unseen. Her gift is a quality of presence that makes others feel truly known. The challenge is maintaining her own boundaries amid the constant flow of feeling.",jungian:"The anima in her most complete form — the unconscious made conscious, the feeling function fully developed. She is the inner feminine principle that connects ego to Self through the medium of emotion and image. Her shadow is dissolution of the self in service to others.",powerGods:"The oracle whose access to the depths gives her an uncanny power over those who desperately need to be seen. The sibyl who knows your secrets. Power through reflection — showing others themselves in ways they cannot resist.",traditional:"The contemplative, the mystic, the vessel of divine compassion. She prays for the world from a place of profound stillness. Her depth is a gift from God, to be held in humility and offered in service.",modern:"The highly attuned therapist, the artist who channels collective emotional truth, the mother who knows her children's inner lives better than they do. Emotional depth as professional and personal superpower.",postModern:"The burden of endless emotional attunement — especially when it falls to women by default. The queen who contains everyone else's feelings at the cost of her own. Whose cup is being filled?",metaModern:"Profound receptivity paired with self-honouring boundaries. The queen who is both deeply open and clearly herself — presence without merger, compassion without self-erasure. The cup that also pours into itself."},"knight-of-cups":{suit:"Cups",rank:"knight",mbti:"ISTP",title:"Lord of the Waves and the Waters",description:"The Knight of Cups is Air of Water — romantic idealism borne aloft on poetic imagination. He is the troubadour, the mystic knight, the dreamer who follows his heart across impossible distances. His offers of love and beauty are genuine, but they may evaporate when reality demands practicality. He is the invitation to something transcendent, always arriving with a message from the realm of the ideal.",jungian:"The romantic animus projection at its most seductive — the figure onto whom one casts all longings for transcendence and perfect love. Psychologically, encountering this archetype asks whether one is in love with the ideal or the actual person before them.",powerGods:"The seducer whose beauty and sensitivity are precisely his weapons. Power through romantic idealism — making you believe you are the one who will finally be enough for his impossible heart.",traditional:"The chivalric knight who serves a lady or a spiritual ideal with pure devotion. Love as sacred vow. Courtly love as a discipline that elevates the soul. Feeling refined through ritual and sacrifice.",modern:"The sensitive artist-lover, the man who makes grand gestures and disappears when the work of sustaining intimacy begins. Emotional intelligence without emotional maturity. The muse rather than the partner.",postModern:"The romantic ideal as a cultural construct that sets impossible standards and punishes the mundane. Whose version of love gets to be called romantic? The troubadour tradition and its gendered power dynamics.",metaModern:"The heart's genuine longing for transcendence, held within the willingness to show up for the ordinary. Romance integrated with commitment. The ideal and the real held in productive tension."},"page-of-cups":{suit:"Cups",rank:"page",mbti:"ISFP",title:"Princess of the Waters",description:"The Page of Cups is Earth of Water — emotional sensitivity in its most open, undefended form. She is the dreaming child who hears the fish speaking from the cup, who finds magic in unexpected encounters. Psychic, tender, and imaginatively alive, she brings messages from the unconscious in the form of synchronicities, dreams, and sudden flashes of inspiration. Her gift is the ability to receive what others have already stopped listening for.",jungian:"The anima in her earliest, most unformed manifestation — the soul-image before it has been shaped by encounter with the world. She represents the pristine receptivity of the unconscious, capable of extraordinary perception precisely because she carries no armour.",powerGods:"The strange child whose uncanny perceptions unsettle the adults around her. Power through innocence — no one quite knows what to do with someone who sees through the agreed-upon pretences.",traditional:"The novice in the emotional or spiritual life, learning to tend the inner waters with gentleness and reverence. Feeling as a sacred gift to be developed slowly and carefully.",modern:"The highly sensitive person discovering their empathic gifts, the young artist learning to trust their emotional truth over external validation. Vulnerability as creative strength.",postModern:"The romanticisation of childlike innocence as a solution to over-rationalised culture. Whose sensitivity is valued as visionary and whose is dismissed as fragility?",metaModern:"The open heart that has learned discernment without losing wonder. Emotional receptivity paired with the first growth of healthy boundaries — still listening for the fish in the cup, but beginning to understand what the message means."},"king-of-swords":{suit:"Swords",rank:"king",mbti:"ENTP",title:"Lord of the Wind and the Breezes",description:"The King of Swords is Fire of Air — fierce intelligence commanding clear, authoritative judgement. He is the archetype of the judge, the commander, the analytical genius who cuts through confusion with precision and intellectual courage. His mind operates at speed, seeing through deception and holding complex systems simultaneously. He demands clarity, expects directness, and has little patience for emotional reasoning in place of rational evidence.",jungian:"The fully developed thinking function — logos in its most austere expression. Represents the ego's capacity for clear-eyed self-examination and the courage to follow reason to conclusions others flinch from. The shadow is intellectual cruelty, where precision becomes weaponised detachment.",powerGods:"The military strategist whose advantage is information and the willingness to act on it decisively and without sentiment. Power through superior intelligence and the capacity to impose order through force of judgement.",traditional:"The lawgiver, the magistrate, the scholar-priest whose word carries the weight of accumulated tradition and careful study. Reason in service of divine order. The letter of the law as a moral framework.",modern:"The surgeon, the barrister, the systems thinker — someone whose value lies in the precision of their analysis and their immunity to cognitive bias. Objectivity as professional virtue. The expert's authority.",postModern:'Whose reason counts as universal? The sword of "objective" analysis has historically cut in very particular directions. Exposing the ideological freight carried in claims to pure rationality.',metaModern:"Clear intelligence in service of genuine understanding — reason that includes rather than excludes, precision that illuminates rather than diminishes. The sword wielded with care for what it cuts."},"queen-of-swords":{suit:"Swords",rank:"queen",mbti:"ENFP",title:"Queen of the Thrones of Air",description:"The Queen of Swords is Water of Air — deep feeling processed through crystalline clarity of mind. She has known grief, loss, and the sharp edges of experience, and from these she has forged an intelligence of devastating perceptiveness. She sees through pretence without effort, communicates with precise honesty, and holds her boundaries with calm firmness. Her apparent coldness is not absence of feeling but the discipline of someone who has learned what clarity costs.",jungian:"The integration of the thinking and feeling functions — a figure who has passed through the waters of grief and emerged with a mind that is both sharp and deep. She represents the wisdom that comes only through experience of loss. Her shadow is bitterness: clarity curdled into contempt.",powerGods:"The widow-queen whose loss has stripped away every illusion and left a sovereign entirely free of the need for approval. Power through indifference — she no longer needs what you're withholding.",traditional:"The learned woman whose grief has refined her faith and whose sharp intelligence serves a higher truth. The wise woman whose advice is sought precisely because she feels nothing for your ego.",modern:"The brilliant analyst or editor who demands clarity and tolerates no intellectual dishonesty. She has seen through every rationalisation and expects you to have done the same. Standards without sentimentality.",postModern:"The woman who had to develop intellectual armour to be taken seriously in structures not built for her. The cost of claiming clarity in a world that pathologises emotional women and cold women equally.",metaModern:"Clarity and compassion held together without pretending either is easy. The queen who can say the hard true thing and remain open to the other's pain. Honesty as an act of care."},"knight-of-swords":{suit:"Swords",rank:"knight",mbti:"INTP",title:"Lord of the Wind and the Storms",description:"The Knight of Swords is Air of Air — pure mental force moving at maximum velocity. He is the storm of intellect: brilliant, unstoppable, and often heedless of what he destroys in his rush toward truth. An argument is never settled until every weakness has been exposed. He charges into every intellectual debate with complete commitment, and his ideas, right or wrong, arrive with the force of absolute conviction. He is the archetype of the principled crusader and the fanatic in equal measure.",jungian:"The thinking function at its most untempered — the animus fully identified with abstract principle at the expense of embodied reality. He represents the psyche's capacity for absolute conviction, which can be liberating or catastrophic depending on whether the conviction is earned.",powerGods:"The ideological warrior who fights for an idea as though his life depends on it — because in his world it does. Power through the willingness to sacrifice everything, including relationships, for principle.",traditional:"The crusader, the reformer, the monk with a sword — faith so absolute it becomes a weapon. The terrifying integrity of someone who has surrendered entirely to a cause larger than themselves.",modern:"The investigative journalist, the contrarian intellectual, the radical activist — someone who pursues truth at personal cost and expects the same from everyone around them. Debate as a moral obligation.",postModern:"The violence of certainty. Whose truths get to move at full speed and whose are required to prove themselves at every step? The knight's charge leaves behind a landscape of dismantled arguments, some of which were load-bearing.",metaModern:"The sharp mind that has learned to aim before charging. Truth-seeking with epistemic humility — willing to be wrong, willing to slow down, willing to consider whether the battle is worth the battlefield."},"page-of-swords":{suit:"Swords",rank:"page",mbti:"INFP",title:"Princess of the Rushing Winds",description:"The Page of Swords is Earth of Air — intellectual curiosity in its most restless, alert form. She is watching, listening, analysing, gathering information before committing to any position. Clever, quick, and slightly suspicious of everyone's motives, she is the young spy, the student who questions everything, the mind that has not yet found its cause but is ready to draw at a moment's notice. Unexpected news, surveillance, and the early stages of learning to think critically all belong to her.",jungian:"The early stages of differentiation of the thinking function — the nascent intellect testing its edges against the world. A necessary vigilance that precedes trust. Her shadow is paranoia: alertness that cannot switch off.",powerGods:"The young informant whose power lies in what they know that others don't. Gathering intelligence as protection and leverage. The child who learned early that information is survival.",traditional:"The diligent student preparing for examination, the young soldier standing watch — discipline before authority, learning the rules before questioning them.",modern:"The intern with a notepad, the graduate researcher, the junior analyst — sharp, eager, slightly overwhelming in their thoroughness. Has not yet learned to be strategic with their observations.",postModern:"The whistleblower in the making. The one in the institution who notices what everyone else has agreed not to see. Whose vigilance is paranoia and whose is justified?",metaModern:"The curious mind that has learned to ask questions from genuine wonder rather than defensive alert. Intelligence as a gift offered rather than a shield raised. Watching the world with openness rather than suspicion."},"king-of-pentacles":{suit:"Pentacles",rank:"king",mbti:"ESTJ",title:"Lord of the Wild and Fertile Land",description:"The King of Pentacles is Fire of Earth — mastery over the material world, the will that has transformed effort into enduring abundance. He is the patriarch of wealth and practical wisdom: methodical, generous, and utterly reliable. Having built something lasting from patient labour, he now rules with the calm authority of someone who knows the land completely. He values what endures over what impresses, and his generosity is grounded in genuine sufficiency.",jungian:"The father archetype fully embodied in the material realm — the ego that has successfully negotiated with reality and arrived at genuine security rather than compensatory accumulation. The shadow is miserliness: the fear that the land will fail again, hoarding against an imagined scarcity.",powerGods:"The feudal lord whose ownership of land is ownership of lives. Power through the control of resources — he who controls the harvest controls the people. Wealth as an expression of superior virtue or divine favour.",traditional:"The steward of God's abundance, responsible for those who labour on his land. Wealth held in trust, not as personal achievement but as sacred obligation. Generosity as the proper use of worldly goods.",modern:"The self-made mogul who built an empire through persistent, methodical effort. He doesn't need to impress anyone — the results speak. Long-term thinking, patient capital, compound returns on every investment including relationships.",postModern:'Whose labour builds the king\'s abundance? The landed patriarch as a figure sustained by invisible toil. Examining what it means to "build something" when the foundations rest on unpaid or underpaid work.',metaModern:"Prosperity rooted in genuine contribution and equitably distributed. The steward-king who knows his abundance is relational — sustained by the health of everyone in the ecosystem, not extracted from it."},"queen-of-pentacles":{suit:"Pentacles",rank:"queen",mbti:"ESFJ",title:"Queen of the Thrones of Earth",description:"The Queen of Pentacles is Water of Earth — sensuous, nurturing abundance in its most fully embodied form. She is the great mother of material life: she tends bodies, cultivates soil, manages households, and creates the conditions in which everything and everyone she cares for can thrive. Practical, sensory, deeply present in the physical world, she finds the sacred in the ordinary — in food, in touch, in the careful organisation of material reality into sustainable flourishing.",jungian:"The Great Mother archetype in her most benevolent and earthy form — the anima fully incarnated in matter. She represents the psyche's capacity to find meaning and pleasure in embodied existence rather than transcendence. Her shadow is possessive over-protection: smothering in the name of care.",powerGods:"The earth goddess whose fertility is worshipped and whose displeasure means famine. Power through the control of nourishment — she who feeds holds the deepest authority over those who are hungry.",traditional:"The ideal mother and householder, whose domain is the sacred space of the home. Her labour is invisible because it is everything. She builds the world from the inside out, one meal, one hearth, one tended body at a time.",modern:"The brilliant domestic economist, the ethical investor, the woman who builds quiet wealth through attention to detail and the long game. She does not seek visibility but her competence is undeniable.",postModern:"The domestic as political — whose \"natural\" gift for nurturing becomes someone else's infrastructure? The queen's abundance is built on labour that the world prefers to call instinct.",metaModern:"The body and earth held as sacred — not in the service of productivity but as intrinsic value. Nurturing from genuine fullness. The queen who tends herself as carefully as she tends her realm."},"knight-of-pentacles":{suit:"Pentacles",rank:"knight",mbti:"ISTJ",title:"Lord of the Wide and Fertile Land",description:"The Knight of Pentacles is Air of Earth — methodical intelligence applied to the patient work of building. He is the diligent labourer, the careful craftsman, the dependable planner who will not be rushed. While other knights charge recklessly ahead, he surveys the territory, checks the soil, and then proceeds step by deliberate step. He may lack the dash of his companions, but the work he completes is done with absolute thoroughness. What he builds, lasts.",jungian:"The thinking function grounded in sensation — intellect that respects rather than transcends the physical. Represents the capacity for sustained effort: the psychological function that can defer gratification indefinitely in service of a long-term goal. The shadow is stagnation: patience hardened into refusal to change.",powerGods:"The veteran who has outlasted every brilliant strategist through simple endurance. Power through reliability — the one the kingdom actually depends on when the visionaries have moved on.",traditional:"The yeoman farmer, the guild craftsman — someone for whom work is vocation and quality is a moral standard. There is dignity in honest labour. The work is its own reward.",modern:"The project manager, the DevOps engineer, the reliability expert — the person who makes everything else work by paying attention to the things no one else wants to care about. Unglamorous and indispensable.",postModern:"The steady worker as a figure often erased from narratives that celebrate disruption and innovation. Whose reliability sustains whose freedom to be creative? Endurance as a class phenomenon.",metaModern:"Dedication without rigidity — patient work held within awareness that the land itself changes. The knight who tends the soil while remaining willing to change crops when the season demands it."},"page-of-pentacles":{suit:"Pentacles",rank:"page",mbti:"ISFJ",title:"Princess of the Echoing Hills",description:"The Page of Pentacles is Earth of Earth — the concentrated essence of material potential, still and studious. She holds her coin up to the light not to show it off but to truly understand it. She is the dedicated student, the young apprentice, the careful researcher who wants to learn the craft properly before attempting mastery. Practical, grounded, and genuinely curious about how the physical world works, she represents the first careful steps toward material competence.",jungian:"The earliest stage of the ego's encounter with material reality — the self learning that the world has its own logic that must be respected before it can be worked with. She is the psyche discovering the discipline of craft.",powerGods:"The young inheritor who understands, perhaps for the first time, what it actually means to hold power in the material world. The weight of the coin. The responsibility of what can be built or squandered.",traditional:"The apprentice who submits to the master's teaching, the novice before the craft. Humility before knowledge. Learning as a sacred obligation. The long path of genuine skill.",modern:"The intern who actually wants to learn the business from the ground up, the first-generation college student managing a budget for the first time. The excitement and terror of material competence emerging.",postModern:"The student whose access to craft and learning is circumscribed by the resources available to them. Whose dedication gets transformed into professional skill and whose remains amateur?",metaModern:"The beginner who approaches material reality with reverence and curiosity — understanding that competence must be grown, not seized. Earth studied with the patience of someone who knows the harvest will come."}},M={Wands:"Ni",Cups:"Se",Swords:"Ne",Pentacles:"Si"},C={king:{attitude:"E",judging:"T"},queen:{attitude:"E",judging:"F"},knight:{attitude:"I",judging:"T"},page:{attitude:"I",judging:"F"}},P={ENTJ:{name:"The Commander",stack:["Ni","Te","Fi","Se"],description:"Strategic leaders driven by long-range vision and decisive action. They organise systems and people toward ambitious goals with relentless efficiency.",courtBridge:"As the Knight of Wands (Thoth), ENTJ channels Ni-dominant intuition through extraverted thinking — the fiery will that commands through visionary strategy rather than brute force."},ENFJ:{name:"The Protagonist",stack:["Ni","Fe","Ti","Se"],description:"Charismatic idealists who inspire and guide others toward growth. They sense what people need and create the conditions for collective flourishing.",courtBridge:"As the Queen of Wands, ENFJ wields Ni-dominant intuition through extraverted feeling — the warm radiance that draws others into a shared vision and holds them there with genuine care."},INTJ:{name:"The Architect",stack:["Ni","Te","Fi","Se"],description:"Independent strategists who see patterns others miss. They build complex internal models of reality and pursue their vision with quiet, unrelenting determination.",courtBridge:"As the Prince of Wands (Thoth), INTJ embodies Ni-dominant intuition processed through introverted thinking — the inner fire that moves outward as intellectual force and systemic insight."},INFJ:{name:"The Advocate",stack:["Ni","Fe","Ti","Se"],description:"Visionary empaths who seek deep meaning and work quietly toward ideals. They understand people at a level that can seem almost psychic, driven by a sense of purpose larger than themselves.",courtBridge:"As the Princess of Wands (Thoth), INFJ holds Ni-dominant intuition in its most inward, potential-bearing form — the spark before it becomes flame, the vision still gathering its creative force."},ESTP:{name:"The Entrepreneur",stack:["Se","Ti","Fe","Ni"],description:"Bold pragmatists who thrive in the present moment. They read situations instantly, take decisive action, and adapt on the fly with easy confidence.",courtBridge:"As the Knight of Cups (Thoth), ESTP channels Se-dominant sensing through extraverted thinking — the mastery of emotional and sensory currents wielded with commanding authority."},ESFP:{name:"The Entertainer",stack:["Se","Fi","Te","Ni"],description:"Vivacious experientialists who bring warmth and spontaneity wherever they go. They live through direct sensory engagement and share that aliveness generously.",courtBridge:"As the Queen of Cups, ESFP expresses Se-dominant sensing through extraverted feeling — pure emotional receptivity alive in the present moment, reflecting beauty and feeling back to the world."},ISTP:{name:"The Virtuoso",stack:["Se","Ti","Fe","Ni"],description:"Cool-headed analysts who understand systems through hands-on engagement. They take things apart to see how they work and respond to crises with calm precision.",courtBridge:"As the Prince of Cups (Thoth), ISTP moves Se-dominant sensing through introverted thinking — the romantic idealism of water processed through detached, elegant analysis."},ISFP:{name:"The Adventurer",stack:["Se","Fi","Te","Ni"],description:"Gentle artists who experience the world through a rich inner palette of values and aesthetics. They live authentically, guided by deep personal feeling rather than external expectation.",courtBridge:"As the Princess of Cups (Thoth), ISFP holds Se-dominant sensing in its most tender, undefended form — the open heart that receives the world as beauty and translates it into quiet creative expression."},ENTP:{name:"The Debater",stack:["Ne","Ti","Fe","Si"],description:"Inventive provocateurs who see possibilities everywhere and challenge every assumption. They generate ideas at speed and thrive on intellectual sparring.",courtBridge:"As the Knight of Swords (Thoth), ENTP channels Ne-dominant intuition through extraverted thinking — the fierce intellect that commands through the force of argument and the clarity of analysis."},ENFP:{name:"The Campaigner",stack:["Ne","Fi","Te","Si"],description:"Enthusiastic visionaries who connect ideas, people, and possibilities into inspiring narratives. They champion causes with infectious optimism and genuine warmth.",courtBridge:"As the Queen of Swords, ENFP expresses Ne-dominant intuition through extraverted feeling — the perceptive clarity born of deep experience, wielding honesty as an act of compassion."},INTP:{name:"The Logician",stack:["Ne","Ti","Fe","Si"],description:"Abstract thinkers who build intricate theoretical frameworks. They pursue logical consistency with quiet intensity, always refining their understanding of how things work.",courtBridge:"As the Prince of Swords (Thoth), INTP moves Ne-dominant intuition through introverted thinking — the storm of pure intellect, brilliant and unstoppable in its pursuit of truth."},INFP:{name:"The Mediator",stack:["Ne","Fi","Te","Si"],description:"Idealistic dreamers guided by deeply held values. They seek authenticity and meaning, often expressing their rich inner world through creative and compassionate action.",courtBridge:"As the Princess of Swords (Thoth), INFP holds Ne-dominant intuition in its most alert, watchful form — the curious mind gathering impressions before committing, vigilant and ready to draw."},ESTJ:{name:"The Executive",stack:["Si","Te","Fi","Ne"],description:"Organised administrators who build and maintain reliable systems. They value tradition, responsibility, and clear chains of command, leading through consistent example.",courtBridge:"As the Knight of Pentacles (Thoth), ESTJ channels Si-dominant sensing through extraverted thinking — the mastery of the material world expressed as authoritative stewardship and practical wisdom."},ESFJ:{name:"The Consul",stack:["Si","Fe","Ti","Ne"],description:"Warm community-builders who create harmony and ensure everyone is cared for. They honour traditions, remember details, and sustain the social fabric through devoted attention.",courtBridge:"As the Queen of Pentacles, ESFJ expresses Si-dominant sensing through extraverted feeling — the nurturing abundance that tends bodies, soil, and souls with sensuous, embodied care."},ISTJ:{name:"The Logistician",stack:["Si","Te","Fi","Ne"],description:"Dependable realists who honour duty and follow through with meticulous care. They build lasting structures through patient, methodical effort and unwavering commitment.",courtBridge:"As the Prince of Pentacles (Thoth), ISTJ moves Si-dominant sensing through introverted thinking — the diligent craftsman who surveys, plans, and builds with absolute thoroughness."},ISFJ:{name:"The Defender",stack:["Si","Fe","Ti","Ne"],description:"Quiet protectors who remember what matters and work tirelessly behind the scenes. They preserve what is valuable, support those they love, and approach learning with humble dedication.",courtBridge:"As the Princess of Pentacles (Thoth), ISFJ holds Si-dominant sensing in its most studious, potential-bearing form — the careful apprentice who wants to understand the craft before attempting mastery."}};function A(e,a){let o=M[e],{attitude:i,judging:n}=C[a],t="S"===o.charAt(0)?"S":"N";return"".concat(i).concat(t).concat(n).concat("Si"===o||"Ni"===o?"J":"P")}let W={2:"El n\xfamero de la dualidad, la asociaci\xf3n y la elecci\xf3n. El dos representa el equilibrio, la cooperaci\xf3n y la interacci\xf3n entre fuerzas opuestas. Habla de decisiones, relaciones y la necesidad de encontrar armon\xeda entre diferentes aspectos.",3:"El n\xfamero de la creaci\xf3n y el crecimiento. El tres representa la s\xedntesis de fuerzas opuestas que crean algo nuevo. Habla de creatividad, autoexpresi\xf3n, colaboraci\xf3n y la manifestaci\xf3n de ideas en forma concreta.",4:"El n\xfamero de la estabilidad y los cimientos. El cuatro representa el orden, la estructura y las bases s\xf3lidas. Habla de la manifestaci\xf3n en el mundo material, el establecimiento de l\xedmites y la creaci\xf3n de seguridad duradera.",5:"El n\xfamero del cambio y la disrupci\xf3n. El cinco representa la inestabilidad, el conflicto y los cambios necesarios. Habla de libertad, aventura y los desaf\xedos que conducen al crecimiento y el aprendizaje.",6:"El n\xfamero de la armon\xeda y el equilibrio. El seis representa el balance, el amor y la belleza. Habla de la nutrici\xf3n, la sanaci\xf3n, la responsabilidad y la b\xfasqueda de soluciones que beneficien a todos.",7:"El n\xfamero de la sabidur\xeda y la espiritualidad. El siete representa el conocimiento interior, el an\xe1lisis y la conciencia espiritual. Habla de buscar verdades m\xe1s profundas, la introspecci\xf3n y la comprensi\xf3n m\xe1s all\xe1 de lo material.",8:"El n\xfamero del poder y la manifestaci\xf3n. El ocho representa el \xe9xito material, la autoridad y el poder personal. Habla del logro, la fuerza y la capacidad de hacer que las cosas sucedan en el mundo f\xedsico.",9:"El n\xfamero de la culminaci\xf3n y la plenitud. El nueve representa el logro, la consumaci\xf3n y la sabidur\xeda adquirida a trav\xe9s de la experiencia. Habla de alcanzar metas, la conciencia espiritual y la preparaci\xf3n para nuevos ciclos.",10:"El n\xfamero de la completitud y los nuevos comienzos. El diez representa el fin de un ciclo y el potencial para nuevos inicios. Habla de la manifestaci\xf3n, la finalidad y la acumulaci\xf3n de las energ\xedas de todos los n\xfameros anteriores."},R={Wands:"El palo del fuego, la pasi\xf3n, la creatividad y la ambici\xf3n. Los Bastos representan la energ\xeda espiritual, la inspiraci\xf3n, la determinaci\xf3n, la fuerza, la intuici\xf3n, la creatividad, la ambici\xf3n y la expansi\xf3n, el pensamiento original y las semillas de las cuales brota la vida.",Cups:"El palo del agua, las emociones, la intuici\xf3n y las relaciones. Las Copas representan los sentimientos, las emociones, la intuici\xf3n, las relaciones, el amor, la sanaci\xf3n y el viaje del alma a trav\xe9s de las aguas de la vida.",Swords:"El palo del aire, el intelecto, el pensamiento y la acci\xf3n. Las Espadas representan la mente, los pensamientos, la comunicaci\xf3n, el conflicto, el poder, el cambio, la fuerza y los aspectos intelectuales de la conciencia.",Pentacles:"El palo de la tierra, los asuntos materiales y la practicidad. Los Pent\xe1culos representan la manifestaci\xf3n, la realidad, la materia f\xedsica, la carrera, el dinero, el hogar, el cuerpo y los resultados tangibles de nuestros esfuerzos en el mundo material."},I={"2 of Wands":{title:"Se\xf1or del Dominio",description:"Planificaci\xf3n futura y decisiones, dando los primeros pasos hacia la manifestaci\xf3n de tus metas."},"3 of Wands":{title:"Se\xf1or de la Fuerza Establecida",description:"Expansi\xf3n, previsi\xf3n y liderazgo en empresas que comienzan a mostrar resultados."},"4 of Wands":{title:"Se\xf1or de la Obra Perfeccionada",description:"Celebraci\xf3n, armon\xeda y la culminaci\xf3n de una fase significativa que trae alegr\xeda y estabilidad."},"5 of Wands":{title:"Se\xf1or de la Contienda",description:"Competencia, conflicto y tensi\xf3n creativa que impulsa el crecimiento a trav\xe9s del desaf\xedo."},"6 of Wands":{title:"Se\xf1or de la Victoria",description:"\xc9xito, reconocimiento y triunfo despu\xe9s de haber puesto el esfuerzo necesario."},"7 of Wands":{title:"Se\xf1or del Valor",description:"Mantener tu posici\xf3n, defender tu terreno y conservar el coraje bajo presi\xf3n."},"8 of Wands":{title:"Se\xf1or de la Rapidez",description:"Movimiento veloz, acci\xf3n r\xe1pida y mensajes que llegan con noticias importantes."},"9 of Wands":{title:"Se\xf1or de la Gran Fuerza",description:"Resiliencia, perseverancia y mantenimiento de posiciones defensivas mientras se re\xfane fuerza interior."},"10 of Wands":{title:"Se\xf1or de la Opresi\xf3n",description:"Carga, responsabilidad y el peso del \xe9xito que puede volverse demasiado pesado de soportar."},"2 of Cups":{title:"Se\xf1or del Amor",description:"Asociaci\xf3n, romance y la uni\xf3n armoniosa de fuerzas en perfecto equilibrio."},"3 of Cups":{title:"Se\xf1or de la Abundancia",description:"Celebraci\xf3n, amistad y el compartir gozoso de la abundancia emocional."},"4 of Cups":{title:"Se\xf1or del Lujo o del Placer Mezclado",description:"Contemplaci\xf3n, reevaluaci\xf3n y posible insatisfacci\xf3n a pesar de la seguridad emocional."},"5 of Cups":{title:"Se\xf1or de la P\xe9rdida en el Placer",description:"Decepci\xf3n, p\xe9rdida emocional, pero con esperanza si miras m\xe1s all\xe1 de las copas derramadas."},"6 of Cups":{title:"Se\xf1or del Placer",description:"Nostalgia, felicidad inocente y la alegr\xeda pura de compartir con otros."},"7 of Cups":{title:"Se\xf1or del \xc9xito Ilusorio",description:"Elecciones, fantas\xedas y la necesidad de distinguir entre sue\xf1os y realidad."},"8 of Cups":{title:"Se\xf1or del \xc9xito Abandonado",description:"Seguir adelante, buscar un significado m\xe1s profundo y dejar atr\xe1s lo que ya no sirve."},"9 of Cups":{title:"Se\xf1or de la Felicidad Material",description:"Contentamiento, satisfacci\xf3n emocional y el cumplimiento de los deseos."},"10 of Cups":{title:"Se\xf1or del \xc9xito Perpetuo",description:"Armon\xeda, felicidad duradera y el logro de la plenitud emocional."},"2 of Swords":{title:"Se\xf1or de la Paz Restaurada",description:"Toma de decisiones, paz temporal a trav\xe9s de la evasi\xf3n y la necesidad de equilibrio."},"3 of Swords":{title:"Se\xf1or del Dolor",description:"Desamor, verdad dolorosa y el proceso necesario de liberaci\xf3n emocional."},"4 of Swords":{title:"Se\xf1or del Descanso tras la Contienda",description:"Recuperaci\xf3n, meditaci\xf3n y la necesidad de contemplaci\xf3n y reposo."},"5 of Swords":{title:"Se\xf1or de la Derrota",description:"Conflicto, derrota y la victoria hueca de ganar a cualquier precio."},"6 of Swords":{title:"Se\xf1or del \xc9xito Merecido",description:"Transici\xf3n, avanzar y dejar aguas turbulentas rumbo a costas m\xe1s tranquilas."},"7 of Swords":{title:"Se\xf1or del Esfuerzo Inestable",description:"Estrategia, enga\xf1o y la evaluaci\xf3n cuidadosa de riesgos y \xe9tica."},"8 of Swords":{title:"Se\xf1or de la Fuerza Menguada",description:"Restricci\xf3n, limitaciones autoimpuestas y la necesidad de ver m\xe1s all\xe1 de las barreras aparentes."},"9 of Swords":{title:"Se\xf1or de la Desesperaci\xf3n y la Crueldad",description:"Ansiedad, pesadillas y el peso de los pensamientos de preocupaci\xf3n en la noche oscura."},"10 of Swords":{title:"Se\xf1or de la Ruina",description:"Finales dolorosos, tocar fondo y la promesa de luz despu\xe9s de la oscuridad."},"2 of Pentacles":{title:"Se\xf1or del Cambio Armonioso",description:"Equilibrio, adaptabilidad y malabarismo con m\xfaltiples responsabilidades con gracia."},"3 of Pentacles":{title:"Se\xf1or de las Obras Materiales",description:"Artesan\xeda, colaboraci\xf3n y el dominio de habilidades pr\xe1cticas."},"4 of Pentacles":{title:"Se\xf1or del Poder Terrenal",description:"Seguridad, control y la necesidad de equilibrar la estabilidad material con la generosidad."},"5 of Pentacles":{title:"Se\xf1or de la Tribulaci\xf3n Material",description:"Adversidad, pobreza espiritual y la necesidad de buscar ayuda en tiempos dif\xedciles."},"6 of Pentacles":{title:"Se\xf1or del \xc9xito Material",description:"Generosidad, prosperidad y el flujo equilibrado de dar y recibir."},"7 of Pentacles":{title:"Se\xf1or del \xc9xito Incumplido",description:"Evaluaci\xf3n, paciencia y la valoraci\xf3n de inversiones a largo plazo."},"8 of Pentacles":{title:"Se\xf1or de la Prudencia",description:"Desarrollo de habilidades, dedicaci\xf3n y la atenci\xf3n cuidadosa al detalle en tu trabajo."},"9 of Pentacles":{title:"Se\xf1or de la Ganancia Material",description:"Independencia, lujo y los frutos del esfuerzo disciplinado y el refinamiento."},"10 of Pentacles":{title:"Se\xf1or de la Riqueza",description:"Legado, herencia y el establecimiento de abundancia material duradera."}},G={"2 of Wands":"Representa la tensi\xf3n entre la seguridad y la aventura, el primer paso en la individuaci\xf3n donde uno debe elegir entre lo familiar y lo desconocido.","3 of Wands":"Simboliza la expansi\xf3n de la conciencia a trav\xe9s del compromiso activo con el mundo, representando la creciente percepci\xf3n del ego sobre su potencial.","4 of Wands":"Refleja el establecimiento de una estructura estable del ego, celebrando los cimientos necesarios para un mayor crecimiento psicol\xf3gico.","5 of Wands":"Representa los conflictos internos y los aspectos competitivos de la psique que deben integrarse para el crecimiento personal.","6 of Wands":"Simboliza el triunfo de la mente consciente al lograr reconocimiento y validar el viaje del ser.","7 of Wands":"Representa el coraje de mantener el propio camino individual a pesar de la oposici\xf3n de las fuerzas colectivas.","8 of Wands":"Simboliza el movimiento veloz de la energ\xeda ps\xedquica cuando las barreras entre lo consciente y lo inconsciente se levantan temporalmente.","9 of Wands":"Refleja las estructuras defensivas construidas por el ego despu\xe9s de experimentar desaf\xedos, mostrando tanto protecci\xf3n como posible limitaci\xf3n.","10 of Wands":"Representa la carga de la conciencia y la responsabilidad que viene con una mayor percepci\xf3n psicol\xf3gica.","2 of Cups":"Simboliza el reconocimiento inicial del \xe1nima/\xe1nimus, el primer paso para comprender la necesidad del alma de conexi\xf3n emocional.","3 of Cups":"Representa la celebraci\xf3n de la plenitud emocional y la integraci\xf3n de diferentes aspectos de la psique.","4 of Cups":"Refleja un estado de estancamiento emocional donde la psique necesita reconocer nuevas posibilidades de crecimiento.","5 of Cups":"Simboliza la experiencia necesaria de p\xe9rdida y duelo en el proceso de transformaci\xf3n psicol\xf3gica.","6 of Cups":"Representa la reconexi\xf3n con el ni\xf1o interior y los aspectos puros e incondicionados de la psique.","7 of Cups":"Simboliza el encuentro con la sombra a trav\xe9s de ilusiones y proyecciones del inconsciente.","8 of Cups":"Representa el coraje de abandonar viejos patrones emocionales en busca de una verdad psicol\xf3gica m\xe1s profunda.","9 of Cups":"Refleja el estado de plenitud emocional que surge de la integraci\xf3n exitosa de elementos conscientes e inconscientes.","10 of Cups":"Simboliza el logro de la totalidad psicol\xf3gica y la completitud emocional.","2 of Swords":"Representa el intento de la mente de mantener el equilibrio a trav\xe9s de la negaci\xf3n o la evasi\xf3n del conflicto psicol\xf3gico.","3 of Swords":"Simboliza el dolor necesario de tomar conciencia de verdades emocionales reprimidas.","4 of Swords":"Refleja la necesidad de retiro psicol\xf3gico e integraci\xf3n de realizaciones dif\xedciles.","5 of Swords":"Representa los conflictos internos y las luchas de poder dentro de la psique.","6 of Swords":"Simboliza el viaje de transici\xf3n de un estado de conciencia a otro.","7 of Swords":"Representa el arquetipo del embaucador y las formas en que nos enga\xf1amos a nosotros mismos.","8 of Swords":"Refleja las limitaciones autoimpuestas y el miedo a enfrentar la propia sombra.","9 of Swords":"Simboliza el viaje nocturno por el mar del inconsciente y la confrontaci\xf3n con miedos profundos.","10 of Swords":"Representa la muerte de viejos patrones de pensamiento y el potencial para el renacimiento psicol\xf3gico.","2 of Pentacles":"Representa el equilibrio din\xe1mico necesario entre los aspectos materiales y espirituales de la vida en el proceso de individuaci\xf3n.","3 of Pentacles":"Simboliza la integraci\xf3n de diferentes aspectos del ser en un trabajo significativo.","4 of Pentacles":"Refleja el intento del ego de mantener el control y la seguridad, a veces a costa del crecimiento.","5 of Pentacles":"Representa la experiencia de pobreza material o espiritual que a menudo precede a la transformaci\xf3n.","6 of Pentacles":"Simboliza el intercambio entre diferentes aspectos de la psique, dar y recibir en equilibrio.","7 of Pentacles":"Refleja la paciencia requerida en el proceso de crecimiento y transformaci\xf3n psicol\xf3gica.","8 of Pentacles":"Representa el trabajo disciplinado de forjar el propio camino individual de individuaci\xf3n.","9 of Pentacles":"Simboliza el logro de la independencia psicol\xf3gica y la autosuficiencia.","10 of Pentacles":"Representa la manifestaci\xf3n del S\xed Mismo y el logro de la totalidad psicol\xf3gica en el mundo material."},N={"2 of Wands":{powerGods:"Tienes el mundo en tus manos, guerrero. Dos caminos, dos reinos, pero no puedes conquistar ambos a la vez. Los d\xe9biles deliberan eternamente; los fuertes eligen y golpean. \xbfCu\xe1l reino sentir\xe1 tu fuego primero? Deja la vacilaci\xf3n para las almas menores. Tu hambre es sagrada: alim\xe9ntala.",traditional:"Dos caminos se despliegan ante ti, fiel, y las escrituras hablan de ambos. Busca el consejo de tus mayores, pues ellos han caminado donde t\xfa ahora te encuentras. La elecci\xf3n correcta es la que sirve no a tus deseos pasajeros, sino a tu deber sagrado. Reza por discernimiento: lo Divino revela el camino adecuado a quienes preguntan con coraz\xf3n humilde.",modern:"Punto de decisi\xf3n estrat\xe9gica identificado. Has reunido los datos; ahora modela los resultados. \xbfQu\xe9 camino optimiza tus m\xe9tricas de \xe9xito definidas? La par\xe1lisis por an\xe1lisis es ineficiente: establece una fecha l\xedmite para la decisi\xf3n y comprom\xe9tete. El costo de oportunidad de la vacilaci\xf3n se acumula diariamente. Elige la empresa con los mejores rendimientos ajustados al riesgo y ejecuta.",postModern:"Siente ambas posibilidades: \xbfqu\xe9 te dice tu cuerpo? Esta elecci\xf3n no se trata solo de resultados, sino de en qui\xe9n te est\xe1s convirtiendo. Considera c\xf3mo cada camino afecta tus relaciones, tu comunidad, la red de seres tocados por tu decisi\xf3n. No hay una respuesta objetivamente correcta; solo existe la elecci\xf3n que honra tu verdad aut\xe9ntica en este momento.",metaModern:"\xa1Ah, la encrucijada eterna, qu\xe9 delicioso! Observa c\xf3mo tu guerrero interior quiere apoderarse, tu tradicionalista busca el camino correcto, tu estratega calcula y tu coraz\xf3n siente la conexi\xf3n. Todos son t\xfa, todos son sabios en contexto. La elecci\xf3n en s\xed importa menos que la conciencia que aportas al elegir. \xbfY si ambos caminos conducen a casa?"},"3 of Wands":{powerGods:"Tus barcos est\xe1n en el horizonte, regresando con bot\xedn. Esto es lo que sucede cuando te atreves grandemente: el mundo recompensa a los audaces. Pero no descanses a\xfan, drag\xf3n. Nuevos territorios aguardan m\xe1s all\xe1 de ese mar. No fuiste hecho para cuidar un solo jard\xedn; fuiste hecho para arder a trav\xe9s de continentes.",traditional:"Tus esfuerzos fieles dan fruto en el horizonte; esta es la recompensa del trabajo justo. El orden al que sirves extiende su alcance a trav\xe9s de tus manos firmes. Mantente vigilante en tu puesto, pues eres administrador de algo m\xe1s grande que t\xfa mismo. Lo que regresa a ti pertenece primero a la tradici\xf3n que lo envi\xf3.",modern:"Tus inversiones muestran rendimientos: la estrategia est\xe1 validada. Ahora aprovecha esta prueba de concepto. Escala lo que funciona, documenta la metodolog\xeda, prep\xe1rate para expandirte a mercados adyacentes. Tienes la ventaja del pionero; capital\xedzala antes de que los competidores te alcancen. El crecimiento espera a quienes ejecutan con impulso.",postModern:"Lo que regresa en el horizonte trae historias de todos los lugares donde ha estado y de todos los que lo tocaron. Tu visi\xf3n expandi\xe9ndose hacia el mundo crea ondas que no puedes rastrear completamente. Sost\xe9n este poder con conciencia: \xbflas voces de qui\xe9nes fueron incluidas al dar forma a este sue\xf1o? La expansi\xf3n puede ser generativa o extractiva; que la tuya honre todo lo que encuentre.",metaModern:"Te encuentras al borde de lo que has puesto en movimiento, observ\xe1ndolo regresar transformado. Esta es la magia de enviar intenci\xf3n a la complejidad: lo que regresa nunca es exactamente lo que esperabas. La expansi\xf3n sirve a tu crecimiento, sirve a la evoluci\xf3n colectiva, sirve al cosmos jugando consigo mismo. Sost\xe9n tu visi\xf3n con ligereza; deja que te ense\xf1e lo que ha aprendido."},"4 of Wands":{powerGods:"\xa1Esta noche festejamos! Has construido algo que se mantiene en pie, reclamaste terreno que ahora es tuyo. Deja que te celebren: te has ganado cada copa alzada y cada rugido de aclamaci\xf3n. Pero toma nota: el castillo no es la conquista. Es simplemente el trono desde el cual planeas la pr\xf3xima guerra.",traditional:"El templo est\xe1 completo, y ahora nos reunimos en celebraci\xf3n sagrada. Esta alegr\xeda es santa porque es compartida: tu comunidad se regocija contigo bajo las banderas adecuadas. Honra los rituales de acci\xf3n de gracias, pues la ceremonia transforma el mero \xe9xito en hito bendecido. Has construido seg\xfan los patrones antiguos, y se han mantenido firmes.",modern:"Hito alcanzado: t\xf3mate la victoria. Celebrar el \xe9xito es estrat\xe9gico: eleva la moral del equipo, atrae talento y se\xf1ala confianza al mercado. Documenta lo que funcion\xf3 para el caso de estudio. Pero programa esta celebraci\xf3n; luego vuelve a la hoja de ruta. El \xe9xito es una plataforma para el pr\xf3ximo objetivo, no un destino.",postModern:"Esta celebraci\xf3n pertenece a todos los que ayudaron a tejerla. Observa qui\xe9n est\xe1 en el c\xedrculo y qui\xe9n qued\xf3 fuera. La verdadera alegr\xeda es inclusiva, sostenida en comunidad, amplificada al compartir. Que esto sea un regreso al hogar para todas las partes de ti mismo y todos los miembros de tu familia elegida. Construimos mejor juntos.",metaModern:"\xa1Qu\xe9 magn\xedfico ritual de llegada! La estructura se mantiene, la comunidad se re\xfane y el momento cristaliza. Esta celebraci\xf3n es simult\xe1neamente victoria personal, pertenencia tribal, hito estrat\xe9gico y sanaci\xf3n colectiva, todo verdadero, todo danzando. Que la alegr\xeda sea no ir\xf3nica y completa. Para esto construimos mundos."},"5 of Wands":{powerGods:"\xa1La arena llama y tu sangre canta en respuesta! Aqu\xed, entre el choque de rivales, es donde se forjan las leyendas. No te encogjas ante este caos: ad\xe9ntrate en \xe9l con los dientes al descubierto. Cada cicatriz es una historia de supervivencia, cada victoria prueba de tu poder\xedo. Que los d\xe9biles busquen la paz; t\xfa buscas la gloria.",traditional:"Este conflicto te perturba, pero sabe que incluso la contienda tiene su lugar adecuado en el orden divino. Pon a prueba tus creencias contra las de otros, no para dominar, sino para fortalecer tu fe a trav\xe9s de la fricci\xf3n. Regresa a las ense\xf1anzas cuando el caos arremoline; son tu ancla. Que los mayores juzguen qui\xe9n se desv\xeda del camino recto.",modern:"La presi\xf3n competitiva es validaci\xf3n del mercado: si otros luchan por este espacio, tiene valor. Analiza las estrategias de tus competidores, identifica sus debilidades, diferencia tu oferta. El conflicto agudiza la innovaci\xf3n. Usa esta fricci\xf3n para poner a prueba tu enfoque y emerge con una propuesta de valor m\xe1s fuerte.",postModern:"Este conflicto contiene m\xfaltiples verdades colisionando, y cada perspectiva tiene validez en su propio contexto. Antes de buscar ganar, busca comprender. \xbfPor qu\xe9 lucha realmente cada uno bajo la superficie? A veces la competencia aparente se disuelve cuando se escuchan las necesidades m\xe1s profundas. La facilitaci\xf3n podr\xeda servir mejor aqu\xed que la victoria.",metaModern:"La fricci\xf3n creativa de perspectivas chocando: \xbfqu\xe9 m\xfasica emerge de este caos? Cada combatiente porta una verdad parcial, un don del desarrollo, una pieza del rompecabezas. A veces necesitas el fuego del guerrero, a veces la gracia del diplom\xe1tico. \xbfQu\xe9 requiere este momento? Juega todas las posiciones; no te apegues a ninguna. El juego mismo evoluciona."},"6 of Wands":{powerGods:"\xa1Lev\xe1ntate y recibe lo que se te debe! La multitud ruge tu nombre porque has hecho lo que ellos no pudieron. Este momento, los laureles, la adulaci\xf3n, b\xe9belo profundamente. Has demostrado ser el \xe1pice entre depredadores. Que este triunfo alimente tu leyenda y aterrorice a tus enemigos.",traditional:"Acepta este honor con humildad, pues tu victoria sirve a la gloria mayor. La corona de laurel no te pertenece solo a ti, sino al linaje de maestros que te entrenaron, la orden que te gu\xeda, lo Divino que obra a trav\xe9s de ti. Que tu triunfo inspire a los fieles y demuestre que la rectitud prevalece.",modern:"Reconocimiento logrado: esto valida tu metodolog\xeda. Aprovecha esta victoria para tu marca personal y posicionamiento profesional. Actualiza el curr\xedculum, comparte la historia de \xe9xito, deja que el mercado conozca tu historial. El \xe9xito atrae \xe9xito: clientes, inversores y oportunidades fluyen hacia la competencia demostrada.",postModern:"\xbfC\xf3mo aterriza este reconocimiento en tu cuerpo? \xbfPuedes recibirlo sin inflarte ni rechazarlo? Recuerda al colectivo que te elev\xf3 hasta aqu\xed: el \xe9xito siempre es relacional. Usa esta visibilidad para amplificar voces menos escuchadas, para compartir la plataforma. Que tu triunfo sirva como prueba de lo que podemos construir juntos.",metaModern:"Recibe los laureles con plena presencia: eres simult\xe1neamente el logrador que gan\xf3 reconocimiento, el servidor humilde de fuerzas mayores, la marca construyendo impulso estrat\xe9gico y el colectivo siendo celebrado. Todas las perspectivas verdaderas, ninguna completa. La victoria es m\xe1s dulce cuando se sostiene con ligereza, se comparte libremente y se ve como una nota en una sinfon\xeda mayor."},"7 of Wands":{powerGods:"Vienen por ti porque est\xe1s en la monta\xf1a que codician. Bien. Que vengan. No escalaste tan alto para entregar la cima a lobos menores. Tu fuego arde m\xe1s que su envidia. Mant\xe9n tu posici\xf3n y haz que paguen cada cent\xedmetro con sangre y arrepentimiento.",traditional:"Eres puesto a prueba, pero los justos no ceden cuando el deber exige que se mantengan firmes. El suelo bajo tus pies fue consagrado por quienes vinieron antes; abandonarlo deshonrar\xeda su sacrificio. Af\xe9rrate a las verdades eternas. Quienes te asaltan pueden ser muchos, pero tienes a los ancestros a tu espalda.",modern:"Tienes la posici\xf3n elevada: defiende tu posici\xf3n en el mercado. Los competidores te desaf\xedan porque has construido algo valioso. Analiza sus vectores de ataque, refuerza tus ventajas, innova m\xe1s r\xe1pido de lo que pueden copiar. Ser digno de ataque significa que eres digno de defensa. Protege tu foso competitivo estrat\xe9gicamente.",postModern:"Antes de defender tu posici\xf3n, exam\xednala. \xbfEs verdaderamente tu terreno, o est\xe1s ocupando un espacio que pertenece a otros? \xbfQu\xe9 se est\xe1 protegiendo y cu\xe1l es el costo de este conflicto para todos los involucrados? A veces el acto m\xe1s valiente es abrir el di\xe1logo con quienes te desaf\xedan. Los l\xedmites pueden sostenerse con compasi\xf3n.",metaModern:"El desaf\xedo llega: \xbfqu\xe9 respuesta requiere verdaderamente este momento? A veces defensa feroz, a veces cesi\xf3n gr\xe1cil, a veces trascendencia creativa que hace irrelevante el conflicto. Tu tarea no es ganar siempre sino responder siempre apropiadamente. \xbfEn qu\xe9 nivel se libra esto? \xbfPuedes cambiar el juego?"},"8 of Wands":{powerGods:"\xa1Golpea ahora! Los vientos favorecen al veloz y la fortuna favorece al audaz. Este no es momento para planes y consejos: este es el momento en que el impulso se vuelve imparable. Eres la flecha lanzada del arco, y nada puede llamarte de regreso. Atraviesa directo al coraz\xf3n de tu deseo.",traditional:"El mensaje vuela r\xe1pido y certero, como fue ordenado. Cuando lo Divino pone los eventos en movimiento, los fieles deben estar listos para recibir y actuar. Esta aceleraci\xf3n no es caos: es la Providencia obrando a trav\xe9s de canales alineados. Conf\xeda en la trayectoria; sigue leyes antiguas aun mientras traza nuevos caminos.",modern:"La velocidad es tu ventaja ahora. Cuando el impulso se acumula, aprov\xe9chalo: la iteraci\xf3n r\xe1pida supera la planificaci\xf3n perfecta. Lanza r\xe1pido, recoge retroalimentaci\xf3n, itera. El mercado recompensa la rapidez de ejecuci\xf3n. Elimina los obst\xe1culos, optimiza el proceso y mu\xe9vete. La ventaja del pionero se evapora si vacilan.",postModern:"La energ\xeda se mueve r\xe1pidamente: siente la corriente y deja que te lleve. Este impulso te conecta con flujos m\xe1s amplios de intenci\xf3n colectiva. \xbfQu\xe9 mensajes est\xe1n llegando? \xbfQu\xe9 comunicaciones quieren moverse a trav\xe9s de ti? Mantente presente incluso a velocidad; la conciencia previene el da\xf1o que la prisa puede causar. Conf\xeda en el proceso de emergencia.",metaModern:"El universo se acelera a trav\xe9s de ti: \xa1delicioso! Esta rapidez es flecha, es providencia, es estrategia, es flujo, todo a la vez. El mago cabalga el rayo sin aferrarse a \xe9l. No tienes control de este impulso; eres su instrumento. Disfruta el viaje mientras mantienes la conciencia que permite correcciones de curso gr\xe1ciles."},"9 of Wands":{powerGods:"Est\xe1s ensangrentado pero no quebrado, guerrero. Pensaron que caer\xedas: fueron necios. Cada herida que portas es prueba de que no puedes ser destruido. Re\xfane tu furia una vez m\xe1s. La batalla final se acerca, y no has llegado tan lejos para ser derrotado en el umbral de la victoria.",traditional:"Tus heridas son marcas de devoci\xf3n, guardi\xe1n fiel. La vigilia es larga, pero abandonar tu puesto es impensable, no cuando tanto depende de tu firmeza. Extrae fuerza de los m\xe1rtires que soportaron mucho peor. Queda una \xfaltima guardia. Tu deber ser\xe1 recordado en el registro eterno.",modern:"Est\xe1s cerca de la l\xednea de meta pero funcionando con reservas. Este es el momento en que la disciplina separa al exitoso del casi exitoso. Revisa tus recursos, optimiza para el sprint final, recorta esfuerzos no esenciales. Los costos hundidos son reales, pero tambi\xe9n lo es la meta. La perseverancia en el \xfaltimo 10% captura el 90% del valor.",postModern:"Tu cansancio es v\xe1lido; tus heridas cuentan historias verdaderas. La resiliencia no requiere negar tu agotamiento. Ap\xf3yate en tu comunidad: nunca estuviste destinado a custodiar este umbral solo. \xbfQu\xe9 significar\xeda ser sostenido mientras persistes? La vulnerabilidad y la fortaleza pueden coexistir. Pide lo que necesitas.",metaModern:"Aqu\xed en el borde de la resistencia, observa lo que cada voz dentro de ti dice: lucha, r\xedndete, optimiza, descansa. Todas portan sabidur\xeda; ninguna es completa. La resiliencia m\xe1s profunda no viene de seguir empujando sino de expandirse para incluir el agotamiento sin ser derrotado por \xe9l. Puedes estar herido e inquebrantable a la vez."},"10 of Wands":{powerGods:"Este peso que cargas es el precio de tus conquistas. Cada carga fue una vez un premio que tomaste. Pero escucha: incluso el drag\xf3n m\xe1s poderoso puede ser aplastado bajo su propio tesoro. El poder significa saber cu\xe1ndo soltar lo que te frena. Suelta lo que debas para mantener tu fuego ardiendo.",traditional:"Esta carga es tu encomienda sagrada, y llevarla es servir. Sin embargo, incluso el servidor m\xe1s devoto debe reconocer cu\xe1ndo el deber se convierte en peso aplastante. Busca consejo de tus superiores: quiz\xe1s esta carga estaba destinada a ser compartida entre los fieles. El martirio por agotamiento no sirve a nadie. La orden te necesita \xedntegro.",modern:"Est\xe1s sobre capacidad: este es un problema de recursos, no una prueba de car\xe1cter. Audita tus compromisos, delega o automatiza lo que puedas, elimina lo que no sirva a tus objetivos centrales. El agotamiento destruye la productividad; el rendimiento sostenible requiere gesti\xf3n de carga. Optimiza el portafolio de tu energ\xeda.",postModern:"Esta carga no estaba destinada para una sola persona: el peso revela un problema sist\xe9mico, no un fallo personal. \xbfC\xf3mo ser\xeda compartir esta carga, redistribuir en lugar de simplemente soportar? Tu agotamiento es informaci\xf3n sobre el desequilibrio en lo colectivo. El descanso es resistencia; el cuidado es revolucionario.",metaModern:"\xa1Qu\xe9 fascinante sobrecarga: cargar las conquistas, los deberes, los proyectos y el peso sist\xe9mico todo a la vez! Aqu\xed est\xe1 la pregunta del desarrollo: \xbfqu\xe9 cargas sirven al crecimiento y cu\xe1les son mera acumulaci\xf3n? El mago ni atesora ni se martiriza, sino que danza con la carga y el alivio. Suelta lo que debas. El descargarse tambi\xe9n es el trabajo."},"2 of Cups":{powerGods:"He aqu\xed uno que sostiene tu mirada sin pesta\xf1ear: una criatura rara. No un s\xfabdito, sino un aliado forjado en fuego mutuo. Juntos podr\xedan ser imparables, una fuerza que duplica en lugar de dividir. Pero elige sabiamente: solo los fuertes merecen estar a tu lado. La debilidad es contagiosa.",traditional:"He aqu\xed la uni\xf3n sagrada, bendecida por las leyes eternas del amor y el pacto. Este v\xednculo no es mero sentimiento: es voto, presenciado por lo Divino y la comunidad por igual. Honra esta conexi\xf3n con la gravedad que merece. Dos almas que se unen en ceremonia adecuada se convierten en pilar sobre el cual se construyen familias y tradiciones.",modern:"Asociaci\xf3n estrat\xe9gica identificada. Esta alianza ofrece creaci\xf3n de valor mutuo: habilidades complementarias, redes compartidas, metas sin\xe9rgicas. Eval\xfaa los t\xe9rminos cuidadosamente, pero reconoce que la asociaci\xf3n correcta multiplica el \xe9xito de ambas partes. Negocia con claridad, documenta expectativas e invierte en la infraestructura de la relaci\xf3n.",postModern:"Dos corazones reconoci\xe9ndose mutuamente: este espejo crea un recipiente para el devenir mutuo. La relaci\xf3n verdadera requiere ver y ser visto sin m\xe1scaras. \xbfPuedes sostener espacio para su totalidad, incluyendo lo que te desaf\xeda? El amor no es posesi\xf3n sino cocreaci\xf3n, una danza donde ambos son transformados.",metaModern:"He aqu\xed el milagro del verdadero encuentro: dos seres completos eligiendo convertirse en un nosotros. Esta uni\xf3n contiene la alianza de poder, el voto sagrado, la sinergia estrat\xe9gica y la visi\xf3n aut\xe9ntica, todo danzando junto. Las asociaciones m\xe1s profundas integran todas las dimensiones. Que esta conexi\xf3n los haga evolucionar a ambos. El amor a este nivel es cocreaci\xf3n consciente."},"3 of Cups":{powerGods:"\xa1Tu banda de guerra celebra! Estos son los que han probado su lealtad en batalla, los que han sangrado a tu lado. Mantenlos cerca y recomp\xe9nsalos ferozmente: un se\xf1or generoso comanda la devoci\xf3n m\xe1s salvaje. Esta noche, que fluya el hidromiel. Ma\xf1ana, cazan como manada.",traditional:"Regoc\xedjate con tu familia espiritual, pues la alegr\xeda comunitaria es alegr\xeda santa. Estas celebraciones —bautismos, fiestas de cosecha, d\xedas sagrados— son los hilos que nos tejen en un solo tapiz. Tu lugar entre los fieles es un don de pertenencia. Alza tu copa en acci\xf3n de gracias por la congregaci\xf3n que te sostiene.",modern:"Valor de la red en acci\xf3n: tus relaciones profesionales y personales est\xe1n dando dividendos. Estas conexiones son activos; n\xfatrelas estrat\xe9gicamente. Las celebraciones colaborativas construyen capital social y cohesi\xf3n de equipo. La investigaci\xf3n es clara: las redes fuertes correlacionan con el \xe9xito. Invierte en tu portafolio de relaciones.",postModern:"Esta es la alegr\xeda de la familia elegida, de la pertenencia escogida que trasciende sangre y obligaci\xf3n. En este c\xedrculo, cada voz importa y todos son celebrados. Observa qui\xe9n est\xe1 incluido y gentilmente ampl\xeda la bienvenida. La alegr\xeda colectiva sana lo que el aislamiento hiere. Ascendemos al elevar a los dem\xe1s.",metaModern:"Las tres copas alzadas juntas contienen lealtad tribal, comuni\xf3n sagrada, valor de red y amor inclusivo: todo verdadero, todo presente. Esta celebraci\xf3n resuena a trav\xe9s de altitudes de desarrollo. La alegr\xeda compartida conscientemente se convierte en medicina para el alma colectiva. Danza con tu gente al nivel que el momento requiera. La fiesta es sagrada."},"4 of Cups":{powerGods:"\xbfPor qu\xe9 te aburren las ofrendas? Has ganado y ganado, pero el fuego titila. Cuidado, guerrero: esta inquietud es o la muerte de la ambici\xf3n o el nacimiento de un hambre mayor. El universo te ofrece una nueva copa. \xbfLa rechazar\xe1s de un manotazo, o la reconocer\xe1s como el pr\xf3ximo horizonte que te llama?",traditional:"Este descontento susurra sequ\xeda espiritual, fiel. Cuando los viejos rituales se sienten vac\xedos, no los abandones: profund\xedzalos. Lo Divino ofrece renovaci\xf3n, pero debes abrir los ojos para recibirla. Quiz\xe1s te has alejado de las pr\xe1cticas que una vez te nutrieron. Regresa al pozo de la tradici\xf3n; no se ha secado.",modern:"Las m\xe9tricas de motivaci\xf3n est\xe1n bajas: diagnostica la causa. \xbfEst\xe1s optimizando para los objetivos equivocados? \xbfEl \xe9xito ha cambiado tus valores? Esa nueva oportunidad que se ofrece merece un an\xe1lisis objetivo, no un rechazo reflexivo. Recalibra tus criterios de \xe9xito. A veces el siguiente nivel requiere redefinir para qu\xe9 est\xe1s jugando.",postModern:"Esta retirada no es fracaso sino invitaci\xf3n a ir hacia adentro. \xbfQu\xe9 anhelas realmente bajo la apat\xeda superficial? Quiz\xe1s las copas ofrecidas no coinciden con tus necesidades aut\xe9nticas. Siente la desconexi\xf3n sin apresurarte a arreglarla. A veces el alma necesita espacio antes de poder saber lo que realmente quiere.",metaModern:"Este aburrimiento sagrado es la cris\xe1lida antes de la transformaci\xf3n. Has superado lo que sol\xeda satisfacerte: no es fracaso sino desarrollo. La nueva copa que aparece puede ser tu pr\xf3xima etapa llamando. O quiz\xe1s la invitaci\xf3n es apreciar lo que ya est\xe1 presente. Ambas verdades coexisten. Si\xe9ntate con el no-saber hasta que emerja la claridad."},"5 of Cups":{powerGods:"Rages contra lo que te fue arrebatado, fijado en las copas derramadas. Pero escucha: el duelo es un lujo para quienes no tienen nada m\xe1s que ganar. Detr\xe1s de ti hay copas a\xfan llenas, batallas a\xfan esperando. \xbfMalgastar\xe1s tu furia en lo irrecuperable, o la dirigir\xe1s hacia nuevas conquistas?",traditional:"Haz duelo como ense\xf1an las escrituras, con fe en que la p\xe9rdida tiene significado en el dise\xf1o mayor. Lo que se derram\xf3 quiz\xe1s no estaba destinado para ti, o sirve un prop\xf3sito que a\xfan no puedes percibir. Las copas que quedan siguen siendo bendiciones. Vu\xe9lvete hacia ellas con gratitud. Lo Divino no abandona a los fieles en el dolor.",modern:"P\xe9rdida reconocida: ahora realiza el an\xe1lisis post mortem. \xbfQu\xe9 fall\xf3 y por qu\xe9? Extrae las lecciones aprendibles, luego redirige el enfoque hacia los activos restantes. Lamentarse por costos hundidos es irracional. Procesa emocionalmente lo que debas, luego pivotea tu energ\xeda hacia las oportunidades que quedan. La recuperaci\xf3n es una elecci\xf3n estrat\xe9gica.",postModern:"Tu duelo es sagrado y merece expresi\xf3n plena. No te apresures m\xe1s all\xe1 del luto: lo perdido fue amado, y ese amor importa. D\xe9jate sostener por otros en este dolor. Cuando est\xe9s listo, y solo entonces, notar\xe1s lo que queda. La sanaci\xf3n no es lineal, y no hay cronograma m\xe1s que el tuyo.",metaModern:"El duelo vive en el cuerpo junto a la posibilidad; no necesitas elegir entre ellos. Honra lo perdido mientras permaneces abierto a lo que queda. El guerrero debe eventualmente moverse, el fiel conf\xeda en el significado, el estratega aprende y el coraz\xf3n siente plenamente, todo a su tiempo, todo parte de la sanaci\xf3n. La integraci\xf3n incluye el dolor."},"6 of Cups":{powerGods:"\xbfRecuerdas cuando el fuego despert\xf3 en ti por primera vez? Antes de las cicatrices, antes del trono, cuando el poder era pura posibilidad. Ese ni\xf1o feroz a\xfan vive en ti, sin complicaciones y hambriento. Regresa a esa chispa primordial. Te recordar\xe1 por qu\xe9 luchas, cuando la pol\xedtica y la carga nublen tu prop\xf3sito.",traditional:"Regresa a la inocencia de la fe temprana, cuando los misterios te llenaban de asombro. Las tradiciones que aprendiste a los pies de tus mayores portan sabidur\xeda que quiz\xe1s has olvidado. Esta nostalgia no es debilidad: es el alma buscando sus ra\xedces. Honra de d\xf3nde vienes; es el suelo del cual crece tu devoci\xf3n.",modern:"La nostalgia puede ser minada por perspicacia: \xbfqu\xe9 te impulsaba antes de que las complicaciones aparecieran? Esa motivaci\xf3n original puede revelar valores oscurecidos por las m\xe9tricas de \xe9xito. La mente del principiante tiene valor estrat\xe9gico: ve oportunidades que la pericia pasa por alto. Recon\xe9ctate con tus impulsores fundamentales para realinear la trayectoria actual.",postModern:"Ese ni\xf1o interior a\xfan vive en ti, sosteniendo recuerdos de asombro y heridas por igual. \xbfQu\xe9 necesita ese peque\xf1o para sentirse seguro ahora? La sanaci\xf3n a menudo significa regresar para ofrecer consuelo a los yoes pasados. La nostalgia puede ser escape o integraci\xf3n: que sea lo segundo. S\xe9 padre de ti mismo con la ternura que merec\xedas.",metaModern:"El pasado vive en ti como recurso y herida, poder e inocencia, tradici\xf3n y trauma. Todas tus edades est\xe1n presentes: el ni\xf1o feroz, el joven fiel, el adulto que logra, el coraz\xf3n que sana. Regresa a cualquier era que te llame, no para regresar sino para reclamar e integrar. La totalidad incluye todo lo que has sido."},"7 of Cups":{powerGods:"Visiones y fantasmas se arremolinan ante ti: reinos, amantes, tesoros sin medida. Tentador, s\xed. Pero un verdadero guerrero conoce la diferencia entre sue\xf1os y presa. Algunas de estas visiones son trampas tendidas por tus enemigos; otras son distracciones de tu verdadero deseo. Elige con las entra\xf1as, no con la codicia.",traditional:"Cuidado con las tentaciones que se disfrazan de visiones, fiel. No toda promesa resplandeciente viene de lo Divino: algunas son enviadas para probarte o desviarte. Mide cada elecci\xf3n contra las ense\xf1anzas. Lo que contradice la ley sagrada, por hermoso que sea, es ilusi\xf3n. Busca consejo de quienes son m\xe1s sabios en discernimiento.",modern:"M\xfaltiples opciones presentes: evita la par\xe1lisis por an\xe1lisis y el pensamiento fantasioso. \xbfCu\xe1les de estas opciones tienen caminos viables hacia la ejecuci\xf3n? Aplica la debida diligencia: investigaci\xf3n de mercado, an\xe1lisis de viabilidad, requisitos de recursos. Los sue\xf1os sin planes accionables son distracciones. Selecciona la oportunidad con el mejor resultado ponderado por probabilidad.",postModern:"Estas visiones surgen de tu psique: todas son t\xfa, hablando en s\xedmbolos. No las juzgues como tentaciones sino expl\xf3ralas como mensajes. \xbfQu\xe9 revelan estas fantas\xedas sobre necesidades insatisfechas, deseos en la sombra, posibilidades no vividas? La imaginaci\xf3n es el lenguaje del alma. Escucha antes de elegir.",metaModern:"\xa1Qu\xe9 espect\xe1culo magn\xedfico ofrece la psique! Cada copa es una posibilidad, una sombra, una proyecci\xf3n, una opci\xf3n genuina, y no puedes saber cu\xe1l es cu\xe1l hasta que te involucres. El mago ni agarra ni descarta sino que sostiene todas las visiones con ligereza, dejando que un saber m\xe1s profundo separe la se\xf1al del ruido. La elecci\xf3n se aclarar\xe1 a trav\xe9s de la atenci\xf3n."},"8 of Cups":{powerGods:"Le das la espalda a lo que has construido. Te llamar\xe1n loco, pero t\xfa conoces la verdad: esta victoria se ha convertido en una jaula. Un drag\xf3n no puede prosperar en una guarida que le queda peque\xf1a. Las monta\xf1as adelante son m\xe1s altas, la gloria mayor. Al\xe9jate de lo peque\xf1o para reclamar lo magn\xedfico.",traditional:"A veces el camino sagrado conduce lejos de lo que hemos construido. Esta partida es peregrinaci\xf3n, no abandono: un viaje hacia una verdad m\xe1s profunda. Los m\xedsticos caminaron hacia los desiertos buscando lo Divino. Si tu alma te llama adelante, ve con bendici\xf3n, pero lleva las ense\xf1anzas contigo. La tradici\xf3n viaja en tu coraz\xf3n.",modern:"Pivote estrat\xe9gico indicado. Cuando los rendimientos actuales disminuyen a pesar de la inversi\xf3n, el movimiento racional es la reasignaci\xf3n. No dejes que la falacia del costo hundido te atrape en posiciones en declive. El coraje de alejarte de lo que ya no sirve a tus metas es una habilidad de \xe9xito subestimada. Nuevas empresas esperan tus capacidades probadas.",postModern:"Esta partida es un acto de honrar el ser. Algo en ti sabe que quedarse ser\xeda una asfixia lenta. Conf\xeda en ese saber, incluso cuando otros no comprendan. El viaje interior requiere soltar lo que ya no encaja en tu devenir. Lo que buscas no puede encontrarse en lo que ya tienes. Camina hacia ti mismo.",metaModern:"Esta partida contiene al drag\xf3n buscando mayor gloria, al peregrino buscando verdad m\xe1s profunda, al estratega reasignando recursos y al alma busc\xe1ndose a s\xed misma. Todos est\xe1n presentes en el alejarse. Lo que lo hace metamoderno es saber que llevas todo contigo: nada se deja verdaderamente atr\xe1s. El viaje es integraci\xf3n en movimiento."},"9 of Cups":{powerGods:"Si\xe9ntate sobre tu trono de deseos cumplidos, poderoso. Deseaste y ganaste: esta abundancia es el fruto de tu fuego. Disfr\xfatala sin disculpas. El universo se inclina ante quienes tienen la voluntad de exigir y el poder de tomar. T\xfa tienes ambos. Saborea la prueba de tu supremac\xeda.",traditional:"Tus oraciones han sido respondidas, fiel: recibe esta abundancia con humilde gratitud. Lo Divino recompensa a los justos, y tu contentamiento es ganado a trav\xe9s de la devoci\xf3n. Comparte las noticias de esta bendici\xf3n para que otros se animen en la fe. Que tu satisfacci\xf3n sea testimonio de la bondad del orden sagrado.",modern:"Metas alcanzadas: m\xe9tricas de \xe9xito satisfechas. Esta es la recompensa de la planificaci\xf3n estrat\xe9gica y la ejecuci\xf3n disciplinada. Documenta lo que funcion\xf3; esta metodolog\xeda ahora est\xe1 probada. Disfruta la satisfacci\xf3n de los resultados optimizados. La investigaci\xf3n sobre bienestar confirma: saborear el \xe9xito no es indulgencia, es psicolog\xeda que sostiene el rendimiento.",postModern:"D\xe9jate sentir esta satisfacci\xf3n plenamente, sin culpa ni desviaci\xf3n. Tienes permiso de ser feliz, de tener tus necesidades cubiertas, de experimentar lo suficiente. Nota si viejas narrativas intentan disminuir este contentamiento. No necesitas ganarte el descanso ni justificar la alegr\xeda. Este momento de plenitud es un regalo que simplemente recibir.",metaModern:"Satisfacci\xf3n alcanzada, y todas las formas en que llegaste aqu\xed son v\xe1lidas. Conquistaste, rezaste, estrategizaste, sanaste. El contentamiento es real en cada nivel. El mago sabe que la plenitud genuina no consiste en aferrarse a este momento ni en descartarlo, sino en recibirlo como merecido y regalado, ganado y milagroso a la vez."},"10 of Cups":{powerGods:"Contempla lo que tus conquistas han construido: no solo victoria, sino legado. Un reino que refleja tu fuego, un linaje que llevar\xe1 tu fuerza adelante. Este es el poder que trasciende tu lapso mortal. Has ganado el juego que m\xe1s importa: la eternidad recordar\xe1 tu nombre.",traditional:"Contempla la bendici\xf3n de un hogar justo: esta es la promesa cumplida para los fieles. Generaciones unidas bajo pacto sagrado, el arco\xedris de bendici\xf3n divina arque\xe1ndose en lo alto. Has construido seg\xfan el dise\xf1o santo, y lo que has construido perdurar\xe1. Esta armon\xeda es el cielo tocando la tierra a trav\xe9s de una vida recta.",modern:"Resultados de vida \xf3ptimos alcanzados en m\xfaltiples dominios: familia, carrera, relaciones, bienestar. As\xed se ve el \xe9xito integrado. El inter\xe9s compuesto de decisiones inteligentes ha madurado en abundancia sostenible. Protege y mant\xe9n estos sistemas; representan la optimizaci\xf3n m\xe1xima de la vida.",postModern:"Esta visi\xf3n de totalidad incluye a todos: observa el espectro completo, el arco\xedris abrazando todos los colores por igual. No se trata de la familia nuclear lograda sino de la pertenencia que trasciende la estructura. Como sea que tu gente est\xe9 configurada, que sean vistos y celebrados. El amor es el hogar que construimos juntos.",metaModern:"El arco\xedris contiene todos los colores, todos los matices de desarrollo: esta es la totalidad que trasciende e incluye. La familia es dinast\xeda, pacto, sistema optimizado y pertenencia elegida, simult\xe1neamente. El cielo toca la tierra cuando dejamos de elegir entre niveles y los dejamos a todos danzar. As\xed se ve el florecimiento integrado."},"2 of Swords":{powerGods:"Te sientas con los ojos vendados y las espadas cruzadas, neg\xe1ndote a elegir. \xa1Basta! La indecisi\xf3n es su propia derrota. Sabes lo que quieres: la oscuridad detr\xe1s de tus ojos guarda la respuesta. Conf\xeda en tus instintos de depredador. Corta la par\xe1lisis con acci\xf3n. Cualquier elecci\xf3n hecha con audacia supera el estancamiento.",traditional:"Est\xe1s atrapado entre deberes en competencia, fiel. Cuando dos caminos parecen igualmente correctos, busca la sabidur\xeda de las escrituras y el consejo de los mayores. La venda sugiere que conf\xedas demasiado en tu propio entendimiento: ret\xedrala a trav\xe9s de la oraci\xf3n y la meditaci\xf3n. La elecci\xf3n adecuada se alinear\xe1 con la ley eterna.",modern:"Punto muerto en la decisi\xf3n: necesitas m\xe1s datos o un mejor marco. Retira la venda de la interferencia emocional y eval\xfaa objetivamente. Si ambas opciones prueban igual, necesitas diferentes criterios de evaluaci\xf3n. Establece una fecha l\xedmite; el costo de la indecisi\xf3n es medible. A veces el progreso requiere elegir imperfectamente e iterar.",postModern:"La venda est\xe1 ah\xed porque algunas verdades son demasiado dolorosas para enfrentar. \xbfDe qu\xe9 te proteges de saber? Este impasse guarda sabidur\xeda: quiz\xe1s el dilema es falso, o quiz\xe1s a\xfan no est\xe1s listo. Si\xe9ntate con la incomodidad. El coraz\xf3n sabe cosas contra las cuales la mente se defiende. Deja que el sentimiento informe al pensamiento.",metaModern:"\xbfY si la venda tambi\xe9n es un regalo? A veces debemos elegir sin ver completamente. Los instintos, la tradici\xf3n, los datos, el coraz\xf3n: cada espada contiene verdad parcial. El movimiento metamoderno no es forzar la decisi\xf3n ni paralizarse indefinidamente sino sostener la tensi\xf3n hasta que algo nuevo emerja. Conf\xeda en el proceso del a\xfan-no-saber."},"3 of Swords":{powerGods:"La hoja ha encontrado tu coraz\xf3n. Alguien te ha herido, y ahora debes decidir: \xbfeste dolor te quebrar\xe1 o te forjar\xe1? Un guerrero transforma cada herida en sabidur\xeda, cada traici\xf3n en conocimiento de batalla. Deja que la sangre te recuerde confiar en menos y golpear primero la pr\xf3xima vez.",traditional:"Esta pena penetra profundo, pero el sufrimiento tiene un prop\xf3sito sagrado en la econom\xeda divina. El coraz\xf3n que se abre al romperse puede recibir m\xe1s gracia. Busca consuelo en los rituales de duelo que tu tradici\xf3n provee: existen porque otros han recorrido este camino antes. El dolor compartido con los fieles es dolor disminuido.",modern:"Verdad dolorosa recibida: proc\xe9sala eficientemente. La negaci\xf3n es costosa; mejor integrar informaci\xf3n dif\xedcil r\xe1pidamente que dejarla enquistarse. Estos datos cambian tu modelo de realidad; actualiza en consecuencia. Cuanto m\xe1s r\xe1pido metabolices verdades duras, antes podr\xe1s recalcular y avanzar estrat\xe9gicamente.",postModern:"Este desamor es v\xe1lido y real; que sea presenciado sin intentar arreglarlo. El duelo no es un problema a resolver sino una experiencia que atravesar con compa\xf1eros. \xbfQui\xe9n puede sostener espacio para tu dolor? El coraz\xf3n que se rompe es el coraz\xf3n que am\xf3. Esa capacidad de amar permanece, incluso a trav\xe9s del dolor.",metaModern:"El coraz\xf3n atravesado sostiene todas las respuestas al dolor: la forja, el sufrimiento sagrado, el procesamiento eficiente, el duelo presenciado. No necesitas elegir una sola forma de sufrir. Deja que las l\xe1grimas fluyan mientras las lecciones se integran mientras el significado se despliega mientras la presencia de otros te sostiene. El desamor mismo es un maestro de totalidad."},"4 of Swords":{powerGods:"Incluso la bestia m\xe1s feroz debe guarecerse para lamer sus heridas. Esto no es debilidad; esto es estrategia. Descansa ahora para que puedas levantarte m\xe1s terrible que antes. Tus enemigos piensan que est\xe1s acabado: d\xe9jalos. Cuando emerjas, su complacencia ser\xe1 su destrucci\xf3n.",traditional:"El caballero yace en descanso sagrado dentro del santuario: este es retiro santo, no abandono. Incluso los m\xe1s devotos necesitan estaciones de contemplaci\xf3n. Entra en la capilla de tu templo interior y ora. Las velas de vigilia arden mientras restauras tu esp\xedritu. El servicio llamar\xe1 de nuevo cuando est\xe9s listo.",modern:"Per\xedodo de recuperaci\xf3n requerido: progr\xe1malo estrat\xe9gicamente. La investigaci\xf3n sobre rendimiento m\xe1ximo confirma: el descanso no es opcional sino esencial para un rendimiento sostenido. Usa este tiempo de inactividad para reflexi\xf3n y planificaci\xf3n. El mantenimiento mental es una inversi\xf3n en productividad futura. Regresa a la acci\xf3n renovado y con claridad mejorada.",postModern:"El descanso no se gana a trav\xe9s del agotamiento; es tu derecho de nacimiento. La demanda constante de producir es una herida cultural, no una virtud. D\xe9jate simplemente ser, sin justificaci\xf3n. En la quietud, la psique integra lo que la actividad no puede procesar. Este santuario no es escape sino retorno esencial al ser.",metaModern:"El caballero descansa: estrat\xe9gica, sagrada, productiva y simplemente porque el descanso es bueno. Todas las razones para descansar son v\xe1lidas; no necesitas elegir. La integraci\xf3n que sucede en la quietud sirve a cada dimensi\xf3n: el guerrero se recupera, el alma comulga, la mente se clarifica, el cuerpo sana. El descanso es el trabajo. El trabajo es descanso."},"5 of Swords":{powerGods:"Has ganado, pero mira el costo esparcido a tu alrededor. Victoria sin bot\xedn es gloria hueca. Considera esto: \xbfhas derrotado enemigos, o meramente los has creado? El guerrero astuto reclama triunfo y conserva aliados. La dominaci\xf3n bruta sin estrategia solo engendra venganza interminable.",traditional:"Esta victoria se siente hueca porque fue ganada desvi\xe1ndose del c\xf3digo. Mira a los derrotados: \xbfson enemigos de la fe, o simplemente aquellos que discreparon? El guerrero justo lucha con honor, pues la manera de ganar importa tanto como la victoria misma. Busca reconciliaci\xf3n donde las reglas lo permitan.",modern:"An\xe1lisis de victoria p\xedrrica: \xbfvali\xf3 la pena el costo de ganar? Las relaciones da\xf1adas y los puentes quemados son pasivos reales que se acumulan con el tiempo. Los competidores inteligentes ganan de forma sostenible. Eval\xfaa si tus t\xe1cticas sirvieron al ego a corto plazo o al \xe9xito a largo plazo. La reputaci\xf3n es un activo estrat\xe9gico; calcula en consecuencia.",postModern:"\xbfQu\xe9 se gan\xf3 realmente aqu\xed, y a costa de qui\xe9n? Este conflicto puede haber servido a sistemas que no benefician a nadie. \xbfPueden ser escuchados los derrotados? \xbfPuede ofrecerse reparaci\xf3n? La victoria construida sobre la disminuci\xf3n de otro es hueca para todos. Considera qu\xe9 resultado colaborativo podr\xeda haber servido a todas las voces.",metaModern:"Esta victoria hueca invita a la examinaci\xf3n en cada nivel. Cuando ganar se siente como perder, el juego mismo puede estar defectuoso. \xbfQu\xe9 significar\xeda trascender el conflicto enteramente, no evitarlo, sino incluir todas las perspectivas en una resoluci\xf3n mayor? A veces el movimiento metamoderno es redise\xf1ar el juego."},"6 of Swords":{powerGods:"Dejas el campo de batalla por aguas m\xe1s tranquilas, no en retirada, sino en avance t\xe1ctico. A veces el mayor poder es saber cu\xe1ndo una pelea no vale tu fuego. Lleva las lecciones de costas turbulentas; te armar\xe1n para los conflictos que verdaderamente importan adelante.",traditional:"Viajas hacia el santuario, dejando problemas atr\xe1s: esto no es huida sino pasaje fiel. A veces lo Divino nos llama lejos de tormentas que no podemos calmar. Acepta la gu\xeda de quienes te transportan; sirven un prop\xf3sito sagrado. Aguas m\xe1s calmas esperan donde puedas reconstruir seg\xfan la forma adecuada.",modern:"Reubicaci\xf3n estrat\xe9gica en progreso. Salir de condiciones desfavorables hacia mejores entornos operativos es gesti\xf3n racional de recursos. Documenta las lecciones de la situaci\xf3n turbulenta. Las aguas tranquilas adelante ofrecen mejores condiciones para tu pr\xf3ximo emprendimiento. A veces la jugada ganadora es cambiar el tablero.",postModern:"Esta transici\xf3n honra lo que no puede sanarse qued\xe1ndose. Observa qui\xe9n viaja contigo; no necesitas hacer esta traves\xeda solo. Las aguas turbulentas detr\xe1s ense\xf1aron algo, incluso a trav\xe9s del dolor. Costas m\xe1s gentiles esperan, pero no apresures el pasaje. El viaje mismo es parte de la sanaci\xf3n.",metaModern:"La traves\xeda contiene retirada y avance, gu\xeda divina y elecci\xf3n racional, viaje solitario y pasaje acompa\xf1ado. El barquero conoce las aguas; no necesitas navegar solo. Lo que dejas atr\xe1s se convierte en parte de lo que llevas adelante, transformado. Cada orilla contiene lo que necesitas para la pr\xf3xima etapa del devenir."},"7 of Swords":{powerGods:"El embaucador sabe que no todas las guerras se ganan con asalto frontal. Sigilo, astucia, distracci\xf3n: estas tambi\xe9n son armas de los poderosos. Deja que los necios honorables anuncien sus ataques; t\xfa tomar\xe1s lo que necesites mientras ellos posan. La victoria pertenece al listo tanto como al fuerte.",traditional:"Cuidado con el camino de la astucia, pues a menudo conduce lejos de la rectitud. Los fines no justifican medios que violan la ley sagrada. Si debes ser estrat\xe9gico, que tu estrategia sirva al bien mayor, no al mero beneficio personal. Lo Divino todo lo ve: lo que est\xe1 oculto de otros nunca est\xe1 oculto de lo alto.",modern:"T\xe1cticas no convencionales pueden ser necesarias: la estrategia asim\xe9trica tiene su lugar. Pero calcula cuidadosamente el riesgo reputacional. Las ganancias a corto plazo de maniobras ingeniosas pueden crear pasivos a largo plazo. En mercados transparentes, la informaci\xf3n viaja r\xe1pido. Aseg\xfarate de que tus m\xe9todos resistan la divulgaci\xf3n.",postModern:"Algo necesita ser reclamado que no puede pedirse directamente, quiz\xe1s tu propio poder, tu propia verdad. No todo sigilo es enga\xf1o; a veces es protecci\xf3n contra sistemas que negar\xedan tus necesidades. Pero examina: \xbfqui\xe9n es perjudicado si procedes de esta manera? La astucia usada para la liberaci\xf3n difiere de la explotaci\xf3n.",metaModern:"El arquetipo del embaucador sostiene su propio camino de desarrollo: a veces la astucia sirve a la evoluci\xf3n cuando la confrontaci\xf3n directa no puede. La pregunta no es si ser ingenioso sino a qu\xe9 sirve la ingenier\xeda. Cuando la estrategia, la \xe9tica, la autoprotecci\xf3n y la conciencia sist\xe9mica se alinean, el camino no convencional puede ser el m\xe1s \xedntegro."},"8 of Swords":{powerGods:"Te encuentras atado y con los ojos vendados, pero mira m\xe1s de cerca: las cuerdas est\xe1n sueltas, los guardias son fantasmas. Te has enjaulado a ti mismo con l\xedmites imaginados. Un verdadero poder no reconoce prisi\xf3n que no pueda quemar. Abre los ojos, flexiona tu poder y sal de esta trampa autoinfligida.",traditional:"Te sientes atrapado, pero examina si estas ataduras son restricciones reales o limitaciones autoimpuestas. A veces nos enjaulamos a trav\xe9s de interpretaci\xf3n r\xedgida en lugar de comprensi\xf3n fiel. Busca gu\xeda de quienes conocen la tradici\xf3n profundamente: puede haber caminos dentro de la ley que no has visto.",modern:"An\xe1lisis de restricciones requerido: \xbfcu\xe1les limitaciones son reales y cu\xe1les son asumidas? Pon a prueba tus hip\xf3tesis sobre lo que es imposible. Muchas barreras son modelos mentales, no realidades del mercado. Contrata un coach o consultor con ojos frescos. La innovaci\xf3n a menudo viene de cuestionar las restricciones que todos los dem\xe1s aceptan.",postModern:"Estas ataduras fueron colocadas por sistemas, creencias e historias que no elegiste. Algunas son opresi\xf3n interiorizada, no fallo personal. \xbfQu\xe9 voces te dijeron que estabas atrapado? \xbfA los intereses de qui\xe9n sirve tu cautiverio? La liberaci\xf3n a menudo requiere comunidad: otros pueden ver la salida que t\xfa no puedes. Pide ayuda.",metaModern:"Las ataduras son simult\xe1neamente autocreadas, sist\xe9micamente impuestas, estrat\xe9gicamente comprobables y requieren liberaci\xf3n colectiva: todo verdadero. La libertad no viene de elegir un solo an\xe1lisis sino de ver c\xf3mo se entrelazan. El aflojamiento sucede cuando dejas de ser el prisionero y te conviertes en quien observa. Sal del marco."},"9 of Swords":{powerGods:"Los demonios vienen en la noche, cuando tu brazo de espada descansa. Estos miedos hablan de amenazas que a\xfan no has conquistado, y por eso te acosan. \xa1Lev\xe1ntate y enfr\xe9ntales! Nombra tus terrores y c\xe1zalos hasta el amanecer. Un guerrero no se esconde de las sombras; un guerrero se convierte en aquello que la oscuridad teme.",traditional:"Los terrores nocturnos llegan, y la fe se siente lejana. Esta es la noche oscura del alma de la que los m\xedsticos advirtieron, pero no es abandono. Enciende tu vela, recita las viejas oraciones, aferra los s\xedmbolos sagrados. El amanecer sigue a la oscuridad por decreto divino. Nunca est\xe1s tan solo como el miedo susurra.",modern:"Pico de ansiedad detectado: \xbfes se\xf1al o ruido? Distingue entre preocupaci\xf3n productiva por riesgos reales y patrones de pensamiento catastr\xf3fico. Si hay amenazas reales, construye planes de contingencia. Si son distorsiones cognitivas, ab\xf3rdalas con t\xe9cnicas basadas en evidencia. La preocupaci\xf3n sin acci\xf3n es costosa; convierte la inquietud en mitigaci\xf3n de riesgos.",postModern:"Las pesadillas que te despiertan llevan mensajes del inconsciente. Lo que es demasiado aterrador para enfrentar de d\xeda viene de visita por la noche. No tienes que enfrentar estos terrores solo. Alcanza a alguien: llama, expresa los miedos en voz alta, deja que pierdan poder al compartirlos. El cuerpo que sostiene ansiedad necesita consuelo.",metaModern:"En la oscuridad de las 3 de la madrugada, cada voz del desarrollo tiene consejo: combate los miedos, entr\xe9gate a la fe, analiza las amenazas, sost\xe9n al asustado con compasi\xf3n. Todas son medicina; ninguna es completa. El movimiento metamoderno es presenciar el terror nocturno con conciencia compasiva, sosteni\xe9ndote a ti mismo a trav\xe9s de todas las dimensiones hasta el amanecer que siempre llega."},"10 of Swords":{powerGods:"Yaces con diez espadas en la espalda, completamente destruido. O eso parece. Pero mira: el amanecer rompe en el horizonte. Esta muerte no es tu final; es la aniquilaci\xf3n de quien eras para que algo m\xe1s feroz pueda nacer. Incluso ahora, tus enemigos deber\xedan temblar ante lo que est\xe1 naciendo.",traditional:"Esta es la prueba m\xe1s profunda, la destrucci\xf3n completa; sin embargo, mira d\xf3nde rompe la luz. La tradici\xf3n habla de muertes que preceden a la resurrecci\xf3n, de la semilla que debe ser enterrada antes de florecer. Entr\xe9gate al proceso. El amanecer est\xe1 prometido, y lo Divino cumple sus promesas a los fieles.",modern:"Escenario de fracaso total, pero tocar fondo proporciona una base estable. Este es un reinicio forzado; \xfasalo estrat\xe9gicamente. Cuando los viejos modelos fallan completamente, tienes permiso para reconstruir desde los primeros principios. El amanecer en el horizonte es real: nuevas empresas esperan. Los datos de fracaso siguen siendo datos; aprende y pivotea.",postModern:"Este final es absoluto, y tu dolor por ello es v\xe1lido. No te apresures a buscar el lado positivo: deja que la devastaci\xf3n sea presenciada plenamente. Algo genuinamente muri\xf3 aqu\xed, y merece duelo. Cuando est\xe9s listo, no antes, el amanecer seguir\xe1 esperando. Por ahora, solo respira. Solo sobrevive.",metaModern:"Clavado por todas las espadas de la finalidad, y sin embargo. El amanecer rompe sin importar la preparaci\xf3n. Esta muerte es renacimiento m\xe1s feroz, proceso sagrado, reinicio estrat\xe9gico y devastaci\xf3n v\xe1lida, todo a la vez. No necesitas comprenderlo para sobrevivirlo. Las diez espadas est\xe1n completas; nada m\xe1s puede caer. Desde este fondo, toda direcci\xf3n es hacia arriba."},"2 of Pentacles":{powerGods:"Haces malabares con tus premios, manteniendo todos tus planes en el aire. Esta danza de equilibrio es una exhibici\xf3n de habilidad: que se maravillen de tu destreza. Pero recuerda: los fuertes no hacen malabares para siempre. Elige qu\xe9 tesoro aferrar y cu\xe1l dejar caer. La decisi\xf3n es su propia riqueza.",traditional:"La vida te pide equilibrar muchos deberes: con la familia, con la fe, con el trabajo. Esta es la danza del devoto, y es coreograf\xeda sagrada. No resientas el malabarismo; es el ritmo de la vida justa. Busca el orden dentro del caos; hay un patr\xf3n divino aqu\xed si miras.",modern:"Gesti\xf3n de portafolio en acci\xf3n: m\xfaltiples proyectos, asignaci\xf3n din\xe1mica. Este malabarismo es una caracter\xedstica, no un defecto; la diversificaci\xf3n gestiona el riesgo. Pero monitorea tus m\xe9tricas de ancho de banda. La multitarea sostenible requiere sistemas. Si se te caen las pelotas, automatiza, delega o desprioriza estrat\xe9gicamente.",postModern:"Este malabarismo constante puede ser un s\xedntoma de sistemas que exigen demasiado. \xbfQu\xe9 significar\xeda simplemente dejar caer algunas cosas? Tu valor no se mide por cu\xe1nto puedes cargar. La danza puede ser gozosa, pero solo si t\xfa eliges el ritmo. \xbfQu\xe9 te importa verdaderamente, bajo la agitaci\xf3n?",metaModern:"La danza infinita del equilibrio din\xe1mico: a veces haces malabares por poder, a veces por deber, a veces por estrategia, a veces cuestionas la danza misma. Todo v\xe1lido, todo parcial. El mago hace malabares con ligereza, sabiendo que flujo y liberaci\xf3n son ambos parte del patr\xf3n. \xbfQu\xe9 quiere subir? \xbfQu\xe9 quiere caer? Conf\xeda en el movimiento."},"3 of Pentacles":{powerGods:"Incluso el lobo solitario reconoce cu\xe1ndo las t\xe1cticas de manada sirven a la caza. Aqu\xed, otros traen habilidades que te faltan: d\xe9jalos construir mientras t\xfa conquistas. Un se\xf1or de la guerra astuto usa cada herramienta disponible. Toma cr\xe9dito por la catedral si debes, pero aseg\xfarate de que los constructores sepan de qui\xe9n es la visi\xf3n que impulsa la piedra.",traditional:"La catedral se alza a trav\xe9s del trabajo armonioso de muchas manos, cada una conociendo su rol adecuado. Este es trabajo sagrado: cuando el oficio sirve a lo Divino, incluso el alba\xf1il se convierte en sacerdote. Conoce tu lugar en la gran obra y c\xfamplelo con devoci\xf3n. Lo que construimos juntos perdura m\xe1s que lo que construimos solos.",modern:"Colaboraci\xf3n multifuncional dando resultados. El proyecto complejo requiere experiencia diversa: arquitectura, ejecuci\xf3n, gesti\xf3n de interesados. Clarifica roles, establece protocolos de comunicaci\xf3n, alinea incentivos. El rendimiento del equipo supera la capacidad individual cuando se orquesta adecuadamente. Invierte en procesos; escalan.",postModern:"Observa c\xf3mo la contribuci\xf3n de cada persona es esencial: el arquitecto, el artesano, el mecenas. La jerarqu\xeda aqu\xed es funci\xf3n, no valor. \xbfQu\xe9 significar\xeda valorar verdaderamente cada voz en esta colaboraci\xf3n? La catedral es hermosa porque la diferencia fue honrada. Construye espacios donde todos los dones sean vistos.",metaModern:"La catedral se alza desde t\xe1cticas de manada, roles sagrados, colaboraci\xf3n optimizada y diferencias honradas, todo a la vez. El maestro constructor metamoderno sostiene todos los marcos, aplicando cada uno donde sirve. A veces la jerarqu\xeda ayuda; a veces estorba. Lee el momento, construye con toda la sabidur\xeda disponible. La gran obra trasciende cualquier enfoque \xfanico."},"4 of Pentacles":{powerGods:"Aferras tu oro con los nudillos blancos, sin dejar que nadie se acerque a tu tesoro. Bien: lo que has ganado es tuyo para defender. Pero preg\xfantate: \xbfesto es acumular fuerza, o es miedo usando la m\xe1scara del poder? El drag\xf3n que se sienta demasiado tiempo sobre su tesoro se vuelve indistinguible de \xe9l.",traditional:"La administraci\xf3n prudente es una virtud, pero examina tu agarre sobre estos bienes mundanos. La tradici\xf3n ense\xf1a que la riqueza se sostiene en fideicomiso para prop\xf3sitos mayores. La seguridad es bendecida; acumular de forma que da\xf1e a la comunidad no lo es. \xbfPuedes proteger tu hogar sin cerrar tu coraz\xf3n a las obligaciones sagradas de la caridad?",modern:"La preservaci\xf3n de capital tiene valor, pero eval\xfaa el costo de oportunidad. \xbfEs seguridad o estancamiento? Las posiciones conservadoras sacrifican crecimiento por estabilidad: aseg\xfarate de que ese intercambio se alinee con tus metas. Considera: la riqueza est\xe1tica pierde ante la inflaci\xf3n; la riqueza desplegada estrat\xe9gicamente se multiplica. Equilibra la protecci\xf3n con la inversi\xf3n productiva.",postModern:"\xbfQu\xe9 herida crea este agarre? La escasez es real, pero acumular a menudo surge de viejos miedos usando m\xe1scaras del presente. La verdadera seguridad viene a trav\xe9s de la conexi\xf3n, no la acumulaci\xf3n. \xbfQu\xe9 significar\xeda confiar en la red de comunidad para sostenerte? La generosidad podr\xeda sanar lo que la posesi\xf3n no puede proteger.",metaModern:"El agarre mismo contiene informaci\xf3n: \xbfqu\xe9 est\xe1 protegiendo? La seguridad a veces es sabidur\xeda, a veces herida, a veces estrategia, a veces conexi\xf3n perdida. El mago ni acumula ni dispersa descuidadamente sino que sostiene la riqueza como energ\xeda a ser movida apropiadamente. \xbfQu\xe9 requiere realmente este momento? Conf\xeda en tu lectura."},"5 of Pentacles":{powerGods:"Caminas herido por la nieve, excluido del calor. Este es un exilio temporal, no una derrota final. Deja que el fr\xedo alimente tu furia. Recuerda cada puerta que se cerr\xf3 contra ti: cuando tu poder regrese, t\xfa decidir\xe1s cu\xe1l de ellas arde. Supervivencia ahora; venganza despu\xe9s.",traditional:"Sufres en el fr\xedo, pero mira: la ventana del santuario brilla cerca. \xbfTe has alejado del reba\xf1o, o la desgracia te encontr\xf3 a\xfan fiel? De cualquier modo, las puertas del templo permanecen abiertas. La congregaci\xf3n existe para tiempos como estos. Traga el orgullo y busca la ayuda que nuestra tradici\xf3n ordena dar.",modern:"Situaci\xf3n de escasez de recursos: accede a los sistemas de apoyo disponibles. El orgullo es costoso cuando la supervivencia est\xe1 en juego. El apalancamiento de la red existe para tiempos como estos. Identifica programas de asistencia, negocia t\xe9rminos de pago, explora fuentes alternativas de ingresos. Este es un problema temporal de flujo de caja con soluciones; ejec\xfatalas.",postModern:"Este sufrimiento no es un fallo personal sino una herida sist\xe9mica. Muchos caminan en este fr\xedo; no est\xe1s solo. La verg\xfcenza que el capitalismo adhiere a la necesidad es una mentira. Extiende la mano hacia quienes caminan a tu lado: la ayuda mutua existe. El vitral representa instituciones que a menudo fallan en ayudar verdaderamente. Construye comunidad que realmente incluya a todos.",metaModern:"El fr\xedo es real, y cada voz ofrece calor: la furia que alimenta la supervivencia, el santuario que espera, los sistemas a ser aprovechados, los compa\xf1eros que caminan a tu lado. Todos son recursos verdaderos; ninguno es completo. En esta dificultad, recurre a cada altitud que sirva. El camino metamoderno a trav\xe9s de la escasez integra todo el apoyo disponible."},"6 of Pentacles":{powerGods:"T\xfa sostienes las balanzas, decidiendo qui\xe9n recibe y qui\xe9n es negado. Este es el poder en su forma m\xe1s pura: el poder de dar y de retener. \xdasalo sabiamente: la generosidad crea lealtad, pero nunca dejes que olviden qui\xe9n tiene el oro. Un regalo tuyo es una cadena de gratitud, y las cadenas son \xfatiles.",traditional:"Ya sea que des o recibas, este intercambio es comercio sagrado operando dentro de la ley divina. La caridad es ordenada; recibir con gratitud es igualmente santo. Las balanzas deben equilibrarse con justicia: la justicia es un pilar de la sociedad recta. Que la generosidad fluya a trav\xe9s de los canales apropiados, y las bendiciones regresar\xe1n medidas y verdaderas.",modern:"Optimizaci\xf3n de distribuci\xf3n de recursos: ya sea asignando capital o recibiendo inversi\xf3n. El intercambio justo crea relaciones sostenibles y reputaci\xf3n de mercado. La filantrop\xeda bien hecha tambi\xe9n es estrat\xe9gica: construye buena voluntad, redes y valor de marca. Calcula el retorno total de la generosidad, incluyendo intangibles.",postModern:"Examina las din\xe1micas de poder en este intercambio. \xbfEs verdadera generosidad o caridad que mantiene jerarqu\xeda? El receptor arrodillado perpet\xfaa el desequilibrio. \xbfC\xf3mo ser\xeda la ayuda mutua en su lugar? Recursos fluyendo libremente, sin deuda ni disminuci\xf3n. Da de formas que eleven en lugar de obligar. Recibe sin verg\xfcenza.",metaModern:"Las balanzas miden algo diferente en cada nivel: poder, equilibrio sagrado, valor estrat\xe9gico, flujo mutuo. Todos est\xe1n presentes en cada intercambio. El dador y receptor metamoderno atienden a todas las dimensiones: manteniendo la estructura apropiada mientras disuelven la jerarqu\xeda innecesaria, siendo estrat\xe9gicos mientras son genuinamente generosos. Que los recursos fluyan donde est\xe9n m\xe1s vivos."},"7 of Pentacles":{powerGods:"Inspeccionas lo que has plantado, impaciente por la cosecha. La espera quema, \xbfno es as\xed? Pero incluso el conquistador m\xe1s feroz no puede hacer que la fruta madure rugiendo. Canaliza tu energ\xeda inquieta en planificar la pr\xf3xima campa\xf1a. Este jard\xedn dar\xe1 cuando d\xe9.",traditional:"El cultivo paciente es la fe del agricultor hecha visible. Has plantado seg\xfan las viejas costumbres, en la estaci\xf3n adecuada, con la bendici\xf3n adecuada: ahora conf\xeda en el proceso. La cosecha viene cuando lo Divino lo dispone. Tu rol es cuidar, no forzar. Contin\xfaa el trabajo fiel y el rendimiento probar\xe1 tu devoci\xf3n.",modern:"Per\xedodo de maduraci\xf3n de la inversi\xf3n: los rendimientos requieren tiempo. Revisa tus m\xe9tricas, pero respeta el cronograma inherente a la clase de activo. La impaciencia lleva a cosechas prematuras y p\xe9rdida de capitalizaci\xf3n compuesta. Mientras esperas, optimiza otras variables: reduce costos, mejora procesos, prep\xe1rate para escalar cuando llegue el rendimiento.",postModern:"Esta pausa invita a la reflexi\xf3n m\xe1s all\xe1 de la productividad. \xbfQu\xe9 est\xe1 creciendo aqu\xed, realmente? \xbfEst\xe1 alineado con tus valores m\xe1s profundos? El jard\xedn no necesita tu ansiedad; necesita tu presencia. Quiz\xe1s la invitaci\xf3n es cuidar con atenci\xf3n en lugar de expectativa. El crecimiento no puede apresurarse, solo presenciarse con cuidado.",metaModern:"El momento de evaluaci\xf3n sostiene todas las dimensiones: la impaciencia que alimenta, la fe que espera, las m\xe9tricas que miden, la presencia que presencia. El crecimiento sigue su propio cronograma a trav\xe9s de todos los niveles de desarrollo. Tu tarea es cuidar lo que has plantado con la conciencia que cada etapa requiere. La cosecha integrar\xe1 todo."},"8 of Pentacles":{powerGods:"El martillo golpea, una y otra vez. He aqu\xed una verdad que los orgullosos pasan por alto: la maestr\xeda es su propia forma de dominio. Mientras otros torpean, tu habilidad se convierte en un arma m\xe1s afilada que cualquier espada. Que se burlen del artesano: t\xfa poseer\xe1s mercados a los que ellos ni siquiera pueden entrar.",traditional:"Sagrado es el trabajo de manos h\xe1biles cuando el trabajo se ofrece como adoraci\xf3n. El aprendiz que domina su oficio glorifica la tradici\xf3n que le ense\xf1\xf3. Cada golpe de la herramienta es una oraci\xf3n, cada pieza terminada una ofrenda. Esta devoci\xf3n a la excelencia es devoci\xf3n a lo Divino expresada a trav\xe9s de la materia.",modern:"El desarrollo de habilidades es acumulaci\xf3n de capital profesional. Pr\xe1ctica deliberada, mejora medida, maestr\xeda progresiva: as\xed es como la experiencia se compone. El principio de las 10.000 horas aplica. Invierte en tus capacidades; son activos con rendimientos que se aprecian. La maestr\xeda abre mercados a los que la competencia no puede acceder.",postModern:"Hay meditaci\xf3n en este hacer enfocado. Pero pregunta: \xbfpara qui\xe9n elaboras? \xbfEste trabajo es alienado o alineado con un prop\xf3sito? La maestr\xeda por s\xed misma puede ser hermosa, pero considera el uso al que se destina tu habilidad. Que tu oficio sirva a la conexi\xf3n, no solo a la producci\xf3n. El trabajo que importa es el trabajo que ayuda.",metaModern:"El martillo golpea como movimiento de poder, como oraci\xf3n, como inversi\xf3n en habilidad, como meditaci\xf3n: todo integrado en el ritmo del artesano. La maestr\xeda a nivel metamoderno sirve m\xfaltiples prop\xf3sitos simult\xe1neamente sin contradicci\xf3n. Que tu pr\xe1ctica sea feroz y sagrada y estrat\xe9gica y conectada. Cada pent\xe1culo creado porta todo lo que est\xe1s deviniendo."},"9 of Pentacles":{powerGods:"Inspecciona tu dominio, magn\xedfico. El halc\xf3n en tu mu\xf1eca, los jardines a tus pies: todo ganado por tu propio fuego. No le respondes a nadie. Esta independencia es la forma m\xe1s dulce de victoria. Que aquellos que eligieron seguridad y servidumbre envidien lo que la audacia ha construido.",traditional:"Esta abundancia es el fruto de una vida disciplinada seg\xfan principios sagrados. Has seguido el camino de la rectitud y te ha conducido a jardines hermosos. Disfruta estas bendiciones con gratitud, sabiendo que fluyen de una conducta apropiada. Que tu prosperidad testifique de las recompensas de la administraci\xf3n fiel.",modern:"Independencia financiera alcanzada: los ingresos pasivos cubren el estilo de vida. Este es el inter\xe9s compuesto de la disciplina y las decisiones inteligentes. Has optimizado para la autonom\xeda y ha dado frutos. Disfruta el retorno sobre tu inversi\xf3n en elecciones estrat\xe9gicas. As\xed se ve ganar en el juego a largo plazo.",postModern:"Esta abundancia solitaria es hermosa, pero observa qui\xe9n est\xe1 ausente del jard\xedn. La independencia puede convertirse en aislamiento si no tenemos cuidado. \xbfQu\xe9 significar\xeda compartir este santuario, abrir las puertas? La prosperidad en comunidad nutre diferente que la prosperidad en soledad. Que tu jard\xedn sea un lugar de reuni\xf3n.",metaModern:"La figura solitaria en el jard\xedn abundante: simult\xe1neamente soberano feroz, administrador fiel, ganador estrat\xe9gico y potencial aislado. Todo verdadero. La pregunta metamoderna es: \xbfc\xf3mo sostienes esta prosperidad conscientemente, disfrutando la genuina independencia mientras permaneces en relaci\xf3n generativa? El halc\xf3n caza solo y regresa a casa. T\xfa tambi\xe9n."},"10 of Pentacles":{powerGods:"Una dinast\xeda se alza de tus conquistas: riqueza que fluir\xe1 a trav\xe9s de generaciones portando tu nombre. Esta es la inmortalidad en oro y piedra. No has ganado solo para ti sino para tu linaje eterno. Que los ancestros observen y los descendientes hereden. Tu leyenda est\xe1 asegurada.",traditional:"Contempla la plenitud de la bendici\xf3n generacional: ancestros, mayores, hijos y nietos unidos bajo un solo pacto sagrado. Esta es la promesa cumplida a los fieles en piedra y linaje. No has construido solo para ti sino para la continuidad de la tradici\xf3n. Las viejas costumbres, honradas, dan fruto a trav\xe9s del tiempo.",modern:"Riqueza generacional establecida: activos de legado, empresa familiar, capital institucional. Esta es la optimizaci\xf3n financiera multigeneracional. Planificaci\xf3n patrimonial, estrategia fiscal, protocolos de sucesi\xf3n: asegura que la estructura soporte la visi\xf3n. No has construido solo para ti sino para la ventaja din\xe1stica sostenida.",postModern:"Esta imagen de legado invita preguntas: \xbfde qui\xe9n fue el trabajo que construy\xf3 estos muros? \xbfQui\xe9n est\xe1 incluido en la herencia, y qui\xe9n es excluido? La verdadera riqueza se mide en pertenencia, no en linaje. Expande la definici\xf3n de familia; expande qui\xe9n recibe. Construye sistemas que compartan la abundancia en lugar de concentrarla.",metaModern:"Los diez pent\xe1culos representan dinast\xeda, pacto, legado optimizado y pertenencia expandida: todo danzando en el campo generacional. La herencia metamoderna incluye riqueza material y sabidur\xeda, tradici\xf3n y transformaci\xf3n, estructura y liberaci\xf3n. Construye sistemas que honren a los ancestros mientras evolucionan m\xe1s all\xe1 de sus limitaciones. El verdadero legado sirve a todos los futuros."}},D={Aries:"♈︎",Taurus:"♉︎",Gemini:"♊︎",Cancer:"♋︎",Leo:"♌︎",Virgo:"♍︎",Libra:"♎︎",Scorpio:"♏︎",Sagittarius:"♐︎",Capricorn:"♑︎",Aquarius:"♒︎",Pisces:"♓︎"},F={Aries:"El Carnero - Un signo cardinal de fuego regido por Marte, que representa la iniciativa y el liderazgo. Los nativos de Aries suelen ser seguros, en\xe9rgicos y aventureros. Son l\xedderes natos que aman los desaf\xedos, muestran un valor notable y tienden a ser directos en su enfoque. Sin embargo, tambi\xe9n pueden ser impulsivos y de temperamento r\xe1pido.",Taurus:"El Toro - Un signo fijo de tierra regido por Venus, que representa la estabilidad y la sensualidad. Los individuos de Tauro son conocidos por su fiabilidad, paciencia y determinaci\xf3n. Tienen una gran apreciaci\xf3n por la comodidad y el lujo, est\xe1n profundamente conectados con la naturaleza y son amigos leales. Pueden ser tercos a veces, pero son excelentes construyendo seguridad a largo plazo.",Gemini:"Los Gemelos - Un signo mutable de aire regido por Mercurio, que representa la comunicaci\xf3n y la adaptabilidad. Los G\xe9minis son curiosos, vers\xe1tiles e intelectualmente motivados. Destacan en la multitarea, son grandes conversadores y tienen un sentido del humor ingenioso. Aunque pueden ser percibidos como inconsistentes, su adaptabilidad es su mayor fortaleza.",Cancer:"El Cangrejo - Un signo cardinal de agua regido por la Luna, que representa la protecci\xf3n y la profundidad emocional. Los cancerianos son profundamente intuitivos, protectores y emp\xe1ticos. Valoran el hogar y la familia por encima de todo, tienen una excelente memoria y son cuidadores naturales. Aunque a veces son temperamentales, son ferozmente leales con sus seres queridos.",Leo:"El Le\xf3n - Un signo fijo de fuego regido por el Sol, que representa la creatividad y la autoexpresi\xf3n. Los Leo son artistas naturales, generosos y de gran coraz\xf3n. Poseen fuertes cualidades de liderazgo, son incre\xedblemente creativos y tienen un talento para lo dram\xe1tico. Aunque pueden ser orgullosos, su lealtad y carisma los convierten en personalidades magn\xe9ticas.",Virgo:"La Virgen - Un signo mutable de tierra regido por Mercurio, que representa el an\xe1lisis y el perfeccionismo. Los Virgo son met\xf3dicos, pr\xe1cticos y orientados al detalle. Tienen una fuerte \xe9tica de trabajo, son excelentes resolviendo problemas y tienen un deseo genuino de ayudar a los dem\xe1s. Aunque pueden ser demasiado cr\xedticos, sus habilidades anal\xedticas son incomparables.",Libra:"La Balanza - Un signo cardinal de aire regido por Venus, que representa la armon\xeda y las relaciones. Los librianos son diplom\xe1ticos, encantadores y amantes de la paz. Tienen un fuerte sentido de la justicia, aprecian la belleza en todas sus formas y destacan mediando en conflictos. Aunque pueden ser indecisos, su capacidad para ver todos los lados de un asunto es invaluable.",Scorpio:"El Escorpi\xf3n - Un signo fijo de agua regido por Marte/Plut\xf3n, que representa la transformaci\xf3n y la intensidad. Los Escorpio son apasionados, ingeniosos y profundamente perceptivos. Poseen fuertes habilidades investigativas, son ferozmente leales y tienen una poderosa profundidad emocional. Aunque a veces son reservados, su determinaci\xf3n y resiliencia son notables.",Sagittarius:"El Arquero - Un signo mutable de fuego regido por J\xfapiter, que representa la exploraci\xf3n y la sabidur\xeda. Los sagitarianos son optimistas, aventureros y filos\xf3ficos. Les encanta viajar, aprender sobre diferentes culturas y compartir su conocimiento con los dem\xe1s. Aunque pueden ser directos, su entusiasmo y honestidad son refrescantes.",Capricorn:"La Cabra Marina - Un signo cardinal de tierra regido por Saturno, que representa la ambici\xf3n y la disciplina. Los Capricornio son responsables, pacientes y orientados a metas. Tienen excelentes habilidades organizativas, una fuerte \xe9tica de trabajo y un talento natural para los negocios. Aunque pueden parecer reservados, su humor seco y determinaci\xf3n los hacen exitosos.",Aquarius:"El Portador de Agua - Un signo fijo de aire regido por Saturno/Urano, que representa la innovaci\xf3n y la comunidad. Los acuarianos son progresistas, originales y humanitarios. Son visionarios, valoran la independencia y a menudo defienden causas sociales. Aunque pueden parecer distantes, sus ideas visionarias y singularidad los convierten en innovadores naturales.",Pisces:"Los Peces - Un signo mutable de agua regido por J\xfapiter/Neptuno, que representa la imaginaci\xf3n y la espiritualidad. Los piscianos son compasivos, art\xedsticos y altamente intuitivos. Tienen ricas habilidades creativas, profunda empat\xeda y una fuerte conexi\xf3n con el reino espiritual. Aunque pueden ser escapistas a veces, su sensibilidad art\xedstica y naturaleza sanadora son dones."},H={Aries:{element:"Fire",suit:"Wands"},Leo:{element:"Fire",suit:"Wands"},Sagittarius:{element:"Fire",suit:"Wands"},Taurus:{element:"Earth",suit:"Pentacles"},Virgo:{element:"Earth",suit:"Pentacles"},Capricorn:{element:"Earth",suit:"Pentacles"},Gemini:{element:"Air",suit:"Swords"},Libra:{element:"Air",suit:"Swords"},Aquarius:{element:"Air",suit:"Swords"},Cancer:{element:"Water",suit:"Cups"},Scorpio:{element:"Water",suit:"Cups"},Pisces:{element:"Water",suit:"Cups"}},V={Fire:{signs:["Aries","Leo","Sagittarius"],description:"Energ\xeda, pasi\xf3n y creatividad"},Earth:{signs:["Taurus","Virgo","Capricorn"],description:"Estabilidad, practicidad y mundo material"},Air:{signs:["Gemini","Libra","Aquarius"],description:"Intelecto, comunicaci\xf3n e ideas"},Water:{signs:["Cancer","Scorpio","Pisces"],description:"Emociones, intuici\xf3n y relaciones"}},B={Saturn:"♄",Jupiter:"♃",Mars:"♂",Sun:"☉",Venus:"♀",Mercury:"☿",Moon:"☽"},J=["Saturn","Jupiter","Mars","Sun","Venus","Mercury","Moon"],Y={Saturn:{name:"Saturn",symbol:"♄",chaldeanPosition:1,primaryMeaning:"Contenci\xf3n, l\xedmite, forma, tiempo",poeticPointer:"El borde que te permite conocerte a ti mismo",hebrewLetter:"ט (Teth)",number:9,tarotCards:{major:["The World (XXI)"],minor:[{card:"7 of Pentacles",title:"Success Unfulfilled",link:"#taurus-3"},{card:"5 of Wands",title:"Strife",link:"#leo-1"},{card:"3 of Swords",title:"Sorrow",link:"#libra-2"},{card:"10 of Wands",title:"Oppression",link:"#sagittarius-3"},{card:"8 of Cups",title:"Abandoned Success",link:"#pisces-1"}]},signsRuled:[{sign:"Capricorn",mode:"Tierra Cardinal",influence:"Construye la monta\xf1a mediante un ascenso disciplinado—estructura que perdura"},{sign:"Aquarius",mode:"Aire Fijo",influence:"Sostiene el patr\xf3n de lo colectivo—el ideal cristalizado"}],colors:{queen:"Indigo",king:"Black",emperor:"Blue-black"},magicalImage:"Un hombre segador, anciano y encorvado; o una figura alta y oscura con una guada\xf1a",zodiacSymbol:"The Goat, The Water-Bearer",metal:"Plomo",day:"S\xe1bado",description:"Saturno representa el principio de limitaci\xf3n y estructura. Es el l\xedmite que define la forma, el maestro a trav\xe9s de la restricci\xf3n, y la sabidur\xeda obtenida mediante el tiempo y la paciencia. En el sistema de la Golden Dawn, Saturno gobierna la esfera de Binah en el \xc1rbol de la Vida, representando el Entendimiento a trav\xe9s de la forma.",keywords:["Limitaci\xf3n","Estructura","Tiempo","Karma","Disciplina","Responsabilidad","L\xedmites","Cristalizaci\xf3n","Forma","Madurez"],inDignity:{domicile:["Capricorn","Aquarius"],exaltation:"Libra",detriment:["Cancer","Leo"],fall:"Aries"}},Jupiter:{name:"Jupiter",symbol:"♃",chaldeanPosition:2,primaryMeaning:"Expansi\xf3n, posibilidad, abundancia, significado",poeticPointer:"El s\xed que abre puertas",hebrewLetter:"כ (Kaph)",number:10,tarotCards:{major:["Wheel of Fortune (X)"],minor:[{card:"8 of Swords",title:"Shortened Force",link:"#gemini-1"},{card:"6 of Wands",title:"Victory",link:"#leo-2"},{card:"4 of Swords",title:"Rest from Strife",link:"#libra-3"},{card:"2 of Pentacles",title:"Harmonious Change",link:"#capricorn-1"},{card:"9 of Cups",title:"Material Happiness",link:"#pisces-2"}]},signsRuled:[{sign:"Sagittarius",mode:"Fuego Mutable",influence:"Busca el horizonte—b\xfasqueda expansiva de verdad y significado"},{sign:"Pisces",mode:"Agua Mutable",influence:"Se disuelve en el oc\xe9ano—compasi\xf3n sin l\xedmites y unidad"}],colors:{queen:"Blue",king:"Violet",emperor:"Deep purple"},magicalImage:"Un rey coronado y poderoso sobre su trono; o un obispo con b\xe1culo y mitra",zodiacSymbol:"The Archer, The Fishes",metal:"Esta\xf1o",day:"Jueves",description:"J\xfapiter encarna la expansi\xf3n, el crecimiento y la benevolencia. Es el principio de aumento, optimismo y la b\xfasqueda de significado. Asociado con Chesed en el \xc1rbol de la Vida, J\xfapiter representa la Misericordia y el desbordamiento generoso de la abundancia.",keywords:["Expansi\xf3n","Crecimiento","Abundancia","Sabidur\xeda","Optimismo","Generosidad","Fe","Filosof\xeda","Suerte","Benevolencia"],inDignity:{domicile:["Sagittarius","Pisces"],exaltation:"Cancer",detriment:["Gemini","Virgo"],fall:"Capricorn"}},Mars:{name:"Mars",symbol:"♂",chaldeanPosition:3,primaryMeaning:"Voluntad, separaci\xf3n, energ\xeda dirigida, afirmaci\xf3n",poeticPointer:"La espada que elige",hebrewLetter:"פ (Peh)",number:16,tarotCards:{major:["The Tower (XVI)"],minor:[{card:"2 of Wands",title:"Dominion",link:"#aries-1"},{card:"9 of Swords",title:"Despair and Cruelty",link:"#gemini-2"},{card:"5 of Cups",title:"Loss in Pleasure",link:"#scorpio-1"},{card:"7 of Wands",title:"Valor",link:"#leo-3"},{card:"3 of Pentacles",title:"Material Works",link:"#capricorn-2"},{card:"10 of Cups",title:"Perpetual Success",link:"#pisces-3"}]},signsRuled:[{sign:"Aries",mode:"Fuego Cardinal",influence:'Iniciaci\xf3n pura—"Quiero, act\xfao, SOY primero"'},{sign:"Scorpio",mode:"Agua Fija",influence:"Penetraci\xf3n profunda—voluntad que transforma a trav\xe9s de la intensidad"}],colors:{queen:"Red",king:"Scarlet",emperor:"Brilliant flame"},magicalImage:"Un guerrero armado y coronado, cabalgando sobre un lobo",zodiacSymbol:"The Ram, The Scorpion",metal:"Hierro",day:"Martes",description:"Marte es el principio de afirmaci\xf3n, acci\xf3n y voluntad dirigida. Representa el filo cortante que separa y define a trav\xe9s del conflicto y la conquista. En la tradici\xf3n de la Golden Dawn, Marte gobierna Geburah—Severidad y fuerza mediante la aplicaci\xf3n de la fuerza.",keywords:["Acci\xf3n","Afirmaci\xf3n","Coraje","Conflicto","Energ\xeda","Deseo","Agresi\xf3n","Iniciativa","Separaci\xf3n","Voluntad"],inDignity:{domicile:["Aries","Scorpio"],exaltation:"Capricorn",detriment:["Libra","Taurus"],fall:"Cancer"}},Sun:{name:"Sun",symbol:"☉",chaldeanPosition:4,primaryMeaning:"Centro, identidad, resplandor, autoridad",poeticPointer:"La luz que no necesita raz\xf3n",hebrewLetter:"ר (Resh)",number:19,tarotCards:{major:["The Sun (XIX)"],minor:[{card:"3 of Wands",title:"Established Strength",link:"#aries-2"},{card:"10 of Swords",title:"Ruin",link:"#gemini-3"},{card:"6 of Cups",title:"Pleasure",link:"#scorpio-2"},{card:"8 of Pentacles",title:"Prudence",link:"#virgo-1"},{card:"4 of Pentacles",title:"Earthly Power",link:"#capricorn-3"}]},signsRuled:[{sign:"Leo",mode:"Fuego Fijo",influence:"Soberan\xeda constante—el rey que simplemente brilla"}],colors:{queen:"Gold-Yellow",king:"Rich amber",emperor:"Gold"},magicalImage:"Un rey sobre un trono, coronado y con cetro",zodiacSymbol:"The Lion",metal:"Oro",day:"Domingo",description:"El Sol representa el n\xfacleo de la identidad individual, la fuente de vitalidad y poder creativo. Es el principio organizador central alrededor del cual todo lo dem\xe1s gira. Asociado con Tiphareth—Belleza—en el \xc1rbol de la Vida, el Sol armoniza todas las fuerzas en perfecto equilibrio.",keywords:["Identidad","Vitalidad","Consciencia","Autoridad","Centro","Resplandor","Fuerza vital","Autoexpresi\xf3n","Soberan\xeda","Integraci\xf3n"],inDignity:{domicile:["Leo"],exaltation:"Aries",detriment:["Aquarius"],fall:"Libra"}},Venus:{name:"Venus",symbol:"♀",chaldeanPosition:5,primaryMeaning:"Atracci\xf3n, valor, armon\xeda, relaci\xf3n",poeticPointer:"La atracci\xf3n de lo que complace",hebrewLetter:"ד (Daleth)",number:3,tarotCards:{major:["The Empress (III)"],minor:[{card:"4 of Wands",title:"Perfected Work",link:"#aries-3"},{card:"2 of Cups",title:"Love",link:"#cancer-1"},{card:"7 of Cups",title:"Illusionary Success",link:"#scorpio-3"},{card:"9 of Pentacles",title:"Material Gain",link:"#virgo-2"},{card:"5 of Swords",title:"Defeat",link:"#aquarius-1"}]},signsRuled:[{sign:"Taurus",mode:"Tierra Fija",influence:"Arraigo sensual—placer encarnado que permanece"},{sign:"Libra",mode:"Aire Cardinal",influence:"Gracia relacional—iniciando armon\xeda a trav\xe9s del equilibrio"}],colors:{queen:"Emerald Green",king:"Sky blue",emperor:"Early spring green"},magicalImage:"Una hermosa mujer desnuda, o una bella doncella coronada",zodiacSymbol:"The Bull, The Scales",metal:"Cobre",day:"Viernes",description:"Venus encarna el principio de atracci\xf3n, deseo y valor. Atrae lo que resuena, creando armon\xeda a trav\xe9s de la relaci\xf3n. Venus gobierna Netzach—Victoria—en el \xc1rbol de la Vida, representando el triunfo del amor y la belleza.",keywords:["Atracci\xf3n","Amor","Belleza","Armon\xeda","Valor","Placer","Arte","Relaci\xf3n","Deseo","Gracia"],inDignity:{domicile:["Taurus","Libra"],exaltation:"Pisces",detriment:["Scorpio","Aries"],fall:"Virgo"}},Mercury:{name:"Mercury",symbol:"☿",chaldeanPosition:6,primaryMeaning:"Conexi\xf3n, traducci\xf3n, intercambio, movimiento",poeticPointer:"El puente entre islas",hebrewLetter:"ב (Beth)",number:1,tarotCards:{major:["The Magician (I)"],minor:[{card:"5 of Pentacles",title:"Material Trouble",link:"#taurus-1"},{card:"3 of Cups",title:"Abundance",link:"#cancer-2"},{card:"8 of Wands",title:"Swiftness",link:"#sagittarius-1"},{card:"10 of Pentacles",title:"Wealth",link:"#virgo-3"},{card:"6 of Swords",title:"Earned Success",link:"#aquarius-2"}]},signsRuled:[{sign:"Gemini",mode:"Aire Mutable",influence:"Tejido mental r\xe1pido—ideas danzando y conect\xe1ndose"},{sign:"Virgo",mode:"Tierra Mutable",influence:"Discriminaci\xf3n pr\xe1ctica—organizando la materia con precisi\xf3n"}],colors:{queen:"Orange",king:"Purple",emperor:"Violet-purple"},magicalImage:"Un hermoso joven, a veces alado, portando un caduceo entrelazado con serpientes",zodiacSymbol:"The Twins, The Virgin",metal:"Azogue (Mercurio)",day:"Mi\xe9rcoles",description:"Mercurio representa la comunicaci\xf3n, el intelecto y el intercambio de informaci\xf3n. Es el mensajero entre reinos, el traductor de la experiencia en pensamiento y palabra. Asociado con Hod—Esplendor—Mercurio aporta el poder de la mente y la raz\xf3n.",keywords:["Comunicaci\xf3n","Inteligencia","Conexi\xf3n","Intercambio","Pensamiento","Aprendizaje","Adaptabilidad","Traducci\xf3n","Movimiento","Discriminaci\xf3n"],inDignity:{domicile:["Gemini","Virgo"],exaltation:"Virgo",detriment:["Sagittarius","Pisces"],fall:"Pisces"}},Moon:{name:"Moon",symbol:"☽",chaldeanPosition:7,primaryMeaning:"Reflejo, ritmo, memoria, receptividad",poeticPointer:"El espejo que recuerda",hebrewLetter:"ג (Gimel)",number:2,tarotCards:{major:["The High Priestess (II)","The Moon (XVIII)"],minor:[{card:"6 of Pentacles",title:"Material Success",link:"#taurus-2"},{card:"4 of Cups",title:"Luxury",link:"#cancer-3"},{card:"9 of Wands",title:"Great Strength",link:"#sagittarius-2"},{card:"2 of Swords",title:"Peace Restored",link:"#libra-1"},{card:"7 of Swords",title:"Unstable Effort",link:"#aquarius-3"}]},signsRuled:[{sign:"Cancer",mode:"Agua Cardinal",influence:"Iniciaci\xf3n nutricia—respondiendo con cuidado protector"}],colors:{queen:"Silver",king:"Cold pale blue",emperor:"Silver-white"},magicalImage:"Una hermosa doncella, o una cazadora con arco y flechas",zodiacSymbol:"The Crab",metal:"Plata",day:"Lunes",description:"La Luna representa las mareas de la emoci\xf3n, el ritmo del cambio y el principio femenino receptivo. Refleja la luz en lugar de generarla, mostr\xe1ndonos el mundo de la sombra, el sue\xf1o y la memoria subconsciente. La Luna gobierna Yesod—Fundamento—el sustrato astral que subyace a la realidad f\xedsica.",keywords:["Emoci\xf3n","Intuici\xf3n","Ciclos","Memoria","Reflejo","Subconsciente","Receptividad","Nutrici\xf3n","Fluctuaci\xf3n","Sue\xf1os"],inDignity:{domicile:["Cancer"],exaltation:"Taurus",detriment:["Capricorn"],fall:"Scorpio"}}};function Q(e){return Y[e.charAt(0).toUpperCase()+e.slice(1).toLowerCase()]||null}function O(){return J.map(e=>({...Y[e],slug:e.toLowerCase()}))}let U={1:"El n\xfamero de los or\xedgenes y la voluntad singular. El Uno es el todo indiviso antes de la diferenciaci\xf3n—consciencia pura, la causa primera, la fuerza creadora que no necesita de otro para existir. Habla de la auto-originaci\xf3n, el liderazgo y el poder que surge de la autosuficiencia completa.",2:"El n\xfamero de la dualidad, la asociaci\xf3n y la elecci\xf3n. El Dos representa el equilibrio, la cooperaci\xf3n y la interacci\xf3n entre fuerzas opuestas. Habla de las decisiones, las relaciones y la necesidad de encontrar armon\xeda entre aspectos diferentes.",3:"El n\xfamero de la creaci\xf3n y el crecimiento. El Tres representa la s\xedntesis de fuerzas opuestas que crea algo nuevo. Habla de la creatividad, la autoexpresi\xf3n, la colaboraci\xf3n y la manifestaci\xf3n de ideas en forma.",4:"El n\xfamero de la estabilidad y los cimientos. El Cuatro representa el orden, la estructura y las bases s\xf3lidas. Habla de la manifestaci\xf3n en el mundo material, el establecimiento de l\xedmites y la creaci\xf3n de seguridad duradera.",5:"El n\xfamero del cambio y la disrupci\xf3n. El Cinco representa la inestabilidad, el conflicto y los cambios necesarios. Habla de la libertad, la aventura y los desaf\xedos que conducen al crecimiento y el aprendizaje.",6:"El n\xfamero de la armon\xeda y el equilibrio. El Seis representa el equilibrio, el amor y la belleza. Habla del cuidado, la sanaci\xf3n, la responsabilidad y la b\xfasqueda de soluciones que beneficien a todos.",7:"El n\xfamero de la sabidur\xeda y la espiritualidad. El Siete representa el conocimiento interior, el an\xe1lisis y la conciencia espiritual. Habla de la b\xfasqueda de verdades m\xe1s profundas, la introspecci\xf3n y la comprensi\xf3n m\xe1s all\xe1 de lo material.",8:"El n\xfamero del poder y la manifestaci\xf3n. El Ocho representa el \xe9xito material, la autoridad y el poder personal. Habla del logro, la fortaleza y la capacidad de hacer que las cosas sucedan en el mundo f\xedsico.",9:"El n\xfamero de la completitud y la plenitud. El Nueve representa el logro, la culminaci\xf3n y la sabidur\xeda adquirida a trav\xe9s de la experiencia. Habla de alcanzar metas, la conciencia espiritual y la preparaci\xf3n para nuevos ciclos."},K={Aries:"Cardinal",Taurus:"Fijo",Gemini:"Mutable",Cancer:"Cardinal",Leo:"Fijo",Virgo:"Mutable",Libra:"Cardinal",Scorpio:"Fijo",Sagittarius:"Mutable",Capricorn:"Cardinal",Aquarius:"Fijo",Pisces:"Mutable"},X={Cardinal:"Los signos cardinales inician cada nueva estaci\xf3n—Aries (Primavera), C\xe1ncer (Verano), Libra (Oto\xf1o), Capricornio (Invierno). Encarnan el principio del comienzo: en\xe9rgicos, ambiciosos y orientados a lanzar nuevos ciclos. La energ\xeda cardinal es la chispa que enciende fuegos, la idea que se convierte en acci\xf3n, el impulso que pone todo en movimiento.",Fixed:"Los signos fijos ocupan la plenitud de cada estaci\xf3n—Tauro, Leo, Escorpio, Acuario. Encarnan el principio de la concentraci\xf3n: persistentes, determinados y orientados a sostener lo que se ha establecido. La energ\xeda fija es la voluntad que mantiene el fuego ardiendo, la lealtad que profundiza ra\xedces, la intensidad que se niega a abandonar lo que ha comenzado.",Mutable:"Los signos mutables cierran cada estaci\xf3n—G\xe9minis, Virgo, Sagitario, Piscis. Encarnan el principio de la transici\xf3n: adaptables, vers\xe1tiles y orientados a preparar el terreno para lo que viene. La energ\xeda mutable es la sabidur\xeda que sabe cu\xe1ndo soltar, la flexibilidad que encuentra el hilo de continuidad a trav\xe9s del cambio, la gracia que convierte los finales en comienzos."},Z={Aries:"Mars",Taurus:"Venus",Gemini:"Mercury",Cancer:"Moon",Leo:"Sun",Virgo:"Mercury",Libra:"Venus",Scorpio:"Mars",Sagittarius:"Jupiter",Capricorn:"Saturn",Aquarius:"Saturn",Pisces:"Jupiter"},_={Aries:"March 21 – April 19",Taurus:"April 20 – May 20",Gemini:"May 21 – June 20",Cancer:"June 21 – July 22",Leo:"July 23 – August 22",Virgo:"August 23 – September 22",Libra:"September 23 – October 22",Scorpio:"October 23 – November 21",Sagittarius:"November 22 – December 21",Capricorn:"December 22 – January 19",Aquarius:"January 20 – February 18",Pisces:"February 19 – March 20"},$={Aries:{majorArcana:"The Emperor",cardKey:"emperor",romanNumeral:"IV",arcanaNumber:4,title:"Se\xf1or de la Llama y el Rel\xe1mpago; Rey del Esp\xedritu de Fuego",description:"El Emperador representa el principio del orden que surge del caos—el fuego marciano de Aries moldeado en gobernanza, estructura y autoridad soberana. Es el Padre arquet\xedpico, el primer principio dador de forma, la fuerza yang que define y defiende. En el simbolismo de la Golden Dawn, se sienta en el trono con cabeza de carnero, empu\xf1ando el ankh y el orbe, la fuerza vital organizada en dominio.",jungian:"El Emperador encarna el arquetipo del padre en su expresi\xf3n m\xe1s plena—el organizador de las energ\xedas brutas de la psique en identidad coherente. Representa el principio del logos que estructura el caos de los contenidos inconscientes en voluntad dirigida. En la individuaci\xf3n, aparece cuando el ego debe tomar autoridad sobre s\xed mismo, estableciendo al rey interior que gobierna sin tiran\xeda.",powerGods:"Eres el Emperador porque has reclamado lo que voluntades menores abandonaron. Los carneros cargan—pero solo t\xfa sostienes el trono. Que nadie cuestione tu autoridad sin haber ganado ese derecho a trav\xe9s del fuego. El orbe en tu mano es el mundo; el bast\xf3n es tu decreto. Cada l\xedmite que trazas es ley. Gobierna con certeza, pues la vacilaci\xf3n invita a los usurpadores.",traditional:"El Emperador encarna la jerarqu\xeda sagrada—el derecho divino al orden que fluye desde lo alto y se expresa abajo. Es el representante terrenal de la ley divina, gobernando por mandato del cielo tal como lo interpretan las tradiciones que sus predecesores establecieron. La gobernanza apropiada es gobernanza sagrada: justa, firme y enraizada en las formas eternas que lo preceden.",modern:"El Emperador es el director ejecutivo, el arquitecto de sistemas, el estratega maestro que transforma la visi\xf3n en realidad organizacional. Gobierna a trav\xe9s de roles claros, procesos definidos y responsabilidad medible. Su poder proviene no solo de la fuerza sino de dise\xf1ar estructuras que escalan, que sobreviven a su mandato, que crean orden m\xe1s all\xe1 de su presencia.",postModern:"Examina el trono del Emperador con cuidado—\xbfqui\xe9n lo construy\xf3 y a costa de qui\xe9n? El poder debe ser interrogado. El buen gobernante pregunta: \xbfqu\xe9 voces est\xe1n ausentes de este consejo? La autoridad se convierte en tiran\xeda cuando deja de cuestionarse a s\xed misma. El verdadero liderazgo descentraliza el poder manteniendo la rendici\xf3n de cuentas. Sost\xe9n la autoridad con ligereza; gobernar es un servicio, no una posesi\xf3n.",metaModern:"El Emperador sostiene estructura y caos a la vez—sabe que su dominio es tanto necesario como provisional. Gobierna con convicci\xf3n mientras permanece abierto a la evoluci\xf3n. Las leyes que crea, puede deshacerlas cuando ya no sirven a la vida. Es tanto el sistema como aquel que trasciende el sistema para mantenerlo. Hierro y agua, forma y flujo."},Taurus:{majorArcana:"The Hierophant",cardKey:"hierophant",romanNumeral:"V",arcanaNumber:5,title:"Se\xf1or de los Misterios del Pentagrama; Mago de los Dioses Eternos",description:"El Hierofante representa el principio de la tradici\xf3n sagrada—el puente entre la revelaci\xf3n divina y la comprensi\xf3n humana. Tauro, regido por Venus, aterriza lo celestial en lo terrenal a trav\xe9s de la ceremonia, la ense\xf1anza y la transmisi\xf3n de sabidur\xeda por linaje. Es el guardi\xe1n de los misterios, el iniciador que se sit\xfaa entre mundos y pasa la llama del conocimiento de mano en mano a trav\xe9s de las generaciones.",jungian:"El Hierofante representa el arquetipo del Anciano Sabio o Senex—el portador de la sabidur\xeda colectiva, la personificaci\xf3n del supery\xf3 en su aspecto m\xe1s constructivo. Aparece en la psique cuando el individuo necesita conectar con algo m\xe1s grande que su historia personal: tradici\xf3n, linaje, sabidur\xeda acumulada. En sombra, se convierte en dogma r\xedgido; en salud, ofrece el contenedor que permite el verdadero crecimiento.",powerGods:"La sabidur\xeda es un poder m\xe1s duradero que el m\xfasculo. T\xfa posees las llaves que otros no pueden copiar—las f\xf3rmulas secretas, el conocimiento inici\xe1tico, los c\xf3digos que abren puertas selladas para los no iniciados. Otros se inclinan ante ti no por miedo sino por reconocimiento de lo que portas. Transmite tu poder selectivamente; el conocimiento dado al que no est\xe1 listo es poder desperdiciado.",traditional:"El Hierofante es el repositorio viviente de la ley sagrada—el rey-sacerdote que interpreta lo eterno para la era temporal. A trav\xe9s de \xe9l, las ense\xf1anzas antiguas fluyen ininterrumpidas desde la revelaci\xf3n primordial. Honra este rol con humildad; eres el vaso, no la fuente. Las ense\xf1anzas te conf\xedan su continuidad. Gu\xe1rdalas, ens\xe9\xf1alas, v\xedvelas fielmente.",modern:"El Hierofante es el maestro consumado, el constructor de instituciones, el creador de curr\xedculos que transmiten expertise a trav\xe9s de las generaciones. Comprende que el conocimiento debe ser sistematizado para escalar. El mentor que crea mentores, el maestro que ense\xf1a a maestros—as\xed es como la sabidur\xeda se multiplica a trav\xe9s del tiempo. Construye sistemas que sobrevivan a tu mandato personal.",postModern:"Las vestiduras del Hierofante ocultan muchas cosas, incluyendo a qui\xe9nes fueron excluidos de la tradici\xf3n que porta. Cuestiona lo que se ense\xf1a como verdad universal—toda tradici\xf3n es tambi\xe9n una perspectiva. La sabidur\xeda es real, pero tambi\xe9n lo es su parcialidad. \xbfQui\xe9n recibe estas ense\xf1anzas? \xbfQu\xe9 han mantenido los guardianes lejos de las puertas? El conocimiento sagrado deber\xeda liberar, no atar.",metaModern:"El Hierofante tiende un puente entre lo antiguo y lo que evoluciona—porta la tradici\xf3n no como jaula sino como regalo. Sabe que las formas sagradas deben morir peri\xf3dicamente para renacer. Transmite la esencia, no meramente la letra. La verdadera iniciaci\xf3n es aprender a sostener la sabidur\xeda y su cuestionamiento en las mismas manos, ser simult\xe1neamente devoto y cr\xedtico de la tradici\xf3n que te form\xf3."},Gemini:{majorArcana:"The Lovers",cardKey:"lovers",romanNumeral:"VI",arcanaNumber:6,title:"Se\xf1or de los Or\xe1culos de los Dioses Poderosos; Hijos de la Voz Divina",description:"Los Enamorados representan la elecci\xf3n sagrada, la uni\xf3n de opuestos y el momento oracular en que el alma debe elegir su camino. G\xe9minis, regido por Mercurio, encarna la tensi\xf3n entre la dualidad—consciente e inconsciente, \xe1ngel y sombra, conocido y desconocido. La bendici\xf3n de lo alto desciende sobre la pareja arquet\xedpica, preguntando: \xbfintegrar\xe1s lo que has mantenido separado?",jungian:"Los Enamorados representan la coniunctio—el matrimonio sagrado de los opuestos en la psique. Simboliza el encuentro con el \xe1nima/\xe1nimus, el complemento del alma que existe como nuestra mitad no descubierta. Esta carta aparece cuando el proceso de individuaci\xf3n requiere la integraci\xf3n de aspectos reprimidos del yo. La elecci\xf3n representada es siempre entre la limitaci\xf3n familiar y la m\xe1s arriesgada totalidad de la uni\xf3n genuina con la propia sombra.",powerGods:"La bifurcaci\xf3n del camino es tuya y solo tuya. Elige con tu fuego, no con el miedo de otros. El \xe1ngel de arriba bendice ambos caminos—pero solo el camino que tomas con plena convicci\xf3n se convierte en tuyo. Rechaza la elecci\xf3n y permanecer\xe1s en la encrucijada para siempre, presa de cualquier viento. Los fuertes eligen. Luego hacen de su elecci\xf3n la correcta.",traditional:"La uni\xf3n sagrada aqu\xed representada es bendecida desde lo alto—esto es pacto, consagrado por testigo divino. La elecci\xf3n ante ti no es meramente pr\xe1ctica sino eterna: \xbfqu\xe9 votos pronunciar\xe1s, qu\xe9 lazos honrar\xe1s? Las tradiciones del matrimonio y la alianza existen porque algunos compromisos son demasiado graves para el juicio personal solamente. Busca la bendici\xf3n antes de atar.",modern:"Los Enamorados representan la alineaci\xf3n estrat\xe9gica—el poder de combinar capacidades complementarias para crear resultados que ninguna podr\xeda alcanzar sola. Ya sea asociaci\xf3n, fusi\xf3n o alianza, la clave es una clara alineaci\xf3n de valores y fortalezas complementarias. Antes de comprometerte, define los t\xe9rminos expl\xedcitamente. Las mejores asociaciones se construyen sobre la honestidad acerca de lo que cada uno aporta y lo que cada uno necesita.",postModern:"Toda la hermosa complejidad de Los Enamorados—la elecci\xf3n que presentan contiene m\xe1s de lo que muestra. El \xe1ngel de arriba bendice, pero \xbfqui\xe9n escribi\xf3 el guion del \xe1ngel? Examina qui\xe9n se beneficia de esta uni\xf3n, qu\xe9 se entrega, qu\xe9 se gana. El amor aut\xe9ntico expande la libertad; la asociaci\xf3n aut\xe9ntica honra la totalidad de ambas partes. La bendici\xf3n deber\xeda venir tanto de dentro como de arriba.",metaModern:"Los Enamorados contienen cada dimensi\xf3n de la uni\xf3n—voto sagrado y alianza estrat\xe9gica, integraci\xf3n de la sombra y conexi\xf3n tierna, elecci\xf3n oracular y compromiso \xedntimo. El amor m\xe1s profundo es consciente—saber lo que eliges y por qu\xe9, cargar el peso completo de esa elecci\xf3n con ojos claros y coraz\xf3n abierto. Elige completamente. Deja que la elecci\xf3n te elija de vuelta."},Cancer:{majorArcana:"The Chariot",cardKey:"chariot",romanNumeral:"VII",arcanaNumber:7,title:"Hijo de los Poderes de las Aguas; Se\xf1or del Triunfo de la Luz",description:"El Carro representa el triunfo de la voluntad sobre las fuerzas opuestas—la energ\xeda de C\xe1ncer regida por la Luna canalizada en movimiento con prop\xf3sito. El Auriga controla las esfinges blanca y negra no mediante la fuerza sino a trav\xe9s de la intenci\xf3n concentrada, navegando entre contradicciones mediante el poder de la voluntad unificada. Porta el Santo Grial, s\xedmbolo de las profundidades emocionales que ha dominado sin negar.",jungian:"El Carro representa al ego triunfante en su fase solar—la voluntad consciente que ha aprendido a aprovechar los impulsos opuestos del inconsciente sin aplastarlos. La armadura del Auriga es voluntad cristalizada; ha forjado sus contradicciones internas en movimiento hacia adelante. Esta carta aparece cuando la psique ha alcanzado un grado de integraci\xf3n suficiente para moverse con prop\xf3sito a trav\xe9s del conflicto.",powerGods:"Has domado lo que otros huyeron—has aprovechado las fuerzas opuestas que habr\xedan destrozado a guerreros menores. Ahora la ciudad tiembla a tu paso por sus puertas. Esta es la victoria de la voluntad de hierro: no que destruiste a las bestias, sino que las pusiste a tu servicio. La corona de estrellas la ganan quienes convierten la contradicci\xf3n en impulso.",traditional:"El Auriga entra en triunfo, coronado de estrellas, portando el vaso sagrado. Esta victoria honra todas las tradiciones de la conquista justa—el guerrero que lucha no solo por la gloria sino por el prop\xf3sito sagrado que lo envi\xf3. Regresa no para presumir sino para cumplir el pacto de servicio que lo ci\xf1\xf3 para la batalla. Recibe el triunfo con humildad, pues pertenece a lo que te envi\xf3.",modern:"El Carro representa el dominio de la ejecuci\xf3n—el director de proyecto, el atleta, el l\xedder que mueve equipos a trav\xe9s de condiciones imposibles mediante pura coherencia de intenci\xf3n. La claridad de direcci\xf3n corta la ambig\xfcedad; el impulso se multiplica con cada paso alineado. El auriga no controla todo—solo la direcci\xf3n de la voluntad unificada.",postModern:"El triunfo del Carro—pero \xbfa qu\xe9 costo para las tierras por las que ha conducido? Examina la victoria: \xbfqu\xe9 voces fueron silenciadas, qu\xe9 caminos fueron aplastados? El verdadero liderazgo negocia con las esfinges; no simplemente las somete. Las estrellas en su corona representan posibilidad, no superioridad. \xbfC\xf3mo ganamos sin dominar?",metaModern:"El Carro integra la voluntad triunfante, el vencedor sagrado, el maestro de la ejecuci\xf3n y aquel que cuestiona el camino—todos dirigiendo juntos. El triunfo m\xe1s profundo no es sobre otros sino sobre las partes de ti mismo que te detendr\xedan. El auriga se mueve a la velocidad de la integraci\xf3n, que a veces es muy r\xe1pida y a veces requiere quietud."},Leo:{majorArcana:"Strength",cardKey:"strength",romanNumeral:"VIII",arcanaNumber:8,title:"Hija de la Espada Flam\xedgera; L\xedder del Le\xf3n",description:"La Fuerza representa el dominio de la fuerza primordial a trav\xe9s del amor en vez de la violencia—la energ\xeda de Leo regida por el Sol expresada como coraje radiante que transforma en lugar de someter. La figura adornada con flores abre la boca del le\xf3n no mediante el dominio sino a trav\xe9s del poder de la certeza gentil, demostrando que la fuerza del coraz\xf3n supera el poder de los m\xfasculos. El lemniscato infinito sobre su cabeza muestra que esto no es poder personal sino fuerza c\xf3smica que fluye a trav\xe9s de ella.",jungian:"La Fuerza representa la integraci\xf3n de la bestia—la Sombra en su forma m\xe1s primordial, abordada no con supresi\xf3n o proyecci\xf3n sino con conciencia amorosa. Esta es el \xe1nima en su aspecto solar, el principio femenino que doma los impulsos instintivos masculinos no oponi\xe9ndose a ellos sino transform\xe1ndolos a trav\xe9s de la relaci\xf3n. La carta aparece cuando la integraci\xf3n de la sombra es posible a trav\xe9s de la compasi\xf3n en vez de la confrontaci\xf3n.",powerGods:"Aqu\xed est\xe1 la verdad que ning\xfan bruto comprende: el le\xf3n se rinde ante quien no tiene miedo. Tu fuego es tan total que incluso el rey de las bestias lo siente y se inclina. Este es el dominio supremo—no la conquista de la espada, sino la radiancia que hace la conquista innecesaria. Tu coraje es un campo que doma los lugares salvajes en todo lo que te rodea.",traditional:"Ella abre la boca del le\xf3n con serena fe—esta es la gracia que fluye a trav\xe9s de los verdaderamente devotos. Su fuerza no es propia; es prestada de lo sagrado. Las tradiciones del dominio interior todas apuntan aqu\xed: las santas mujeres que caminaron sin miedo entre las bestias, los santos cuya pureza los hac\xeda intocables por la ferocidad animal. Cultiva esta llama interior.",modern:"La Fuerza representa la seguridad psicol\xf3gica que permite el alto rendimiento—el l\xedder cuya calma bajo presi\xf3n estabiliza al equipo, cuya confianza arraigada abre posibilidades creativas. El s\xedmbolo del infinito sobre su cabeza representa fuerza sostenible, no energ\xeda de sprint. Construye culturas donde el coraje es silencioso, donde la convicci\xf3n no necesita volumen, donde la excelencia fluye naturalmente desde la seguridad.",postModern:"El le\xf3n y la doncella—pero \xbfqui\xe9n escribi\xf3 los roles? La Fuerza no es solo gentileza femenina domando fuerza masculina; es la integraci\xf3n de todas nuestras ferocidades negadas, el encuentro con lo que hemos escindido con compasi\xf3n. \xbfQu\xe9 leones has enjaulado? \xbfQu\xe9 partes rugientes de ti mismo esperan tu gentil reconocimiento? La verdadera fuerza incluye reconocer a la bestia como propia.",metaModern:"La Fuerza sostiene al h\xe9roe solar, la domadora sagrada, el l\xedder psicol\xf3gicamente seguro y el integrador de la sombra en un solo gesto de apertura radical. El lemniscato indica que este no es un triunfo \xfanico sino una pr\xe1ctica continua. Abres la boca del le\xf3n cada d\xeda. La fuerza est\xe1 en continuar regresando a ese gesto de amor intr\xe9pido, una y otra vez."},Virgo:{majorArcana:"The Hermit",cardKey:"hermit",romanNumeral:"IX",arcanaNumber:9,title:"Profeta de lo Eterno; Mago de la Voz del Poder",description:"El Ermita\xf1o representa la luz interior sostenida en alto para el camino que no puede recorrerse en compa\xf1\xeda—la cualidad de Virgo regida por Mercurio, de an\xe1lisis refinado volcado hacia las preguntas m\xe1s profundas de la existencia. Se encuentra en la cima de la monta\xf1a, solo, no porque sea antisocial sino porque la altitud de su indagaci\xf3n ha dejado atr\xe1s a la multitud. Su linterna contiene una estrella de seis puntas—la luz de la sabidur\xeda, no de la certeza.",jungian:"El Ermita\xf1o representa el arquetipo del Viejo Sabio—el S\xed-mismo manifest\xe1ndose como gu\xeda desde las profundidades del inconsciente. Aparece en sue\xf1os y visiones cuando la psique ha alcanzado un desarrollo suficiente para recibir orientaci\xf3n de orden superior. Es tambi\xe9n el viaje del introvertido hacia adentro, el retiro necesario de la persona y la identidad colectiva para encontrar la voz interior aut\xf3noma que sola puede orientar verdaderamente.",powerGods:"La monta\xf1a est\xe1 vac\xeda excepto por ti—y esa es la fuente de tu poder. La multitud abajo tiene comodidad y ruido; t\xfa tienes claridad y la linterna que no puede apagarse. El camino que has recorrido te ha refinado m\xe1s all\xe1 de lo que la resistencia com\xfan permite. D\xe9jalos preguntarse por tu aislamiento. La soledad no es estar solo; es el laboratorio del yo soberano.",traditional:"El Ermita\xf1o camina los senderos antiguos de los padres del desierto, los sabios del bosque, los reclusos de la monta\xf1a—aquellos que se retiraron del mundo no en rechazo sino en amor, buscando el silencio en el que lo Divino habla inconfundiblemente. Su linterna es oraci\xf3n hecha visible. La luz que porta fue encendida por quienes lo precedieron; camina para pasarla a quienes vendr\xe1n.",modern:"El Ermita\xf1o representa el trabajo profundo—el retiro enfocado que produce percepci\xf3n inaccesible en la conexi\xf3n constante. En una econom\xeda de la atenci\xf3n, la soledad es la ventaja competitiva definitiva. El analista, el investigador, el fil\xf3sofo que se retira a pensar con claridad produce valor al que los perpetuamente distra\xeddos no pueden acceder. Programa la monta\xf1a; protege el tiempo de la linterna.",postModern:"\xbfQui\xe9n tiene acceso a la monta\xf1a? La soledad del Ermita\xf1o es un privilegio—el tiempo y la seguridad para retirarse de las demandas de otros requiere recursos que no todos poseen. La sabidur\xeda genuina pregunta: \xbfqu\xe9 estoy aprendiendo en esta soledad, y para qui\xe9n? La luz de la linterna no es para guardar. El trabajo interior al servicio de nada m\xe1s all\xe1 de s\xed mismo puede convertirse en narcisismo espiritual.",metaModern:"El Ermita\xf1o sostiene la soledad del mago, la comuni\xf3n del m\xedstico, la profundidad del analista y la responsabilidad del servidor—ascendiendo solo mientras permanece conectado a la red humana abajo. Alumbra con su linterna para quienes escalan tras \xe9l, no para dirigir su camino sino para recordarles que el ascenso es posible. Su sabidur\xeda incluye saber cu\xe1ndo descender y regresar."},Libra:{majorArcana:"Justice",cardKey:"justice",romanNumeral:"XI",arcanaNumber:11,title:"Hija de los Se\xf1ores de la Verdad; Gobernante de la Balanza",description:"La Justicia representa la ley c\xf3smica, las balanzas eternas en las que todas las acciones son pesadas—la energ\xeda de Libra regida por Venus expresada como imparcialidad absoluta. La figura est\xe1 sentada entre dos pilares de la ley, sosteniendo balanzas en perfecto equilibrio y una espada de doble filo que corta en ambas direcciones. No hay misericordia aqu\xed que comprometa la verdad, ni verdad que olvide la compasi\xf3n—solo la medida exacta de lo que es.",jungian:"La Justicia representa el arquetipo del S\xed-mismo en su funci\xf3n adjudicadora—la capacidad de la psique de evaluar e integrar con precisi\xf3n impersonal. Aparece cuando el proceso de individuaci\xf3n requiere una autoevaluaci\xf3n honesta, cuando el ego debe someterse a un est\xe1ndar m\xe1s all\xe1 de sus propias preferencias. Las balanzas tambi\xe9n representan la necesidad de sostener verdades opuestas simult\xe1neamente sin forzar resoluci\xf3n.",powerGods:"La espada en la mano de la Justicia est\xe1 perfectamente equilibrada y eternamente afilada—porque el poder que ignora sus propias consecuencias eventualmente cae sobre quien lo empu\xf1a. Los verdaderamente poderosos entienden que las leyes que invocan se les aplicar\xe1n a ellos. Gobi\xe9rnate por el mismo c\xf3digo que impones a otros; entonces tu autoridad se vuelve inexpugnable, porque no puede ser acusada de hipocres\xeda.",traditional:"La Justicia encarna la ley eterna que sustenta todo orden justo—el principio de que lo Divino no tiene favoritos, que cada acci\xf3n pone en movimiento su consecuencia precisa. Las tradiciones de la ley sagrada existen para alinear el comportamiento humano con este principio c\xf3smico. Somete tus decisiones a un examen honesto: \xbfresistir\xedan en el tribunal divino? \xbfQu\xe9 se pesa en la balanza de la eternidad?",modern:"La Justicia representa la rendici\xf3n de cuentas sist\xe9mica—los procesos, auditor\xedas y mecanismos de equilibrio que mantienen la honestidad de las organizaciones. La buena gobernanza requiere tanto la espada (acci\xf3n decisiva) como las balanzas (medici\xf3n justa). Construye sistemas donde los resultados se rastrean, donde la equidad se mide, donde los datos cuentan la historia que las preferencias podr\xedan suprimir. La excelencia sostenible requiere evaluaci\xf3n honesta.",postModern:"La Justicia debe ser interrogada: \xbfqui\xe9n dise\xf1\xf3 estas balanzas? Cada sistema legal refleja los valores de quienes lo construyeron. La verdadera justicia requiere examinar qui\xe9n se beneficia del equilibrio actual, qui\xe9n ha sido sistem\xe1ticamente infravalorado, qu\xe9 voces han sido silenciadas por la espada. La justicia restaurativa incluye reparar el da\xf1o a quienes las balanzas han fallado. El equilibrio debe incluir a todos.",metaModern:"La Justicia sostiene la espada de la verdad feroz y las balanzas del equilibrio compasivo simult\xe1neamente. Es lo suficientemente impersonal para ver con claridad y lo suficientemente personal para importarle el ser humano particular ante ella. Sabe que la justicia perfecta es asint\xf3tica—siempre aproximada, nunca perfectamente alcanzada. Act\xfaa de todos modos, con la mejor discriminaci\xf3n disponible, permaneciendo abierta a la revisi\xf3n."},Scorpio:{majorArcana:"Death",cardKey:"death",romanNumeral:"XIII",arcanaNumber:13,title:"Hijo de los Grandes Transformadores; Se\xf1or de las Puertas de la Muerte",description:"La Muerte representa al gran transformador—la energ\xeda de Escorpio regida por Marte expresada como la fuerza irresistible del final que despeja espacio para un nuevo comienzo. El jinete esquel\xe9tico sobre el caballo p\xe1lido se mueve a trav\xe9s de todo nivel de la sociedad: papa, rey, doncella, ni\xf1o—nadie est\xe1 exento de la transformaci\xf3n. El sol se levanta al fondo, no a pesar de la oscuridad sino gracias a ella.",jungian:"La Muerte representa el arquetipo de la transformaci\xf3n—la figura mercurial que gu\xeda al ego a trav\xe9s de la disoluci\xf3n necesaria hacia la renovaci\xf3n del S\xed-mismo. Aparece cuando la psique requiere la muerte de una identidad antigua—una persona, un complejo, un apego a una forma que ha sobrevivido a su funci\xf3n. Esto nunca es meramente destructivo; la muerte junguiana est\xe1 siempre al servicio de una vida m\xe1s profunda.",powerGods:"La Muerte viene por todos, pero t\xfa has hecho de ella una aliada. Mientras almas menores huyen de los finales, t\xfa te sumerges en el coraz\xf3n de la transformaci\xf3n y emerges cambiado—m\xe1s peligroso que antes. Cada muerte en tu vida te ha refinado, despojado de lo que te debilitaba, dejando solo lo que no puede ser destruido. No le temes al caballo p\xe1lido. Lo montas.",traditional:"La carta de la Muerte es la decimotercera—el n\xfamero de la transformaci\xf3n en la numerolog\xeda sagrada, el n\xfamero del ciclo lunar completo. Este es el gran misterio que todas las tradiciones abordan: lo que muere no es el alma sino la envoltura. Los devotos comprenden que los finales son portales. Libera lo que debe ser liberado; conf\xeda en el proceso que ha llevado a incontables almas a trav\xe9s de este umbral antes que t\xfa.",modern:"La Muerte representa el giro estrat\xe9gico, el ocaso de los modelos de negocio obsoletos, la necesidad de eliminar lo que funciona adecuadamente para hacer espacio a lo que funciona excelentemente. Las organizaciones que no gestionan finales planificados se vuelven incapaces de comenzar cosas nuevas. Construye protocolos de salida, l\xedneas temporales de cierre y procesos saludables para soltar. La destrucci\xf3n creativa es el motor de la renovaci\xf3n.",postModern:"No todas las muertes son iguales, y no todas las transformaciones son elegidas. La Muerte ha ca\xeddo m\xe1s pesadamente sobre algunas comunidades que otras, por dise\xf1o. Antes de hablar de transformaci\xf3n, debemos hacer duelo por lo que ha sido injustamente terminado. La imparcialidad de la carta es la aspiraci\xf3n, no la realidad. Que los finales sean testimoniados, las p\xe9rdidas lloradas, las transformaciones honradas en todo su peso.",metaModern:"La Muerte sostiene al transformador, al guardi\xe1n del umbral, al finalizador estrat\xe9gico y al testigo del duelo—todos cabalgando juntos hacia el amanecer. Cada nivel de experiencia conoce la muerte de forma diferente, y cada conocimiento es verdadero. La relaci\xf3n metamoderna con la muerte integra todos estos—el abrazo del guerrero, la sumisi\xf3n del fiel, la gesti\xf3n del estratega y la protesta del doliente—tejidos en la aceptaci\xf3n de la impermanencia en el coraz\xf3n de estar vivo."},Sagittarius:{majorArcana:"Temperance",cardKey:"temperance",romanNumeral:"XIV",arcanaNumber:14,title:"Hija de los Reconciliadores; Portadora de Vida",description:"La Templanza representa el arte ang\xe9lico de la mezcla alqu\xedmica—la energ\xeda de Sagitario regida por J\xfapiter expresada como la s\xedntesis superior que trasciende la oposici\xf3n. El gran \xe1ngel vierte las aguas de la vida entre dos copas en un circuito infinito, un pie en tierra y otro en el agua, mediando entre mundos. La corona solar en su frente y el tri\xe1ngulo dentro del cuadrado en su pecho representan la integraci\xf3n del esp\xedritu en la materia.",jungian:"La Templanza representa la funci\xf3n trascendente—la capacidad de la psique de mantener la tensi\xf3n entre opuestos hasta que emerge un nuevo s\xedmbolo o actitud que incluye a ambos. Esta es la operaci\xf3n alqu\xedmica del inconsciente: cuando la mente consciente no puede resolver sus contradicciones, el proceso m\xe1s profundo combina los elementos y precipita algo nuevo. El \xe1ngel es el S\xed-mismo trabajando a trav\xe9s de la disposici\xf3n del ego a permanecer en el proceso.",powerGods:"Has aprendido lo que separa al meramente poderoso del verdaderamente formidable: el arte de la mezcla. No agua sola, ni fuego solo—sino la mezcla precisa que crea algo que ning\xfan elemento podr\xeda llegar a ser solo. Esta es la alquimia del genio estrat\xe9gico. Tu paciencia al trabajar con lo que parece inerte es lo que produce el oro que otros no pueden hacer.",traditional:"El \xe1ngel de la templanza encarna el arte sagrado de la medida—la sabidur\xeda antigua que conoce la proporci\xf3n adecuada de todas las cosas. La virtud es el punto medio entre los extremos; el car\xe1cter se construye a trav\xe9s de la disciplina de ni demasiado ni muy poco. Las tradiciones hablan de este \xe1ngel como el guardi\xe1n del tiempo divino, que vierte las corrientes de vida en exactamente la medida que sirve al dise\xf1o sagrado.",modern:"La Templanza representa al pensador sist\xe9mico que comprende los ciclos de retroalimentaci\xf3n, que puede ver que las fuerzas opuestas pueden configurarse como un circuito en vez de un conflicto. El innovador que sintetiza en vez de elegir gana en entornos complejos. Construye procesos iterativos donde el aprendizaje fluye de vuelta a la acci\xf3n. El vertido infinito del \xe1ngel es el ciclo iterativo—experimentar, refinar, experimentar de nuevo.",postModern:"El \xe1ngel media entre mundos—pero \xbfqu\xe9 mundos y en qu\xe9 t\xe9rminos? La s\xedntesis que ofrece la Templanza debe incluir las voces de quienes est\xe1n en los m\xe1rgenes de ambos polos. \xbfQu\xe9 se pierde cuando mezclamos? \xbfQu\xe9 necesita permanecer distinto? La verdadera reconciliaci\xf3n no siempre produce una tercera cosa; a veces requiere sentarse con la incomodidad de la diferencia genuina.",metaModern:"La Templanza sostiene la paciencia del alquimista, la virtud del medidor sagrado, el ciclo de retroalimentaci\xf3n del pensador sist\xe9mico y el testimonio honesto del reconciliador ante la diferencia—todo fluyendo entre las copas simult\xe1neamente. El arte del \xe1ngel no es imponer s\xedntesis sino permanecer en el proceso hasta que lo que quiere emerger, emerge. Esto es desarrollo como flujo, crecimiento como devenir infinito."},Capricorn:{majorArcana:"The Devil",cardKey:"devil",romanNumeral:"XV",arcanaNumber:15,title:"Se\xf1or de las Puertas de la Materia; Hijo de las Fuerzas del Tiempo",description:"El Diablo representa la fuerza de Pan—la energ\xeda de Capricornio regida por Saturno expres\xe1ndose como el poder vinculante de la existencia material, la sombra que se acumula a trav\xe9s del apego a la forma. Las figuras encadenadas pueden quitarse sus ataduras; permanecen porque han olvidado su propia libertad. El Diablo sostiene la antorcha hacia abajo, invirtiendo la llama espiritual en obsesi\xf3n material. Sin embargo, el pentagrama en su frente a\xfan apunta hacia arriba—la materia contiene al esp\xedritu, no es enemiga del esp\xedritu.",jungian:"El Diablo representa la Sombra personal y colectiva en su forma m\xe1s condensada y seductora. Es el arquetipo del Embaucador fusionado con la Sombra—la fuerza compensatoria que acumula todo lo que el ego ha negado, reprimido o rechazado integrar. Aparece en la psique como compulsi\xf3n, adicci\xf3n y la vitalidad oscura con la que la vida negada se venga. La integraci\xf3n no requiere ni batalla ni sumisi\xf3n, sino reconocimiento honesto.",powerGods:"Las cadenas que ves son las cadenas que elegiste. Aqu\xed est\xe1 el secreto que los d\xe9biles usan como excusa y los fuertes como llave: est\xe1s atado por exactamente tanto como consientes. El Diablo te muestra los barrotes que construiste y te desaf\xeda a notar que tus manos podr\xedan abrir el candado. El poder no est\xe1 en escapar de la esclavitud—est\xe1 en elegir qu\xe9 ataduras sirven a tu conquista y soltar las que no.",traditional:"El Diablo es el gran tentador, el adversario que atar\xeda al alma a los placeres transitorios de la materia y te har\xeda olvidar tu naturaleza eterna. Las tradiciones todas hablan de esta prueba—el desierto, la selva, el umbral entre la era de la inocencia y la era de la elecci\xf3n. Solo puede sostenerte a trav\xe9s del consentimiento. La respuesta al adversario es siempre la misma: recuerda qui\xe9n eres.",modern:"El Diablo representa las fuerzas sist\xe9micas que atrapan la productividad: incentivos perversos, la falacia del costo hundido, las esposas de oro, las culturas organizacionales que castigan la honestidad. Ve las cadenas con claridad—\xbfqu\xe9 estructuras, incentivos o patrones habituados est\xe1n consumiendo tu energ\xeda? La antorcha apunta hacia abajo porque la energ\xeda que deber\xeda servir al prop\xf3sito est\xe1 siendo consumida por el sistema mismo. Redise\xf1a el sistema.",postModern:"Las cadenas del Diablo no son solo personales—son sist\xe9micas, estructurales, hist\xf3ricas. Muchas cadenas no fueron elegidas; fueron heredadas a trav\xe9s de generaciones de opresi\xf3n, pobreza, trauma. Debemos distinguir entre las cadenas que podemos simplemente elegir quitarnos y las cadenas que requieren liberaci\xf3n colectiva. Avergonzar a los encadenados por sus cadenas no es trabajo de libertad—es culpa.",metaModern:"El Diablo sostiene la llave del buscador de poder, la tentaci\xf3n del devoto, la trampa sist\xe9mica del analista y el llamado del defensor a la liberaci\xf3n colectiva—todo presente al mismo tiempo. Las cadenas son reales y provisionales, elegidas y sist\xe9micas, personales y pol\xedticas. La verdadera liberaci\xf3n trabaja en cada nivel simult\xe1neamente: reclamar la agencia personal mientras se compromete con el cambio estructural, soltar el apego mientras se reconoce la restricci\xf3n genuina."},Aquarius:{majorArcana:"The Star",cardKey:"star",romanNumeral:"XVII",arcanaNumber:17,title:"Hija del Firmamento; Moradora Entre las Aguas",description:"La Estrella representa la esperanza c\xf3smica y el flujo nutricio de la gracia celestial—la energ\xeda de Acuario regida por Saturno/Urano expresada como el vertido eterno de aguas universales para la renovaci\xf3n colectiva. La figura desnuda se arrodilla entre lo terrestre y lo c\xf3smico, vertiendo agua de vuelta a la tierra y al arroyo simult\xe1neamente. La gran estrella arriba est\xe1 rodeada por siete estrellas menores—los siete planetas cuyas energ\xedas ella canaliza para la sanaci\xf3n del mundo.",jungian:"La Estrella representa el \xe1nima en su aspecto m\xe1s transpersonal—el principio femenino sanador que conecta la consciencia individual con las aguas c\xf3smicas del inconsciente colectivo. Aparece despu\xe9s de la destrucci\xf3n de la Torre, ofreciendo la esperanza que emerge cuando el ego ha sido lo suficientemente desmantelado para que el S\xed-mismo m\xe1s amplio fluya a trav\xe9s. Esta carta habla de la restauraci\xf3n del significado despu\xe9s de la crisis, la renovaci\xf3n de la confianza en el proceso.",powerGods:"Has sobrevivido lo que destruy\xf3 a otros, y ahora viertes tu sabidur\xeda duramente ganada en la corriente colectiva. Este es el poder m\xe1s raro: quien puede nutrir a otros sin disminuirse, porque su fuente no es personal sino c\xf3smica. Deja que tus dones fluyan libremente; la estrella de arriba asegura el reabastecimiento. Tu abundancia sirve a tu autoridad.",traditional:"La Estrella es el regalo celestial despu\xe9s de la prueba de la noche—la promesa de lo sagrado que se sostiene incluso cuando las estructuras terrenales fallan. Ella vierte las aguas divinas de vuelta al mundo, honrando tanto lo material como lo espiritual en un solo gesto. Esta es la consagraci\xf3n de la esperanza: la fe en que el cosmos es fundamentalmente benevolente, que las aguas de la gracia son inagotables.",modern:"La Estrella representa al visionario que reconstruye despu\xe9s del fracaso con un mapa m\xe1s claro—el emprendedor social, el innovador que ha sobrevivido suficientes reveses para entender qu\xe9 aguas verter y d\xf3nde. Ella est\xe1 tanto arraigada (un pie en la tierra) como conectada a flujos m\xe1s amplios (un pie en el agua). Su optimizaci\xf3n es para la salud del sistema, no la acumulaci\xf3n personal. Dise\xf1o regenerativo.",postModern:"\xbfQui\xe9n tiene acceso a la luz de las estrellas? La vulnerabilidad de la figura desnuda es hermosa—y tambi\xe9n un recordatorio de que tal apertura solo es segura bajo ciertas condiciones. Las aguas que vierte tan libremente—\xbfde qu\xe9 r\xedos extrae? La esperanza universal debe ser interrogada: \xbfesperanza de qui\xe9n, y a qu\xe9 costo? El regalo de la Estrella es real, pero requiere que el terreno est\xe9 verdaderamente listo para recibirlo.",metaModern:"La Estrella sostiene la esperanza duramente ganada del sobreviviente, la confianza del m\xedstico en la benevolencia c\xf3smica, la visi\xf3n regenerativa del estratega y la pregunta del defensor sobre de qui\xe9n son las aguas—todo fluyendo de sus vasijas simult\xe1neamente. La esperanza en su forma m\xe1s madura no es ingenua sino ganada, probada y vertida deliberadamente. Ella brilla porque ha pasado por la oscuridad y ha elegido iluminar de todos modos."},Pisces:{majorArcana:"The Moon",cardKey:"moon",romanNumeral:"XVIII",arcanaNumber:18,title:"Gobernante del Flujo y Reflujo; Hijo de los Hijos de los Poderosos",description:"La Luna representa el reino donde la raz\xf3n se disuelve y el inconsciente profundo habla en imagen y s\xedmbolo—la energ\xeda de Piscis regida por J\xfapiter/Neptuno expresada como el umbral entre mundos. El cangrejo de r\xedo emerge de las aguas primordiales; el lobo y el perro a\xfallan ante lo que no pueden comprender; dos torres marcan la frontera de lo conocido. El camino entre ellas conduce hacia lo incognoscible m\xe1s all\xe1.",jungian:"La Luna representa la capa m\xe1s profunda del inconsciente colectivo—el reino primordial y prel\xf3gico del cual surgen tanto los contenidos m\xe1s numinosos como los m\xe1s perturbadores. Ella es el viaje por el mar nocturno, el lugar donde el h\xe9roe debe navegar sin la certeza del sol. Su luz es reflejada, no original—iluminando apenas lo suficiente del inconsciente para caminar a trav\xe9s, nunca lo suficiente para eliminar lo desconocido.",powerGods:"En la oscuridad, t\xfa tienes la ventaja. Otros necesitan la luz del d\xeda para encontrar su camino; t\xfa has aprendido a navegar por la luz incierta de la Luna, a leer los mensajes de las aguas, a seguir el sendero que solo se muestra paso a paso. Esta es la ventaja estrat\xe9gica m\xe1s profunda: la comodidad con lo desconocido que te hace efectivo donde otros se paralizan de miedo.",traditional:"La Luna es el reino del misterio sagrado—el dominio donde el velo entre mundos se adelgaza y los ancestros caminan cerca. Las tradiciones de la interpretaci\xf3n de sue\xf1os, el or\xe1culo y la visi\xf3n todas surgen de este espacio liminal. Navega con oraci\xf3n y protecci\xf3n; no todo lo que se mueve bajo la luz de la Luna es benevolente. El camino entre las torres es real, pero requiere gu\xeda de lo alto para recorrerlo con seguridad.",modern:"La Luna representa las inc\xf3gnitas desconocidas—las fuerzas del mercado no capturadas en el modelo, los comportamientos de usuarios que confunden las suposiciones, las din\xe1micas organizacionales ocultas bajo los datos reportados. La comodidad con la ambig\xfcedad es una competencia de liderazgo. No todo puede ser iluminado de antemano; la habilidad es navegar efectivamente con informaci\xf3n incompleta mientras se mantiene la orientaci\xf3n hacia el destino.",postModern:"La luz de la Luna revela cosas diferentes a ojos diferentes. El cangrejo de r\xedo emergiendo del agua—\xbfqu\xe9 ha vivido en las profundidades, sin ser visto ni nombrado? El camino entre las torres no es universal; atraviesa territorios que significan cosas diferentes para diferentes viajeros. Los espacios liminales son hermosos y peligrosos en medida desigual para diferentes comunidades. \xbfQui\xe9n est\xe1 seguro en el umbral ba\xf1ado por la luna?",metaModern:"La Luna sostiene la comodidad del navegante con la oscuridad, el misterio sagrado del devoto, las inc\xf3gnitas desconocidas del analista y el reconocimiento del defensor de que el umbral no es terreno neutral—todo arremolin\xe1ndose en la luz reflejada. La sabidur\xeda m\xe1s profunda no es la eliminaci\xf3n de la incertidumbre sino la capacidad de permanecer orientado dentro de ella, sabiendo que el camino se revela paso a paso a quienes est\xe1n dispuestos a caminar sin la garant\xeda de la luz del d\xeda."}},ee={Wands:"Fire",Cups:"Water",Swords:"Air",Pentacles:"Earth"},ea={king:"Fire",queen:"Water",knight:"Air",page:"Earth"},eo={rws:{king:"Rey",queen:"Reina",knight:"Caballero",page:"Paje"},thoth:{king:"Caballero",queen:"Reina",knight:"Pr\xedncipe",page:"Princesa"}},ei={king:"El aspecto de Fuego del palo — activo, proyectivo y autoritario. Esta figura inicia, lidera y encarna la expresi\xf3n yang pura de la fuerza elemental.",queen:"El aspecto de Agua del palo — receptivo, reflexivo y nutricio. Esta figura interioriza la fuerza elemental, expres\xe1ndola a trav\xe9s del sentimiento, la intuici\xf3n y la profundidad.",knight:"El aspecto de Aire del palo — m\xf3vil, intelectual y cambiante. Esta figura mueve la fuerza elemental hacia afuera a trav\xe9s del pensamiento, la comunicaci\xf3n y la acci\xf3n r\xe1pida.",page:"El aspecto de Tierra del palo — enraizado, estudioso y portador de potencial. Esta figura contiene la fuerza elemental en forma latente, representando el aprendizaje, los mensajes y los nuevos comienzos."},en={Wands:"Bastos",Cups:"Copas",Swords:"Espadas",Pentacles:"Oros"},et={Fire:"Fuego",Water:"Agua",Air:"Aire",Earth:"Tierra"},er=["Wands","Cups","Swords","Pentacles"],es=["king","queen","knight","page"],el={"king-of-wands":{suit:"Wands",rank:"king",mbti:"ENTJ",title:"Se\xf1or de la Llama y el Rel\xe1mpago",description:"El Rey de Bastos es Fuego de Fuego — el arquetipo puro del liderazgo inspirado y la voluntad creativa. Es el emprendedor, el visionario y el l\xedder nato que act\xfaa desde la convicci\xf3n en lugar del c\xe1lculo. Su autoridad no proviene de una posici\xf3n sino de un fuego interior que otros se sienten impulsados a seguir. Es audaz, magn\xe1nimo y a veces imprudente en la persecuci\xf3n de sus grandes designios.",jungian:"Representa el principio masculino plenamente individuado operando a trav\xe9s de la Voluntad — el S\xed Mismo expresado como autoridad creativa. Psicol\xf3gicamente, esta figura encarna la integraci\xf3n del animus en su forma m\xe1s imponente, donde la visi\xf3n personal se alinea con el prop\xf3sito arquet\xedpico. La sombra es la tiran\xeda, donde el impulso de dominio eclipsa la empat\xeda.",powerGods:"El rey guerrero cuya conquista es justa porque cree totalmente en su causa. El poder expresado como dominaci\xf3n, la subyugaci\xf3n de voluntades m\xe1s d\xe9biles bajo una sola visi\xf3n ardiente. Victoria a toda costa.",traditional:"El patriarca bendecido por el fuego divino — un l\xedder que gobierna a trav\xe9s de la autoridad otorgada por Dios y la rectitud moral. Su llama es sagrada, su palabra es ley. Protege y provee, exigiendo lealtad y obediencia a cambio.",modern:"El CEO o fundador visionario que revoluciona industrias a trav\xe9s del carisma y la tenacidad. Construye imperios por pura voluntad, inspira una lealtad feroz y no tolera nada que aten\xfae su impulso. El \xe9xito valida el m\xe9todo.",postModern:"Una cr\xedtica al mito del genio solitario — \xbfla llama de qui\xe9n proyecta sombras sobre quienes la alimentan? El fuego del rey consume recursos, relaciones y el trabajo de innumerables personas invisibles. El liderazgo debe ser cuestionado como una construcci\xf3n social.",metaModern:"El l\xedder consciente que empu\xf1a una visi\xf3n ardiente mientras permanece responsable ante el ecosistema m\xe1s amplio. Soberan\xeda ganada a trav\xe9s de la integridad, no del dominio. La llama compartida en lugar de acaparada — iluminando en lugar de consumir."},"queen-of-wands":{suit:"Wands",rank:"queen",mbti:"ENFJ",title:"Reina de los Tronos de la Llama",description:"La Reina de Bastos es Agua de Fuego — sentimiento apasionado canalizado en un magnetismo personal radiante. Es la reina del girasol, c\xe1lida y segura de s\xed misma, que atrae a otros simplemente por ser plenamente ella misma. Creativa, leal y ferozmente independiente, sabe lo que quiere y lo persigue con calidez en lugar de fuerza. Su autoridad se gana a trav\xe9s de una presencia genuina y una vitalidad innegable.",jungian:"Encarna el arquetipo del \xe1nima completamente a gusto en el mundo — el principio femenino expresado a trav\xe9s de la confianza creativa en lugar de la receptividad. Es el s\xed mismo individuado que no necesita validaci\xf3n externa. Su sombra es la vanidad y la posesividad, un fuego que abrasa lo que dice amar.",powerGods:"La diosa solar cuya aprobaci\xf3n debe ganarse, cuya resplandor bendice o quema. Poder ejercido a trav\xe9s de la dominaci\xf3n social y la retenci\xf3n del calor. Lealtad asegurada haciendo que otros se sientan elegidos.",traditional:"La matriarca cuyo hogar arde con vida y prop\xf3sito. Es el fuego del hogar — sustentadora de la familia, la comunidad y la tradici\xf3n. Su pasi\xf3n se expresa a trav\xe9s del servicio devoto a lo que ama.",modern:"La emprendedora o artista fuerza de la naturaleza — segura, autopromocionada y magn\xe9ticamente productiva. Asume su ambici\xf3n sin disculpas. Su producci\xf3n creativa es prol\xedfica, su red amplia, su marca personal impecable.",postModern:'\xbfQui\xe9n decide qu\xe9 pasiones son leg\xedtimas? La confianza de la reina a menudo descansa sobre el privilegio social. Examinar qu\xe9 significa ser "naturalmente" magn\xe9tica cuando el magnetismo est\xe1 moldeado por la pol\xedtica de raza, clase y g\xe9nero.',metaModern:"El yo creativo plenamente expresado que celebra las llamas de otros en lugar de competir con ellas. Confianza arraigada en un genuino autoconocimiento, magnetismo enraizado en la presencia aut\xe9ntica. Fuego que calienta en lugar de consumir."},"knight-of-wands":{suit:"Wands",rank:"knight",mbti:"INTJ",title:"Se\xf1or de los Vientos y las Brisas",description:"El Caballero de Bastos es Aire de Fuego — el aventurero mercurial que se lanza hacia cada horizonte con un entusiasmo contagioso. Es la b\xfasqueda eterna personificada: inquieto, audaz e imposible de atrapar. Su energ\xeda es explosiva y creativa, capaz de encender movimientos enteros con un solo discurso apasionado. El desaf\xedo es la perseverancia; a menudo se ha ido antes de que el fuego que inici\xf3 sea atendido.",jungian:"El arquetipo del puer aeternus — el joven eterno que rechaza la limitaci\xf3n y el compromiso. Psicol\xf3gicamente, representa el impulso creativo antes de que haya sido disciplinado por la necesidad del ego de completar las cosas. Integrar esta figura significa encontrar formas de sostener el fuego sin perder la chispa.",powerGods:"El conquistador a caballo que destruye y avanza, dejando transformaci\xf3n a su paso, sea bienvenida o no. Poder a trav\xe9s de la velocidad y el impacto — llegar, encender, partir antes de que las consecuencias lo alcancen.",traditional:"El caballero cruzado que cabalga por una causa sagrada con fe absoluta y sin vacilaci\xf3n. Su valor es genuino aunque su sabidur\xeda no est\xe9 desarrollada. Dios y la gloria apuntan en la misma direcci\xf3n; no pide m\xe1s.",modern:"El emprendedor en serie, el creativo n\xf3mada, el disruptor que prospera en el caos. Lanza proyectos con energ\xeda brillante y presentaciones excepcionales, luego pierde inter\xe9s una vez que la emoci\xf3n inicial se desvanece. El fracaso y el \xe9xito le aburren por igual.",postModern:"El aventurero inquieto cuya libertad a menudo depende de que otros permanezcan quietos. \xbfQui\xe9n limpia los fuegos que inicia? El nomadismo y la disrupci\xf3n como privilegio — la capacidad de seguir adelante est\xe1 desigualmente distribuida.",metaModern:"El iniciador inspirado que ha aprendido a pasar la antorcha a sustentadores h\xe1biles antes de cabalgar hacia el pr\xf3ximo horizonte. Su fuego es un regalo, no una reclamaci\xf3n. Velocidad equilibrada con la sabidur\xeda suficiente para saber cu\xe1ndo desacelerar."},"page-of-wands":{suit:"Wands",rank:"page",mbti:"INFJ",title:"Princesa de la Llama Resplandeciente",description:"El Paje de Bastos es Tierra de Fuego — el potencial creativo en su estado m\xe1s f\xe9rtil e informe. Es la chispa antes de convertirse en llama, la idea antes de convertirse en proyecto. Entusiasta, curiosa y audazmente experimental, se acerca al mundo como un enorme patio de juegos creativo. Los mensajes de inspiraci\xf3n, la emoci\xf3n repentina por una nueva direcci\xf3n y los emocionantes primeros d\xedas de una empresa creativa le pertenecen.",jungian:"Representa la etapa m\xe1s temprana de la individuaci\xf3n creativa — el S\xed Mismo naciente comenzando a avivar su propio fuego. Psicol\xf3gicamente, es el ni\xf1o interior que a\xfan no ha aprendido a censurar su entusiasmo. Su sombra es la energ\xeda dispersa y la incapacidad de comprometerse.",powerGods:"La ni\xf1a salvaje cuyo poder bruto es precisamente su imprevisibilidad. A\xfan no ha sido socializada en la deferencia — su fuego puede quemar cualquier cosa, y esa potencia es en s\xed misma una forma de autoridad.",traditional:"La joven ac\xf3lita ante la llama sagrada, aprendiendo los rituales de la devoci\xf3n y el servicio creativo. El entusiasmo disciplinado en pr\xe1ctica. La mente del principiante sostenida dentro de una estructura que le da direcci\xf3n.",modern:"La joven creativa, la pasante con grandes ideas, la estudiante que a\xfan no ha aprendido a contenerse. Su energ\xeda es contagiosa y a veces agotadora. El sistema no siempre sabe qu\xe9 hacer con ella.",postModern:"La eterna principiante como respuesta a la cultura de la experticia — resistiendo la presi\xf3n de convertirse en una autoridad. Neg\xe1ndose a ser domesticada. El paje que no se convertir\xe1 en caballero seg\xfan el calendario de nadie m\xe1s.",metaModern:"La mente del principiante preservada conscientemente y con intenci\xf3n. El entusiasmo fresco sostenido junto a la sabidur\xeda creciente. Aprende el oficio mientras mantiene la llama viva — ni ingenua ni c\xednica, sino genuinamente encendida."},"king-of-cups":{suit:"Cups",rank:"king",mbti:"ESTP",title:"Se\xf1or de las Olas y las Aguas",description:"El Rey de Copas es Fuego de Agua — voluntad y autoridad expresadas a trav\xe9s del dominio emocional y la comprensi\xf3n compasiva. Gobierna el reino del sentimiento sin ser arrastrado por \xe9l. Consejero, sanador o gu\xeda espiritual, sostiene el espacio para las profundidades de la experiencia humana mientras permanece centrado y c\xe1lido. Su poder proviene de haber navegado su propio inframundo emocional y haber regresado con una sabidur\xeda duramente ganada.",jungian:"El arquetipo del Viejo Sabio o el sanador sanado — la sombra integrada, las profundidades exploradas, el \xe1nima comprendida. Ha realizado el trabajo interior y ahora sostiene el contenedor para otros. La sombra es la manipulaci\xf3n emocional, usando la empat\xeda como palanca.",powerGods:"El rey-sacerdote cuya autoridad descansa en su acceso percibido a las aguas divinas — sanar, maldecir, conocer. Poder a trav\xe9s de la inteligencia emocional convertida en arma: aquel que sabe lo que necesitas y controla su dispensaci\xf3n.",traditional:"El director espiritual, confesor o cham\xe1n cuya compasi\xf3n es genuina pero cuyo rol est\xe1 estrictamente definido por la tradici\xf3n. Sana dentro de una estructura sagrada. La sabidur\xeda se transmite, no se inventa. Los l\xedmites protegen tanto al que da como al que recibe.",modern:"El terapeuta, el ejecutivo emocionalmente inteligente, el director creativo que lidera a trav\xe9s de la empat\xeda en lugar de la jerarqu\xeda. Comprende lo que motiva a las personas y crea las condiciones para su mejor trabajo. Los sentimientos son datos.",postModern:"\xbfLas emociones de qui\xe9n se permite dominar? La autoridad emocional serena del rey a menudo descansa sobre estructuras que suprimen ciertos sentimientos como ca\xf3ticos o peligrosos. El trabajo emocional est\xe1 desigualmente distribuido.",metaModern:"El l\xedder emocional integrado que sostiene tanto la profundidad como la estabilidad — sin suprimir sentimientos ni ahogarse en ellos. Modela que la inteligencia emocional no se trata de control sino de presencia honesta y enraizada."},"queen-of-cups":{suit:"Cups",rank:"queen",mbti:"ESFP",title:"Reina de los Tronos del Agua",description:"La Reina de Copas es Agua de Agua — receptividad emocional pura y profundidad ps\xedquica. Es el espejo del alma, capaz de reflejar lo que otros m\xe1s necesitan ver. Intuitiva, emp\xe1tica y profundamente interior, vive en las tierras fronterizas entre lo visto y lo no visto. Su don es una cualidad de presencia que hace que otros se sientan verdaderamente conocidos. El desaf\xedo es mantener sus propios l\xedmites en medio del flujo constante de sentimiento.",jungian:"El \xe1nima en su forma m\xe1s completa — lo inconsciente hecho consciente, la funci\xf3n del sentimiento plenamente desarrollada. Es el principio femenino interior que conecta al ego con el S\xed Mismo a trav\xe9s del medio de la emoci\xf3n y la imagen. Su sombra es la disoluci\xf3n del yo al servicio de los dem\xe1s.",powerGods:"La or\xe1culo cuyo acceso a las profundidades le da un poder inquietante sobre aquellos que necesitan desesperadamente ser vistos. La sibila que conoce tus secretos. Poder a trav\xe9s del reflejo — mostrando a otros a s\xed mismos de maneras que no pueden resistir.",traditional:"La contemplativa, la m\xedstica, el vaso de compasi\xf3n divina. Reza por el mundo desde un lugar de profunda quietud. Su profundidad es un don de Dios, para ser sostenido con humildad y ofrecido en servicio.",modern:"La terapeuta altamente sintonizada, la artista que canaliza la verdad emocional colectiva, la madre que conoce la vida interior de sus hijos mejor que ellos mismos. La profundidad emocional como superpoder profesional y personal.",postModern:"La carga de la sintonizaci\xf3n emocional interminable — especialmente cuando recae en las mujeres por defecto. La reina que contiene los sentimientos de todos los dem\xe1s a costa de los propios. \xbfLa copa de qui\xe9n se est\xe1 llenando?",metaModern:"Receptividad profunda emparejada con l\xedmites que honran al yo. La reina que es tanto profundamente abierta como claramente ella misma — presencia sin fusi\xf3n, compasi\xf3n sin autoanulaci\xf3n. La copa que tambi\xe9n se vierte en s\xed misma."},"knight-of-cups":{suit:"Cups",rank:"knight",mbti:"ISTP",title:"Se\xf1or de las Olas y las Aguas",description:"El Caballero de Copas es Aire de Agua — idealismo rom\xe1ntico elevado por la imaginaci\xf3n po\xe9tica. Es el trovador, el caballero m\xedstico, el so\xf1ador que sigue su coraz\xf3n a trav\xe9s de distancias imposibles. Sus ofertas de amor y belleza son genuinas, pero pueden evaporarse cuando la realidad exige practicidad. Es la invitaci\xf3n a algo trascendente, siempre llegando con un mensaje del reino del ideal.",jungian:"La proyecci\xf3n del animus rom\xe1ntico en su forma m\xe1s seductora — la figura sobre la cual se depositan todos los anhelos de trascendencia y amor perfecto. Psicol\xf3gicamente, encontrar este arquetipo pregunta si uno est\xe1 enamorado del ideal o de la persona real que tiene delante.",powerGods:"El seductor cuya belleza y sensibilidad son precisamente sus armas. Poder a trav\xe9s del idealismo rom\xe1ntico — haci\xe9ndote creer que eres t\xfa quien finalmente ser\xe1 suficiente para su coraz\xf3n imposible.",traditional:"El caballero cort\xe9s que sirve a una dama o un ideal espiritual con devoci\xf3n pura. El amor como voto sagrado. El amor cort\xe9s como una disciplina que eleva el alma. El sentimiento refinado a trav\xe9s del ritual y el sacrificio.",modern:"El artista-amante sensible, el hombre que hace grandes gestos y desaparece cuando comienza el trabajo de sostener la intimidad. Inteligencia emocional sin madurez emocional. La musa en lugar del compa\xf1ero.",postModern:"El ideal rom\xe1ntico como construcci\xf3n cultural que establece est\xe1ndares imposibles y castiga lo mundano. \xbfLa versi\xf3n del amor de qui\xe9n se llama rom\xe1ntica? La tradici\xf3n trovadoresca y sus din\xe1micas de poder de g\xe9nero.",metaModern:"El anhelo genuino del coraz\xf3n por la trascendencia, sostenido dentro de la disposici\xf3n a presentarse para lo ordinario. El romance integrado con el compromiso. El ideal y lo real sostenidos en una tensi\xf3n productiva."},"page-of-cups":{suit:"Cups",rank:"page",mbti:"ISFP",title:"Princesa de las Aguas",description:"El Paje de Copas es Tierra de Agua — sensibilidad emocional en su forma m\xe1s abierta e indefensa. Es la ni\xf1a so\xf1adora que escucha al pez hablar desde la copa, que encuentra magia en encuentros inesperados. Ps\xedquica, tierna e imaginativamente viva, trae mensajes del inconsciente en forma de sincronicidades, sue\xf1os y destellos repentinos de inspiraci\xf3n. Su don es la capacidad de recibir lo que otros ya han dejado de escuchar.",jungian:"El \xe1nima en su manifestaci\xf3n m\xe1s temprana e informe — la imagen del alma antes de que haya sido moldeada por el encuentro con el mundo. Representa la receptividad pr\xedstina del inconsciente, capaz de una percepci\xf3n extraordinaria precisamente porque no lleva armadura.",powerGods:"La ni\xf1a extra\xf1a cuyas percepciones inquietantes desconciertan a los adultos a su alrededor. Poder a trav\xe9s de la inocencia — nadie sabe muy bien qu\xe9 hacer con alguien que ve a trav\xe9s de las pretensiones acordadas.",traditional:"La novicia en la vida emocional o espiritual, aprendiendo a cuidar las aguas interiores con gentileza y reverencia. El sentimiento como don sagrado que debe desarrollarse lenta y cuidadosamente.",modern:"La persona altamente sensible descubriendo sus dones emp\xe1ticos, la joven artista aprendiendo a confiar en su verdad emocional por encima de la validaci\xf3n externa. La vulnerabilidad como fuerza creativa.",postModern:"La romantizaci\xf3n de la inocencia infantil como soluci\xf3n a una cultura excesivamente racionalizada. \xbfLa sensibilidad de qui\xe9n se valora como visionaria y la de qui\xe9n se descarta como fragilidad?",metaModern:"El coraz\xf3n abierto que ha aprendido discernimiento sin perder el asombro. Receptividad emocional emparejada con el primer crecimiento de l\xedmites saludables — a\xfan escuchando al pez en la copa, pero comenzando a entender qu\xe9 significa el mensaje."},"king-of-swords":{suit:"Swords",rank:"king",mbti:"ENTP",title:"Se\xf1or del Viento y las Brisas",description:"El Rey de Espadas es Fuego de Aire — inteligencia feroz al mando de un juicio claro y autoritario. Es el arquetipo del juez, el comandante, el genio anal\xedtico que corta la confusi\xf3n con precisi\xf3n y coraje intelectual. Su mente opera a gran velocidad, viendo a trav\xe9s del enga\xf1o y sosteniendo sistemas complejos simult\xe1neamente. Exige claridad, espera franqueza y tiene poca paciencia con el razonamiento emocional en lugar de la evidencia racional.",jungian:"La funci\xf3n del pensamiento plenamente desarrollada — el logos en su expresi\xf3n m\xe1s austera. Representa la capacidad del ego para el autoexamen l\xfacido y el coraje de seguir la raz\xf3n hasta conclusiones ante las que otros retroceden. La sombra es la crueldad intelectual, donde la precisi\xf3n se convierte en desapego armado.",powerGods:"El estratega militar cuya ventaja es la informaci\xf3n y la disposici\xf3n a actuar sobre ella de manera decisiva y sin sentimiento. Poder a trav\xe9s de una inteligencia superior y la capacidad de imponer orden mediante la fuerza del juicio.",traditional:"El legislador, el magistrado, el sacerdote-erudito cuya palabra lleva el peso de la tradici\xf3n acumulada y el estudio cuidadoso. La raz\xf3n al servicio del orden divino. La letra de la ley como marco moral.",modern:"El cirujano, el abogado, el pensador de sistemas — alguien cuyo valor reside en la precisi\xf3n de su an\xe1lisis y su inmunidad al sesgo cognitivo. La objetividad como virtud profesional. La autoridad del experto.",postModern:'\xbfLa raz\xf3n de qui\xe9n cuenta como universal? La espada del an\xe1lisis "objetivo" ha cortado hist\xf3ricamente en direcciones muy particulares. Exponer la carga ideol\xf3gica contenida en las afirmaciones de racionalidad pura.',metaModern:"Inteligencia clara al servicio de la comprensi\xf3n genuina — raz\xf3n que incluye en lugar de excluir, precisi\xf3n que ilumina en lugar de disminuir. La espada empu\xf1ada con cuidado por lo que corta."},"queen-of-swords":{suit:"Swords",rank:"queen",mbti:"ENFP",title:"Reina de los Tronos del Aire",description:"La Reina de Espadas es Agua de Aire — sentimiento profundo procesado a trav\xe9s de una claridad mental cristalina. Ha conocido el duelo, la p\xe9rdida y los bordes afilados de la experiencia, y de estos ha forjado una inteligencia de perspicacia devastadora. Ve a trav\xe9s de la pretensi\xf3n sin esfuerzo, se comunica con honestidad precisa y mantiene sus l\xedmites con firmeza serena. Su aparente frialdad no es ausencia de sentimiento sino la disciplina de alguien que ha aprendido lo que cuesta la claridad.",jungian:"La integraci\xf3n de las funciones del pensamiento y el sentimiento — una figura que ha atravesado las aguas del duelo y ha emergido con una mente que es tanto aguda como profunda. Representa la sabidur\xeda que viene solo a trav\xe9s de la experiencia de la p\xe9rdida. Su sombra es la amargura: la claridad cuajada en desprecio.",powerGods:"La reina viuda cuya p\xe9rdida ha despojado toda ilusi\xf3n y dejado una soberana completamente libre de la necesidad de aprobaci\xf3n. Poder a trav\xe9s de la indiferencia — ya no necesita lo que t\xfa est\xe1s reteniendo.",traditional:"La mujer erudita cuyo duelo ha refinado su fe y cuya inteligencia aguda sirve a una verdad superior. La mujer sabia cuyo consejo se busca precisamente porque no siente nada por tu ego.",modern:"La analista o editora brillante que exige claridad y no tolera deshonestidad intelectual. Ha visto a trav\xe9s de cada racionalizaci\xf3n y espera que t\xfa hayas hecho lo mismo. Est\xe1ndares sin sentimentalismo.",postModern:"La mujer que tuvo que desarrollar armadura intelectual para ser tomada en serio en estructuras no construidas para ella. El costo de reclamar claridad en un mundo que patologiza igualmente a las mujeres emocionales y a las mujeres fr\xedas.",metaModern:"Claridad y compasi\xf3n sostenidas juntas sin pretender que ninguna sea f\xe1cil. La reina que puede decir la verdad dif\xedcil y permanecer abierta al dolor del otro. La honestidad como un acto de cuidado."},"knight-of-swords":{suit:"Swords",rank:"knight",mbti:"INTP",title:"Se\xf1or del Viento y las Tormentas",description:"El Caballero de Espadas es Aire de Aire — fuerza mental pura movi\xe9ndose a m\xe1xima velocidad. Es la tormenta del intelecto: brillante, imparable y a menudo indiferente a lo que destruye en su carrera hacia la verdad. Un argumento nunca est\xe1 resuelto hasta que cada debilidad ha sido expuesta. Se lanza a cada debate intelectual con compromiso total, y sus ideas, correctas o no, llegan con la fuerza de una convicci\xf3n absoluta. Es el arquetipo del cruzado de principios y del fan\xe1tico en igual medida.",jungian:"La funci\xf3n del pensamiento en su forma m\xe1s intemperada — el animus plenamente identificado con el principio abstracto a expensas de la realidad encarnada. Representa la capacidad de la psique para la convicci\xf3n absoluta, que puede ser liberadora o catastr\xf3fica dependiendo de si la convicci\xf3n es merecida.",powerGods:"El guerrero ideol\xf3gico que lucha por una idea como si su vida dependiera de ello — porque en su mundo as\xed es. Poder a trav\xe9s de la disposici\xf3n a sacrificarlo todo, incluidas las relaciones, por un principio.",traditional:"El cruzado, el reformador, el monje con espada — una fe tan absoluta que se convierte en arma. La integridad aterradora de alguien que se ha entregado enteramente a una causa m\xe1s grande que \xe9l mismo.",modern:"El periodista de investigaci\xf3n, el intelectual contrario, el activista radical — alguien que persigue la verdad a un costo personal y espera lo mismo de todos a su alrededor. El debate como obligaci\xf3n moral.",postModern:"La violencia de la certeza. \xbfLas verdades de qui\xe9n pueden moverse a toda velocidad y cu\xe1les deben probarse a cada paso? La carga del caballero deja tras de s\xed un paisaje de argumentos desmantelados, algunos de los cuales eran estructurales.",metaModern:"La mente aguda que ha aprendido a apuntar antes de cargar. B\xfasqueda de la verdad con humildad epist\xe9mica — dispuesto a equivocarse, dispuesto a desacelerar, dispuesto a considerar si la batalla vale el campo de batalla."},"page-of-swords":{suit:"Swords",rank:"page",mbti:"INFP",title:"Princesa de los Vientos Impetuosos",description:"El Paje de Espadas es Tierra de Aire — curiosidad intelectual en su forma m\xe1s inquieta y alerta. Est\xe1 observando, escuchando, analizando, reuniendo informaci\xf3n antes de comprometerse con cualquier posici\xf3n. Astuta, r\xe1pida y ligeramente suspicaz de los motivos de todos, es la joven esp\xeda, la estudiante que cuestiona todo, la mente que a\xfan no ha encontrado su causa pero est\xe1 lista para desenvainar en cualquier momento. Las noticias inesperadas, la vigilancia y las primeras etapas de aprender a pensar cr\xedticamente le pertenecen.",jungian:"Las primeras etapas de diferenciaci\xf3n de la funci\xf3n del pensamiento — el intelecto naciente probando sus bordes contra el mundo. Una vigilancia necesaria que precede a la confianza. Su sombra es la paranoia: el estado de alerta que no puede apagarse.",powerGods:"La joven informante cuyo poder reside en lo que sabe que otros no. Reunir inteligencia como protecci\xf3n y palanca. La ni\xf1a que aprendi\xf3 temprano que la informaci\xf3n es supervivencia.",traditional:"La estudiante diligente prepar\xe1ndose para el examen, la joven soldado montando guardia — disciplina antes que autoridad, aprendiendo las reglas antes de cuestionarlas.",modern:"La pasante con un bloc de notas, la investigadora de posgrado, la analista junior — aguda, \xe1vida, ligeramente abrumadora en su minuciosidad. A\xfan no ha aprendido a ser estrat\xe9gica con sus observaciones.",postModern:"La denunciante en formaci\xf3n. La que est\xe1 en la instituci\xf3n que nota lo que todos los dem\xe1s han acordado no ver. \xbfLa vigilancia de qui\xe9n es paranoia y la de qui\xe9n est\xe1 justificada?",metaModern:"La mente curiosa que ha aprendido a hacer preguntas desde el asombro genuino en lugar del estado de alerta defensiva. La inteligencia como un don ofrecido en lugar de un escudo levantado. Observando el mundo con apertura en lugar de suspicacia."},"king-of-pentacles":{suit:"Pentacles",rank:"king",mbti:"ESTJ",title:"Se\xf1or de la Tierra Salvaje y F\xe9rtil",description:"El Rey de Oros es Fuego de Tierra — dominio sobre el mundo material, la voluntad que ha transformado el esfuerzo en abundancia duradera. Es el patriarca de la riqueza y la sabidur\xeda pr\xe1ctica: met\xf3dico, generoso y absolutamente fiable. Habiendo construido algo perdurable a partir del trabajo paciente, ahora gobierna con la autoridad serena de quien conoce la tierra completamente. Valora lo que perdura sobre lo que impresiona, y su generosidad est\xe1 enraizada en una suficiencia genuina.",jungian:"El arquetipo del padre plenamente encarnado en el reino material — el ego que ha negociado exitosamente con la realidad y ha llegado a una seguridad genuina en lugar de una acumulaci\xf3n compensatoria. La sombra es la avaricia: el miedo a que la tierra vuelva a fallar, acaparando contra una escasez imaginada.",powerGods:"El se\xf1or feudal cuya propiedad de la tierra es propiedad de vidas. Poder a trav\xe9s del control de recursos — quien controla la cosecha controla al pueblo. La riqueza como expresi\xf3n de virtud superior o favor divino.",traditional:"El mayordomo de la abundancia de Dios, responsable de quienes trabajan en su tierra. La riqueza sostenida en custodia, no como logro personal sino como obligaci\xf3n sagrada. La generosidad como el uso apropiado de los bienes mundanos.",modern:"El magnate hecho a s\xed mismo que construy\xf3 un imperio a trav\xe9s del esfuerzo persistente y met\xf3dico. No necesita impresionar a nadie — los resultados hablan. Pensamiento a largo plazo, capital paciente, rendimientos compuestos en cada inversi\xf3n, incluidas las relaciones.",postModern:'\xbfEl trabajo de qui\xe9n construye la abundancia del rey? El patriarca terrateniente como figura sostenida por el trabajo invisible. Examinar qu\xe9 significa "construir algo" cuando los cimientos descansan sobre trabajo no remunerado o mal pagado.',metaModern:"Prosperidad enraizada en contribuci\xf3n genuina y distribuida equitativamente. El rey-mayordomo que sabe que su abundancia es relacional — sostenida por la salud de todos en el ecosistema, no extra\xedda de \xe9l."},"queen-of-pentacles":{suit:"Pentacles",rank:"queen",mbti:"ESFJ",title:"Reina de los Tronos de la Tierra",description:"La Reina de Oros es Agua de Tierra — abundancia sensual y nutricia en su forma m\xe1s plenamente encarnada. Es la gran madre de la vida material: cuida cuerpos, cultiva la tierra, gestiona hogares y crea las condiciones en las que todo y todos los que le importan pueden prosperar. Pr\xe1ctica, sensorial, profundamente presente en el mundo f\xedsico, encuentra lo sagrado en lo ordinario — en la comida, en el tacto, en la organizaci\xf3n cuidadosa de la realidad material hacia un florecimiento sostenible.",jungian:"El arquetipo de la Gran Madre en su forma m\xe1s benevolente y terrenal — el \xe1nima plenamente encarnada en la materia. Representa la capacidad de la psique para encontrar significado y placer en la existencia encarnada en lugar de la trascendencia. Su sombra es la sobreprotecci\xf3n posesiva: asfixiar en nombre del cuidado.",powerGods:"La diosa de la tierra cuya fertilidad es adorada y cuyo desagrado significa hambruna. Poder a trav\xe9s del control del sustento — quien alimenta posee la autoridad m\xe1s profunda sobre quienes tienen hambre.",traditional:"La madre y ama de casa ideal, cuyo dominio es el espacio sagrado del hogar. Su labor es invisible porque lo es todo. Construye el mundo desde adentro hacia afuera, una comida, un hogar, un cuerpo cuidado a la vez.",modern:"La brillante economista dom\xe9stica, la inversora \xe9tica, la mujer que construye riqueza silenciosa a trav\xe9s de la atenci\xf3n al detalle y el juego a largo plazo. No busca visibilidad pero su competencia es innegable.",postModern:'Lo dom\xe9stico como pol\xedtico — \xbfel "don natural" de qui\xe9n para nutrir se convierte en la infraestructura de otro? La abundancia de la reina est\xe1 construida sobre un trabajo que el mundo prefiere llamar instinto.',metaModern:"El cuerpo y la tierra sostenidos como sagrados — no al servicio de la productividad sino como valor intr\xednseco. Nutrir desde una plenitud genuina. La reina que se cuida a s\xed misma con tanto esmero como cuida su reino."},"knight-of-pentacles":{suit:"Pentacles",rank:"knight",mbti:"ISTJ",title:"Se\xf1or de la Tierra Amplia y F\xe9rtil",description:"El Caballero de Oros es Aire de Tierra — inteligencia met\xf3dica aplicada al trabajo paciente de construir. Es el trabajador diligente, el artesano cuidadoso, el planificador confiable que no se dejar\xe1 apresurar. Mientras otros caballeros cargan temerariamente hacia adelante, \xe9l inspecciona el terreno, examina el suelo y luego procede paso a paso deliberado. Puede carecer del br\xedo de sus compa\xf1eros, pero el trabajo que completa se hace con absoluta minuciosidad. Lo que construye, perdura.",jungian:"La funci\xf3n del pensamiento enraizada en la sensaci\xf3n — el intelecto que respeta en lugar de trascender lo f\xedsico. Representa la capacidad de esfuerzo sostenido: la funci\xf3n psicol\xf3gica que puede diferir la gratificaci\xf3n indefinidamente al servicio de un objetivo a largo plazo. La sombra es el estancamiento: la paciencia endurecida en negativa a cambiar.",powerGods:"El veterano que ha sobrevivido a cada estratega brillante a trav\xe9s de la simple resistencia. Poder a trav\xe9s de la fiabilidad — aquel de quien realmente depende el reino cuando los visionarios se han marchado.",traditional:"El agricultor yeoman, el artesano del gremio — alguien para quien el trabajo es vocaci\xf3n y la calidad es un est\xe1ndar moral. Hay dignidad en el trabajo honesto. El trabajo es su propia recompensa.",modern:"El gestor de proyectos, el ingeniero de DevOps, el experto en fiabilidad — la persona que hace que todo lo dem\xe1s funcione prestando atenci\xf3n a las cosas de las que nadie m\xe1s quiere ocuparse. Sin glamour e indispensable.",postModern:"El trabajador constante como figura a menudo borrada de las narrativas que celebran la disrupci\xf3n y la innovaci\xf3n. \xbfLa fiabilidad de qui\xe9n sostiene la libertad de qui\xe9n para ser creativo? La resistencia como fen\xf3meno de clase.",metaModern:"Dedicaci\xf3n sin rigidez — trabajo paciente sostenido dentro de la conciencia de que la tierra misma cambia. El caballero que cuida el suelo mientras permanece dispuesto a cambiar de cultivo cuando la estaci\xf3n lo exige."},"page-of-pentacles":{suit:"Pentacles",rank:"page",mbti:"ISFJ",title:"Princesa de las Colinas Resonantes",description:"El Paje de Oros es Tierra de Tierra — la esencia concentrada del potencial material, quieta y estudiosa. Sostiene su moneda a la luz no para presumir sino para comprenderla verdaderamente. Es la estudiante dedicada, la joven aprendiz, la investigadora cuidadosa que quiere aprender el oficio correctamente antes de intentar la maestr\xeda. Pr\xe1ctica, enraizada y genuinamente curiosa sobre c\xf3mo funciona el mundo f\xedsico, representa los primeros pasos cuidadosos hacia la competencia material.",jungian:"La etapa m\xe1s temprana del encuentro del ego con la realidad material — el yo aprendiendo que el mundo tiene su propia l\xf3gica que debe ser respetada antes de poder trabajar con ella. Es la psique descubriendo la disciplina del oficio.",powerGods:"La joven heredera que comprende, quiz\xe1s por primera vez, lo que realmente significa poseer poder en el mundo material. El peso de la moneda. La responsabilidad de lo que puede construirse o despilfarrarse.",traditional:"La aprendiz que se somete a la ense\xf1anza del maestro, la novicia ante el oficio. Humildad ante el conocimiento. El aprendizaje como obligaci\xf3n sagrada. El largo camino de la habilidad genuina.",modern:"La pasante que realmente quiere aprender el negocio desde cero, la estudiante universitaria de primera generaci\xf3n gestionando un presupuesto por primera vez. La emoci\xf3n y el terror de la competencia material emergente.",postModern:"La estudiante cuyo acceso al oficio y al aprendizaje est\xe1 circunscrito por los recursos disponibles para ella. \xbfLa dedicaci\xf3n de qui\xe9n se transforma en habilidad profesional y la de qui\xe9n permanece como aficionada?",metaModern:"La principiante que se acerca a la realidad material con reverencia y curiosidad — comprendiendo que la competencia debe cultivarse, no arrebatarse. La tierra estudiada con la paciencia de quien sabe que la cosecha llegar\xe1."}},ed={Wands:"Ni",Cups:"Se",Swords:"Ne",Pentacles:"Si"},ec={king:{attitude:"E",judging:"T"},queen:{attitude:"E",judging:"F"},knight:{attitude:"I",judging:"T"},page:{attitude:"I",judging:"F"}},eu={ENTJ:{name:"El Comandante",stack:["Ni","Te","Fi","Se"],description:"L\xedderes estrat\xe9gicos impulsados por una visi\xf3n a largo plazo y la acci\xf3n decisiva. Organizan sistemas y personas hacia metas ambiciosas con eficiencia implacable.",courtBridge:"Como el Caballero de Bastos (Thoth), ENTJ canaliza la intuici\xf3n dominante Ni a trav\xe9s del pensamiento extravertido — la voluntad ardiente que comanda mediante estrategia visionaria en lugar de fuerza bruta."},ENFJ:{name:"El Protagonista",stack:["Ni","Fe","Ti","Se"],description:"Idealistas carism\xe1ticos que inspiran y gu\xedan a otros hacia el crecimiento. Perciben lo que las personas necesitan y crean las condiciones para el florecimiento colectivo.",courtBridge:"Como la Reina de Bastos, ENFJ empu\xf1a la intuici\xf3n dominante Ni a trav\xe9s del sentimiento extravertido — la calidez radiante que atrae a otros hacia una visi\xf3n compartida y los sostiene all\xed con cuidado genuino."},INTJ:{name:"El Arquitecto",stack:["Ni","Te","Fi","Se"],description:"Estrategas independientes que ven patrones que otros no perciben. Construyen modelos internos complejos de la realidad y persiguen su visi\xf3n con determinaci\xf3n silenciosa e implacable.",courtBridge:"Como el Pr\xedncipe de Bastos (Thoth), INTJ encarna la intuici\xf3n dominante Ni procesada a trav\xe9s del pensamiento introvertido — el fuego interior que se mueve hacia afuera como fuerza intelectual y perspicacia sist\xe9mica."},INFJ:{name:"El Abogado",stack:["Ni","Fe","Ti","Se"],description:"Emp\xe1ticos visionarios que buscan un significado profundo y trabajan silenciosamente hacia sus ideales. Comprenden a las personas a un nivel que puede parecer casi ps\xedquico, impulsados por un sentido de prop\xf3sito mayor que ellos mismos.",courtBridge:"Como la Princesa de Bastos (Thoth), INFJ sostiene la intuici\xf3n dominante Ni en su forma m\xe1s interior y portadora de potencial — la chispa antes de convertirse en llama, la visi\xf3n a\xfan reuniendo su fuerza creativa."},ESTP:{name:"El Emprendedor",stack:["Se","Ti","Fe","Ni"],description:"Pragm\xe1ticos audaces que prosperan en el momento presente. Leen las situaciones al instante, toman acciones decisivas y se adaptan sobre la marcha con facilidad y confianza.",courtBridge:"Como el Caballero de Copas (Thoth), ESTP canaliza la sensaci\xf3n dominante Se a trav\xe9s del pensamiento extravertido — el dominio de las corrientes emocionales y sensoriales ejercido con autoridad imponente."},ESFP:{name:"El Animador",stack:["Se","Fi","Te","Ni"],description:"Experiencialistas vivaces que aportan calidez y espontaneidad donde quiera que vayan. Viven a trav\xe9s del contacto sensorial directo y comparten esa vitalidad generosamente.",courtBridge:"Como la Reina de Copas, ESFP expresa la sensaci\xf3n dominante Se a trav\xe9s del sentimiento extravertido — receptividad emocional pura y viva en el momento presente, reflejando belleza y sentimiento al mundo."},ISTP:{name:"El Virtuoso",stack:["Se","Ti","Fe","Ni"],description:"Analistas serenos que comprenden los sistemas a trav\xe9s del contacto directo. Desarman las cosas para ver c\xf3mo funcionan y responden a las crisis con precisi\xf3n calmada.",courtBridge:"Como el Pr\xedncipe de Copas (Thoth), ISTP mueve la sensaci\xf3n dominante Se a trav\xe9s del pensamiento introvertido — el idealismo rom\xe1ntico del agua procesado a trav\xe9s de un an\xe1lisis elegante y desapegado."},ISFP:{name:"El Aventurero",stack:["Se","Fi","Te","Ni"],description:"Artistas gentiles que experimentan el mundo a trav\xe9s de una rica paleta interior de valores y est\xe9tica. Viven con autenticidad, guiados por un sentimiento personal profundo en lugar de expectativas externas.",courtBridge:"Como la Princesa de Copas (Thoth), ISFP sostiene la sensaci\xf3n dominante Se en su forma m\xe1s tierna e indefensa — el coraz\xf3n abierto que recibe el mundo como belleza y lo traduce en expresi\xf3n creativa silenciosa."},ENTP:{name:"El Polemista",stack:["Ne","Ti","Fe","Si"],description:"Provocadores inventivos que ven posibilidades en todas partes y cuestionan cada suposici\xf3n. Generan ideas a gran velocidad y prosperan en el debate intelectual.",courtBridge:"Como el Caballero de Espadas (Thoth), ENTP canaliza la intuici\xf3n dominante Ne a trav\xe9s del pensamiento extravertido — el intelecto feroz que comanda mediante la fuerza del argumento y la claridad del an\xe1lisis."},ENFP:{name:"El Activista",stack:["Ne","Fi","Te","Si"],description:"Visionarios entusiastas que conectan ideas, personas y posibilidades en narrativas inspiradoras. Defienden causas con optimismo contagioso y calidez genuina.",courtBridge:"Como la Reina de Espadas, ENFP expresa la intuici\xf3n dominante Ne a trav\xe9s del sentimiento extravertido — la claridad perceptiva nacida de la experiencia profunda, empu\xf1ando la honestidad como un acto de compasi\xf3n."},INTP:{name:"El L\xf3gico",stack:["Ne","Ti","Fe","Si"],description:"Pensadores abstractos que construyen marcos te\xf3ricos intrincados. Persiguen la consistencia l\xf3gica con intensidad silenciosa, siempre refinando su comprensi\xf3n de c\xf3mo funcionan las cosas.",courtBridge:"Como el Pr\xedncipe de Espadas (Thoth), INTP mueve la intuici\xf3n dominante Ne a trav\xe9s del pensamiento introvertido — la tormenta del intelecto puro, brillante e imparable en su b\xfasqueda de la verdad."},INFP:{name:"El Mediador",stack:["Ne","Fi","Te","Si"],description:"So\xf1adores idealistas guiados por valores profundamente arraigados. Buscan autenticidad y significado, a menudo expresando su rico mundo interior a trav\xe9s de la acci\xf3n creativa y compasiva.",courtBridge:"Como la Princesa de Espadas (Thoth), INFP sostiene la intuici\xf3n dominante Ne en su forma m\xe1s alerta y vigilante — la mente curiosa reuniendo impresiones antes de comprometerse, vigilante y lista para actuar."},ESTJ:{name:"El Ejecutivo",stack:["Si","Te","Fi","Ne"],description:"Administradores organizados que construyen y mantienen sistemas confiables. Valoran la tradici\xf3n, la responsabilidad y las cadenas de mando claras, liderando mediante el ejemplo consistente.",courtBridge:"Como el Caballero de Oros (Thoth), ESTJ canaliza la sensaci\xf3n dominante Si a trav\xe9s del pensamiento extravertido — el dominio del mundo material expresado como mayordom\xeda autoritativa y sabidur\xeda pr\xe1ctica."},ESFJ:{name:"El C\xf3nsul",stack:["Si","Fe","Ti","Ne"],description:"Constructores de comunidad c\xe1lidos que crean armon\xeda y aseguran que todos sean atendidos. Honran las tradiciones, recuerdan los detalles y sostienen el tejido social con atenci\xf3n devota.",courtBridge:"Como la Reina de Oros, ESFJ expresa la sensaci\xf3n dominante Si a trav\xe9s del sentimiento extravertido — la abundancia nutricia que cuida cuerpos, tierra y almas con cuidado sensual y encarnado."},ISTJ:{name:"El Log\xedstico",stack:["Si","Te","Fi","Ne"],description:"Realistas confiables que honran el deber y cumplen con cuidado meticuloso. Construyen estructuras duraderas a trav\xe9s del esfuerzo paciente y met\xf3dico y un compromiso inquebrantable.",courtBridge:"Como el Pr\xedncipe de Oros (Thoth), ISTJ mueve la sensaci\xf3n dominante Si a trav\xe9s del pensamiento introvertido — el artesano diligente que inspecciona, planifica y construye con absoluta minuciosidad."},ISFJ:{name:"El Defensor",stack:["Si","Fe","Ti","Ne"],description:"Protectores silenciosos que recuerdan lo que importa y trabajan incansablemente tras bambalinas. Preservan lo valioso, apoyan a quienes aman y abordan el aprendizaje con dedicaci\xf3n humilde.",courtBridge:"Como la Princesa de Oros (Thoth), ISFJ sostiene la sensaci\xf3n dominante Si en su forma m\xe1s estudiosa y portadora de potencial — la aprendiz cuidadosa que quiere comprender el oficio antes de intentar la maestr\xeda."}};function eh(e,a){let o=ed[e],{attitude:i,judging:n}=ec[a],t="S"===o.charAt(0)?"S":"N";return"".concat(i).concat(t).concat(n).concat("Si"===o||"Ni"===o?"J":"P")}let em={en:{cards:i,astrology:b,planets:v,signs:w,court:n,mbti:t},es:{cards:r,astrology:s,planets:l,signs:d,court:c,mbti:u}};function ep(e,a){var o;return(null===(o=em[e])||void 0===o?void 0:o[a])||em.en[a]}function eg(){return ep((0,h.b)(),"cards")}function ef(){return ep((0,h.b)(),"astrology")}function ey(){return ep((0,h.b)(),"planets")}function eb(){return ep((0,h.b)(),"signs")}function ev(){return ep((0,h.b)(),"court")}function ew(){return ep((0,h.b)(),"mbti")}},8231:function(e,a,o){o.d(a,{N:function(){return t}});var i=o(5014);let n={en:JSON.parse('{"metadata":{"title":"Whimsey Tarot - Golden Dawn Study","description":"Study the Golden Dawn system through tarot, astrology, and planetary correspondences"},"nav":{"decan":"Decan","court":"Court","signs":"Signs","planets":"Planets","comingSoon":"Coming soon"},"deckSwitcher":{"rwsTitle":"Rider-Waite-Smith deck","thothTitle":"Thoth deck"},"common":{"loading":"Loading...","viewOnGithub":"View on GitHub","whimseyTarot":"Whimsey Tarot","backToPlanetaryTable":"Back to Planetary Table"},"labels":{"names":"Names","cardMeaning":"Card Meaning","jungianInterpretation":"Jungian Interpretation","powerGods":"Power Gods (Red)","traditional":"Traditional (Amber)","modern":"Modern (Orange)","postModern":"Post-Modern (Green)","metaModern":"Meta-Modern (Teal)","zodiacSign":"Zodiac Sign","governingPlanet":"Governing Planet","numberSignificance":"Number Significance","suitElement":"Suit Element","suit":"Suit","rank":"Rank","elementalFormula":"Elemental Formula","elementalCombination":"Elemental Combination","rankElement":"Rank Element","mbtiType":"MBTI Personality Type","cognitiveStack":"Cognitive Function Stack","mbtiCourtBridge":"MBTI ↔ Court Card","dates":"Dates","numerology":"Numerology","rulingPlanet":"Ruling Planet","modality":"Modality","element":"Element","na":"N/A"},"decanPage":{"subtitle":"Learn Your Lordly Title by Astrological Sign","description":"The twelve zodiac signs are grouped into four elements, each corresponding to a tarot suit. Each sign contains three decans, represented by the numbered cards of their respective suit.","suitLabel":"Suit:"},"courtPage":{"subtitle":"Court Cards","description":"The sixteen court cards represent the elemental aspects of each suit as embodied in human archetypes. Each is both Fire, Water, Air, or Earth <em>of</em> their suit\'s element — a specific facet of a greater elemental whole.","of":"of","rankSuit":"{rank} rank \xb7 {suit} suit","elementOfElement":"As {rankEl} of {suitEl}, this figure embodies the {rankElLower} quality applied to the {suitElLower} realm —","fireRankDescription":"the active, projective will driving the suit\'s force forward with authority and initiative.","waterRankDescription":"the receptive, feeling dimension giving the suit\'s force depth, empathy, and internal resonance.","airRankDescription":"the thinking, communicative aspect carrying the suit\'s force outward through ideas and swift movement.","earthRankDescription":"the grounding, material aspect holding the suit\'s force in latent potential, ready to be cultivated into form."},"signsPage":{"subtitle":"Major Arcana by Zodiac Sign","description":"Each of the twelve zodiac signs is attributed a Major Arcana card in the Golden Dawn system. These trump cards embody the archetypal qualities of their corresponding signs."},"planetsPage":{"title":"The Chaldean Planetary Order","subtitle":"From the Sphere of the Fixed Stars to the Sublunary Realm","tableHeaders":{"planet":"Planet","primaryMeaning":"Primary Meaning","poeticPointer":"Poetic Pointer","firstSignRuled":"First Sign Ruled","influenceOnFirstSign":"Influence on First Sign","secondSignRuled":"Second Sign Ruled","influenceOnSecondSign":"Influence on Second Sign"},"quote":"\\"As above, so below; as within, so without.\\"","quoteSubtext":"The Seven Sacred Wanderers in their celestial dance","clickPrompt":"Click on any planet to explore its detailed Golden Dawn correspondences","noSignsRuled":"No signs ruled in traditional system","coreAttributes":"Core Attributes","chaldeanPosition":"Chaldean Position:","ofSacredWanderers":"of 7 Sacred Wanderers","hebrewLetter":"Hebrew Letter:","number":"Number:","metal":"Metal:","day":"Day:","colors":"Colors","queenScale":"Queen Scale:","kingScale":"King Scale:","emperorScale":"Emperor Scale:","magicalImage":"Magical Image","esotericMeaning":"Esoteric Meaning","signsRuled":"Signs Ruled","essentialDignities":"Essential Dignities","domicile":"Domicile:","exaltation":"Exaltation:","detriment":"Detriment:","fall":"Fall:","tarotAssociations":"Tarot Associations","majorArcana":"Major Arcana","minorArcana":"Minor Arcana","keywords":"Keywords"}}'),es:JSON.parse('{"metadata":{"title":"Whimsey Tarot - Estudio de la Golden Dawn","description":"Estudia el sistema de la Golden Dawn a trav\xe9s del tarot, la astrolog\xeda y las correspondencias planetarias"},"nav":{"decan":"Decano","court":"Corte","signs":"Signos","planets":"Planetas","comingSoon":"Pr\xf3ximamente"},"deckSwitcher":{"rwsTitle":"Baraja Rider-Waite-Smith","thothTitle":"Baraja Thoth"},"common":{"loading":"Cargando...","viewOnGithub":"Ver en GitHub","whimseyTarot":"Whimsey Tarot","backToPlanetaryTable":"Volver a la Tabla Planetaria"},"labels":{"names":"Nombres","cardMeaning":"Significado de la Carta","jungianInterpretation":"Interpretaci\xf3n Junguiana","powerGods":"Dioses del Poder (Rojo)","traditional":"Tradicional (\xc1mbar)","modern":"Moderno (Naranja)","postModern":"Post-Moderno (Verde)","metaModern":"Meta-Moderno (Turquesa)","zodiacSign":"Signo Zodiacal","governingPlanet":"Planeta Regente","numberSignificance":"Significado del N\xfamero","suitElement":"Elemento del Palo","suit":"Palo","rank":"Rango","elementalFormula":"F\xf3rmula Elemental","elementalCombination":"Combinaci\xf3n Elemental","rankElement":"Elemento del Rango","mbtiType":"Tipo de Personalidad MBTI","cognitiveStack":"Pila de Funciones Cognitivas","mbtiCourtBridge":"MBTI ↔ Carta de Corte","dates":"Fechas","numerology":"Numerolog\xeda","rulingPlanet":"Planeta Regente","modality":"Modalidad","element":"Elemento","na":"N/A"},"decanPage":{"subtitle":"Aprende Tu T\xedtulo Se\xf1orial por Signo Astrol\xf3gico","description":"Los doce signos del zod\xedaco se agrupan en cuatro elementos, cada uno correspondiente a un palo del tarot. Cada signo contiene tres decanos, representados por las cartas numeradas de su palo respectivo.","suitLabel":"Palo:"},"courtPage":{"subtitle":"Cartas de la Corte","description":"Las diecis\xe9is cartas de la corte representan los aspectos elementales de cada palo encarnados en arquetipos humanos. Cada una es tanto Fuego, Agua, Aire o Tierra <em>de</em> su elemento de palo — una faceta espec\xedfica de un todo elemental mayor.","of":"de","rankSuit":"rango {rank} \xb7 palo {suit}","elementOfElement":"Como {rankEl} de {suitEl}, esta figura encarna la cualidad de {rankElLower} aplicada al reino de {suitElLower} —","fireRankDescription":"la voluntad activa y proyectiva que impulsa la fuerza del palo hacia adelante con autoridad e iniciativa.","waterRankDescription":"la dimensi\xf3n receptiva y emocional que da profundidad, empat\xeda y resonancia interna a la fuerza del palo.","airRankDescription":"el aspecto pensante y comunicativo que lleva la fuerza del palo hacia afuera a trav\xe9s de ideas y movimiento r\xe1pido.","earthRankDescription":"el aspecto material y enraizante que mantiene la fuerza del palo en potencial latente, listo para ser cultivado en forma."},"signsPage":{"subtitle":"Arcanos Mayores por Signo Zodiacal","description":"Cada uno de los doce signos del zod\xedaco tiene atribuida una carta de Arcano Mayor en el sistema de la Golden Dawn. Estas cartas de triunfo encarnan las cualidades arquet\xedpicas de sus signos correspondientes."},"planetsPage":{"title":"El Orden Planetario Caldeo","subtitle":"Desde la Esfera de las Estrellas Fijas hasta el Reino Sublunar","tableHeaders":{"planet":"Planeta","primaryMeaning":"Significado Principal","poeticPointer":"Se\xf1al Po\xe9tica","firstSignRuled":"Primer Signo Regido","influenceOnFirstSign":"Influencia en el Primer Signo","secondSignRuled":"Segundo Signo Regido","influenceOnSecondSign":"Influencia en el Segundo Signo"},"quote":"\\"Como es arriba, es abajo; como es adentro, es afuera.\\"","quoteSubtext":"Los Siete Errantes Sagrados en su danza celestial","clickPrompt":"Haz clic en cualquier planeta para explorar sus correspondencias detalladas de la Golden Dawn","noSignsRuled":"No rige signos en el sistema tradicional","coreAttributes":"Atributos Fundamentales","chaldeanPosition":"Posici\xf3n Caldea:","ofSacredWanderers":"de 7 Errantes Sagrados","hebrewLetter":"Letra Hebrea:","number":"N\xfamero:","metal":"Metal:","day":"D\xeda:","colors":"Colores","queenScale":"Escala de la Reina:","kingScale":"Escala del Rey:","emperorScale":"Escala del Emperador:","magicalImage":"Imagen M\xe1gica","esotericMeaning":"Significado Esot\xe9rico","signsRuled":"Signos Regidos","essentialDignities":"Dignidades Esenciales","domicile":"Domicilio:","exaltation":"Exaltaci\xf3n:","detriment":"Detrimento:","fall":"Ca\xedda:","tarotAssociations":"Asociaciones del Tarot","majorArcana":"Arcanos Mayores","minorArcana":"Arcanos Menores","keywords":"Palabras Clave"}}')};function t(){return n[(0,i.b)()]||n.en}},7157:function(e,a,o){o.r(a),o.d(a,{elements:function(){return r},zodiacDescriptions:function(){return n},zodiacElements:function(){return t},zodiacSymbols:function(){return i}});let i={Aries:"♈︎",Taurus:"♉︎",Gemini:"♊︎",Cancer:"♋︎",Leo:"♌︎",Virgo:"♍︎",Libra:"♎︎",Scorpio:"♏︎",Sagittarius:"♐︎",Capricorn:"♑︎",Aquarius:"♒︎",Pisces:"♓︎"},n={Aries:"The Ram - A cardinal fire sign ruled by Mars, representing initiative and leadership. Aries natives are typically confident, energetic, and adventurous. They are natural-born leaders who love challenges, display remarkable courage, and tend to be straightforward in their approach. However, they can also be impulsive and quick-tempered.",Taurus:"The Bull - A fixed earth sign ruled by Venus, representing stability and sensuality. Taurus individuals are known for their reliability, patience, and determination. They have a strong appreciation for comfort and luxury, are deeply connected to nature, and make loyal friends. They can be stubborn at times but are excellent at building long-term security.",Gemini:"The Twins - A mutable air sign ruled by Mercury, representing communication and adaptability. Geminis are curious, versatile, and intellectually driven. They excel at multitasking, are great conversationalists, and have a witty sense of humor. While they can be perceived as inconsistent, their adaptability is their greatest strength.",Cancer:"The Crab - A cardinal water sign ruled by the Moon, representing nurturing and emotional depth. Cancerians are deeply intuitive, protective, and empathetic. They value home and family above all, have excellent memory, and are natural caregivers. Though sometimes moody, they are fiercely loyal to loved ones.",Leo:"The Lion - A fixed fire sign ruled by the Sun, representing creativity and self-expression. Leos are natural performers, generous, and warm-hearted. They possess strong leadership qualities, are incredibly creative, and have a flair for drama. While they can be prideful, their loyalty and charisma make them magnetic personalities.",Virgo:"The Virgin - A mutable earth sign ruled by Mercury, representing analysis and perfectionism. Virgos are methodical, practical, and detail-oriented. They have a strong work ethic, are excellent problem-solvers, and have a genuine desire to help others. Though they may be overly critical, their analytical skills are unmatched.",Libra:"The Scales - A cardinal air sign ruled by Venus, representing harmony and relationships. Librans are diplomatic, charming, and peace-loving. They have a strong sense of justice, appreciate beauty in all forms, and excel at mediating conflicts. While they can be indecisive, their ability to see all sides of an issue is invaluable.",Scorpio:"The Scorpion - A fixed water sign ruled by Mars/Pluto, representing transformation and intensity. Scorpios are passionate, resourceful, and deeply perceptive. They possess strong investigative abilities, are fiercely loyal, and have powerful emotional depth. Though sometimes secretive, their determination and resilience are remarkable.",Sagittarius:"The Archer - A mutable fire sign ruled by Jupiter, representing exploration and wisdom. Sagittarians are optimistic, adventurous, and philosophical. They love to travel, learn about different cultures, and share their knowledge with others. While they can be blunt, their enthusiasm and honesty are refreshing.",Capricorn:"The Sea-Goat - A cardinal earth sign ruled by Saturn, representing ambition and discipline. Capricorns are responsible, patient, and goal-oriented. They have excellent organizational skills, strong work ethic, and natural business acumen. Though they may seem reserved, their dry humor and determination make them successful.",Aquarius:"The Water Bearer - A fixed air sign ruled by Saturn/Uranus, representing innovation and community. Aquarians are progressive, original, and humanitarian. They are forward-thinking, value independence, and often champion social causes. While they can appear detached, their visionary ideas and uniqueness make them natural innovators.",Pisces:"The Fish - A mutable water sign ruled by Jupiter/Neptune, representing imagination and spirituality. Pisceans are compassionate, artistic, and highly intuitive. They have rich creative abilities, deep empathy, and a strong connection to the spiritual realm. Though they can be escapist at times, their artistic sensitivity and healing nature are gifts."},t={Aries:{element:"Fire",suit:"Wands"},Leo:{element:"Fire",suit:"Wands"},Sagittarius:{element:"Fire",suit:"Wands"},Taurus:{element:"Earth",suit:"Pentacles"},Virgo:{element:"Earth",suit:"Pentacles"},Capricorn:{element:"Earth",suit:"Pentacles"},Gemini:{element:"Air",suit:"Swords"},Libra:{element:"Air",suit:"Swords"},Aquarius:{element:"Air",suit:"Swords"},Cancer:{element:"Water",suit:"Cups"},Scorpio:{element:"Water",suit:"Cups"},Pisces:{element:"Water",suit:"Cups"}},r={Fire:{signs:["Aries","Leo","Sagittarius"],description:"Energy, passion, and creativity"},Earth:{signs:["Taurus","Virgo","Capricorn"],description:"Stability, practicality, and material world"},Air:{signs:["Gemini","Libra","Aquarius"],description:"Intellect, communication, and ideas"},Water:{signs:["Cancer","Scorpio","Pisces"],description:"Emotions, intuition, and relationships"}}},8358:function(e,a,o){o.r(a),o.d(a,{chaldeanOrder:function(){return n},getPlanetBySlug:function(){return r},getPlanetsInChaldeanOrder:function(){return s},planetSymbols:function(){return i},planetsData:function(){return t}});let i={Saturn:"♄",Jupiter:"♃",Mars:"♂",Sun:"☉",Venus:"♀",Mercury:"☿",Moon:"☽"},n=["Saturn","Jupiter","Mars","Sun","Venus","Mercury","Moon"],t={Saturn:{name:"Saturn",symbol:"♄",chaldeanPosition:1,primaryMeaning:"Containment, boundary, form, time",poeticPointer:"The edge that lets you know yourself",hebrewLetter:"ט (Teth)",number:9,tarotCards:{major:["The World (XXI)"],minor:[{card:"7 of Pentacles",title:"Success Unfulfilled",link:"#taurus-3"},{card:"5 of Wands",title:"Strife",link:"#leo-1"},{card:"3 of Swords",title:"Sorrow",link:"#libra-2"},{card:"10 of Wands",title:"Oppression",link:"#sagittarius-3"},{card:"8 of Cups",title:"Abandoned Success",link:"#pisces-1"}]},signsRuled:[{sign:"Capricorn",mode:"Cardinal Earth",influence:"Builds the mountain through disciplined ascent—structure that endures"},{sign:"Aquarius",mode:"Fixed Air",influence:"Holds the pattern of the collective—the crystallized ideal"}],colors:{queen:"Indigo",king:"Black",emperor:"Blue-black"},magicalImage:"A reaping man, aged and bent; or a tall dark figure with a scythe",zodiacSymbol:"The Goat, The Water-Bearer",metal:"Lead",day:"Saturday",description:"Saturn represents the principle of limitation and structure. It is the boundary that defines form, the teacher through restriction, and the wisdom gained through time and patience. In the Golden Dawn system, Saturn governs the sphere of Binah on the Tree of Life, representing Understanding through form.",keywords:["Limitation","Structure","Time","Karma","Discipline","Responsibility","Boundaries","Crystallization","Form","Maturity"],inDignity:{domicile:["Capricorn","Aquarius"],exaltation:"Libra",detriment:["Cancer","Leo"],fall:"Aries"}},Jupiter:{name:"Jupiter",symbol:"♃",chaldeanPosition:2,primaryMeaning:"Expansion, possibility, abundance, meaning",poeticPointer:"The yes that opens doors",hebrewLetter:"כ (Kaph)",number:10,tarotCards:{major:["Wheel of Fortune (X)"],minor:[{card:"8 of Swords",title:"Shortened Force",link:"#gemini-1"},{card:"6 of Wands",title:"Victory",link:"#leo-2"},{card:"4 of Swords",title:"Rest from Strife",link:"#libra-3"},{card:"2 of Pentacles",title:"Harmonious Change",link:"#capricorn-1"},{card:"9 of Cups",title:"Material Happiness",link:"#pisces-2"}]},signsRuled:[{sign:"Sagittarius",mode:"Mutable Fire",influence:"Seeks the horizon—expansive questing for truth and meaning"},{sign:"Pisces",mode:"Mutable Water",influence:"Dissolves into the ocean—boundless compassion and unity"}],colors:{queen:"Blue",king:"Violet",emperor:"Deep purple"},magicalImage:"A crowned and mighty king upon his throne; or a bishop with staff and mitre",zodiacSymbol:"The Archer, The Fishes",metal:"Tin",day:"Thursday",description:"Jupiter embodies expansion, growth, and benevolence. It is the principle of increase, optimism, and the search for meaning. Associated with Chesed on the Tree of Life, Jupiter represents Mercy and the generous overflow of abundance.",keywords:["Expansion","Growth","Abundance","Wisdom","Optimism","Generosity","Faith","Philosophy","Luck","Benevolence"],inDignity:{domicile:["Sagittarius","Pisces"],exaltation:"Cancer",detriment:["Gemini","Virgo"],fall:"Capricorn"}},Mars:{name:"Mars",symbol:"♂",chaldeanPosition:3,primaryMeaning:"Will, severance, directed energy, assertion",poeticPointer:"The sword that chooses",hebrewLetter:"פ (Peh)",number:16,tarotCards:{major:["The Tower (XVI)"],minor:[{card:"2 of Wands",title:"Dominion",link:"#aries-1"},{card:"9 of Swords",title:"Despair and Cruelty",link:"#gemini-2"},{card:"5 of Cups",title:"Loss in Pleasure",link:"#scorpio-1"},{card:"7 of Wands",title:"Valor",link:"#leo-3"},{card:"3 of Pentacles",title:"Material Works",link:"#capricorn-2"},{card:"10 of Cups",title:"Perpetual Success",link:"#pisces-3"}]},signsRuled:[{sign:"Aries",mode:"Cardinal Fire",influence:'Pure initiation—"I want, I act, I AM first"'},{sign:"Scorpio",mode:"Fixed Water",influence:"Deep penetration—will that transforms through intensity"}],colors:{queen:"Red",king:"Scarlet",emperor:"Brilliant flame"},magicalImage:"A warrior armed and crowned, riding upon a wolf",zodiacSymbol:"The Ram, The Scorpion",metal:"Iron",day:"Tuesday",description:"Mars is the principle of assertion, action, and directed will. It represents the cutting edge that separates and defines through conflict and conquest. In the Golden Dawn tradition, Mars governs Geburah—Severity and strength through the application of force.",keywords:["Action","Assertion","Courage","Conflict","Energy","Desire","Aggression","Initiative","Severance","Will"],inDignity:{domicile:["Aries","Scorpio"],exaltation:"Capricorn",detriment:["Libra","Taurus"],fall:"Cancer"}},Sun:{name:"Sun",symbol:"☉",chaldeanPosition:4,primaryMeaning:"Center, identity, radiance, authority",poeticPointer:"The light that needs no reason",hebrewLetter:"ר (Resh)",number:19,tarotCards:{major:["The Sun (XIX)"],minor:[{card:"3 of Wands",title:"Established Strength",link:"#aries-2"},{card:"10 of Swords",title:"Ruin",link:"#gemini-3"},{card:"6 of Cups",title:"Pleasure",link:"#scorpio-2"},{card:"8 of Pentacles",title:"Prudence",link:"#virgo-1"},{card:"4 of Pentacles",title:"Earthly Power",link:"#capricorn-3"}]},signsRuled:[{sign:"Leo",mode:"Fixed Fire",influence:"Steady sovereignty—the king who simply shines"}],colors:{queen:"Gold-Yellow",king:"Rich amber",emperor:"Gold"},magicalImage:"A king upon a throne crowned and sceptered",zodiacSymbol:"The Lion",metal:"Gold",day:"Sunday",description:"The Sun represents the core of individual identity, the source of vitality and creative power. It is the central organizing principle around which all else revolves. Associated with Tiphareth—Beauty—on the Tree of Life, the Sun harmonizes all forces in perfect balance.",keywords:["Identity","Vitality","Consciousness","Authority","Center","Radiance","Life-force","Self-expression","Sovereignty","Integration"],inDignity:{domicile:["Leo"],exaltation:"Aries",detriment:["Aquarius"],fall:"Libra"}},Venus:{name:"Venus",symbol:"♀",chaldeanPosition:5,primaryMeaning:"Attraction, value, harmony, relationship",poeticPointer:"The pull of what pleases",hebrewLetter:"ד (Daleth)",number:3,tarotCards:{major:["The Empress (III)"],minor:[{card:"4 of Wands",title:"Perfected Work",link:"#aries-3"},{card:"2 of Cups",title:"Love",link:"#cancer-1"},{card:"7 of Cups",title:"Illusionary Success",link:"#scorpio-3"},{card:"9 of Pentacles",title:"Material Gain",link:"#virgo-2"},{card:"5 of Swords",title:"Defeat",link:"#aquarius-1"}]},signsRuled:[{sign:"Taurus",mode:"Fixed Earth",influence:"Sensual rootedness—embodied pleasure that stays"},{sign:"Libra",mode:"Cardinal Air",influence:"Relational grace—initiating harmony through balance"}],colors:{queen:"Emerald Green",king:"Sky blue",emperor:"Early spring green"},magicalImage:"A beautiful naked woman, or a fair maiden crowned",zodiacSymbol:"The Bull, The Scales",metal:"Copper",day:"Friday",description:"Venus embodies the principle of attraction, desire, and value. It draws together what resonates, creating harmony through relationship. Venus governs Netzach—Victory—on the Tree of Life, representing the triumph of love and beauty.",keywords:["Attraction","Love","Beauty","Harmony","Value","Pleasure","Art","Relationship","Desire","Grace"],inDignity:{domicile:["Taurus","Libra"],exaltation:"Pisces",detriment:["Scorpio","Aries"],fall:"Virgo"}},Mercury:{name:"Mercury",symbol:"☿",chaldeanPosition:6,primaryMeaning:"Connection, translation, exchange, movement",poeticPointer:"The bridge between islands",hebrewLetter:"ב (Beth)",number:1,tarotCards:{major:["The Magician (I)"],minor:[{card:"5 of Pentacles",title:"Material Trouble",link:"#taurus-1"},{card:"3 of Cups",title:"Abundance",link:"#cancer-2"},{card:"8 of Wands",title:"Swiftness",link:"#sagittarius-1"},{card:"10 of Pentacles",title:"Wealth",link:"#virgo-3"},{card:"6 of Swords",title:"Earned Success",link:"#aquarius-2"}]},signsRuled:[{sign:"Gemini",mode:"Mutable Air",influence:"Quick mental weaving—ideas dancing and connecting"},{sign:"Virgo",mode:"Mutable Earth",influence:"Practical discrimination—organizing matter with precision"}],colors:{queen:"Orange",king:"Purple",emperor:"Violet-purple"},magicalImage:"A beautiful youth, sometimes winged, bearing a caduceus entwined with serpents",zodiacSymbol:"The Twins, The Virgin",metal:"Quicksilver (Mercury)",day:"Wednesday",description:"Mercury represents communication, intellect, and the exchange of information. It is the messenger between realms, the translator of experience into thought and word. Associated with Hod—Splendor—Mercury brings the power of mind and reason.",keywords:["Communication","Intelligence","Connection","Exchange","Thought","Learning","Adaptability","Translation","Movement","Discrimination"],inDignity:{domicile:["Gemini","Virgo"],exaltation:"Virgo",detriment:["Sagittarius","Pisces"],fall:"Pisces"}},Moon:{name:"Moon",symbol:"☽",chaldeanPosition:7,primaryMeaning:"Reflection, rhythm, memory, responsiveness",poeticPointer:"The mirror that remembers",hebrewLetter:"ג (Gimel)",number:2,tarotCards:{major:["The High Priestess (II)","The Moon (XVIII)"],minor:[{card:"6 of Pentacles",title:"Material Success",link:"#taurus-2"},{card:"4 of Cups",title:"Luxury",link:"#cancer-3"},{card:"9 of Wands",title:"Great Strength",link:"#sagittarius-2"},{card:"2 of Swords",title:"Peace Restored",link:"#libra-1"},{card:"7 of Swords",title:"Unstable Effort",link:"#aquarius-3"}]},signsRuled:[{sign:"Cancer",mode:"Cardinal Water",influence:"Nurturing initiation—responding with protective care"}],colors:{queen:"Silver",king:"Cold pale blue",emperor:"Silver-white"},magicalImage:"A beautiful maiden, or a huntress with bow and arrows",zodiacSymbol:"The Crab",metal:"Silver",day:"Monday",description:"The Moon represents the tides of emotion, the rhythm of change, and the receptive feminine principle. It reflects light rather than generating it, showing us the world of shadow, dream, and subconscious memory. The Moon governs Yesod—Foundation—the astral substrate underlying physical reality.",keywords:["Emotion","Intuition","Cycles","Memory","Reflection","Subconscious","Receptivity","Nurture","Fluctuation","Dreams"],inDignity:{domicile:["Cancer"],exaltation:"Taurus",detriment:["Capricorn"],fall:"Scorpio"}}};function r(e){return t[e.charAt(0).toUpperCase()+e.slice(1).toLowerCase()]||null}function s(){return n.map(e=>({...t[e],slug:e.toLowerCase()}))}},5162:function(e,a,o){o.r(a),o.d(a,{modalityDescriptions:function(){return t},numerologyMeanings:function(){return i},signsCardData:function(){return l},signsDates:function(){return s},signsModality:function(){return n},signsRulingPlanet:function(){return r}});let i={1:"The number of origins and singular will. One is the undivided whole before differentiation—pure consciousness, the first cause, the creative force that needs no other to exist. It speaks to self-origination, leadership, and the power that arises from complete self-sufficiency.",2:"The number of duality, partnership, and choice. Two represents balance, cooperation, and the interaction between opposing forces. It speaks to decisions, relationships, and the need to find harmony between different aspects.",3:"The number of creation and growth. Three represents the synthesis of opposing forces creating something new. It speaks to creativity, self-expression, collaboration, and the manifestation of ideas into form.",4:"The number of stability and foundation. Four represents order, structure, and solid foundations. It speaks to manifestation in the material world, establishing boundaries, and creating lasting security.",5:"The number of change and disruption. Five represents instability, conflict, and necessary changes. It speaks to freedom, adventure, and the challenges that lead to growth and learning.",6:"The number of harmony and balance. Six represents equilibrium, love, and beauty. It speaks to nurturing, healing, responsibility, and finding solutions that benefit all.",7:"The number of wisdom and spirituality. Seven represents inner knowing, analysis, and spiritual awareness. It speaks to seeking deeper truth, introspection, and understanding beyond the material.",8:"The number of power and manifestation. Eight represents material success, authority, and personal power. It speaks to achievement, strength, and the ability to make things happen in the physical world.",9:"The number of completion and fulfillment. Nine represents achievement, culmination, and wisdom gained through experience. It speaks to reaching goals, spiritual awareness, and preparing for new cycles."},n={Aries:"Cardinal",Taurus:"Fixed",Gemini:"Mutable",Cancer:"Cardinal",Leo:"Fixed",Virgo:"Mutable",Libra:"Cardinal",Scorpio:"Fixed",Sagittarius:"Mutable",Capricorn:"Cardinal",Aquarius:"Fixed",Pisces:"Mutable"},t={Cardinal:"Cardinal signs initiate each new season—Aries (Spring), Cancer (Summer), Libra (Autumn), Capricorn (Winter). They embody the principle of beginning: energetic, ambitious, and oriented toward launching new cycles. Cardinal energy is the spark that starts fires, the idea that becomes action, the impulse that sets everything in motion.",Fixed:"Fixed signs occupy the height of each season—Taurus, Leo, Scorpio, Aquarius. They embody the principle of concentration: persistent, determined, and oriented toward sustaining what has been established. Fixed energy is the will that keeps the fire burning, the loyalty that deepens roots, the intensity that refuses to abandon what has begun.",Mutable:"Mutable signs close each season—Gemini, Virgo, Sagittarius, Pisces. They embody the principle of transition: adaptable, versatile, and oriented toward preparing the ground for what comes next. Mutable energy is the wisdom that knows when to release, the flexibility that finds the thread of continuity across change, the grace that makes endings into beginnings."},r={Aries:"Mars",Taurus:"Venus",Gemini:"Mercury",Cancer:"Moon",Leo:"Sun",Virgo:"Mercury",Libra:"Venus",Scorpio:"Mars",Sagittarius:"Jupiter",Capricorn:"Saturn",Aquarius:"Saturn",Pisces:"Jupiter"},s={Aries:"March 21 – April 19",Taurus:"April 20 – May 20",Gemini:"May 21 – June 20",Cancer:"June 21 – July 22",Leo:"July 23 – August 22",Virgo:"August 23 – September 22",Libra:"September 23 – October 22",Scorpio:"October 23 – November 21",Sagittarius:"November 22 – December 21",Capricorn:"December 22 – January 19",Aquarius:"January 20 – February 18",Pisces:"February 19 – March 20"},l={Aries:{majorArcana:"The Emperor",cardKey:"emperor",romanNumeral:"IV",arcanaNumber:4,title:"Lord of Flame and Lightning; King of the Spirit of Fire",description:"The Emperor represents the principle of order arising from chaos—the Martian fire of Aries shaped into governance, structure, and sovereign authority. He is the archetypal Father, the first principle of form-giving, the yang force that defines and defends. In Golden Dawn symbolism, he sits upon the Ram-headed throne, wielding the ankh and the orb, the life force organized into dominion.",jungian:"The Emperor embodies the father archetype in its fullest expression—the organizer of the psyche's raw energies into coherent identity. He represents the logos principle that structures the chaos of unconscious contents into directed will. In individuation, he appears when the ego must take authority over itself, establishing the inner king who rules without tyranny.",powerGods:"You are the Emperor because you have claimed what lesser wills abandoned. The Rams charge—but only you hold the throne. Let no one question your authority without earning that right through fire. The orb in your hand is the world; the staff is your decree. Every boundary you draw is law. Rule with certainty, for hesitation invites usurpers.",traditional:"The Emperor embodies sacred hierarchy—the divine right to order that flows from above and expresses below. He is the earthly representative of divine law, ruling by the mandate of heaven as interpreted through the traditions his predecessors established. Proper governance is holy governance: just, firm, and rooted in the eternal forms that precede him.",modern:"The Emperor is the CEO, the systems architect, the master strategist who transforms vision into organizational reality. He governs through clear roles, defined processes, and measurable accountability. His power comes not from force alone but from designing structures that scale, that outlast his tenure, that create order beyond his presence.",postModern:"Examine the Emperor's throne carefully—who built it, and at whose expense? Power must be interrogated. The good ruler asks: whose voices are absent from this council? Authority becomes tyranny when it stops questioning itself. True leadership decentralizes power while maintaining accountability. Hold authority lightly; governance is a service, not a possession.",metaModern:"The Emperor holds structure and chaos both—he knows his dominion is both necessary and provisional. He rules with conviction while remaining open to evolution. The laws he makes, he can unmake when they no longer serve life. He is both the system and the one who transcends the system to maintain it. Iron and water, form and flow."},Taurus:{majorArcana:"The Hierophant",cardKey:"hierophant",romanNumeral:"V",arcanaNumber:5,title:"Lord of the Mysteries of the Pentagram; Magus of the Eternal Gods",description:"The Hierophant represents the principle of sacred tradition—the bridge between divine revelation and human understanding. Venus-ruled Taurus grounds the celestial into the earthly through ceremony, teaching, and the transmission of wisdom through lineage. He is the keeper of the mysteries, the initiator who stands between worlds and passes the flame of knowledge from hand to hand across generations.",jungian:"The Hierophant represents the archetype of the Wise Elder or Senex—the carrier of collective wisdom, the personification of the superego at its most constructive. He appears in the psyche when the individual needs to connect with something larger than personal history: tradition, lineage, accumulated wisdom. In shadow, he becomes rigid dogma; in health, he offers the container that allows true growth.",powerGods:"Wisdom is power more enduring than muscle. You hold the keys that others cannot copy—the secret formulae, the initiatory knowledge, the codes that open doors sealed to the uninitiated. Others bow before you not from fear but from recognition of what you carry. Transmit your power selectively; knowledge given to the unready is power squandered.",traditional:"The Hierophant is the living repository of sacred law—the priest-king who interprets the eternal for the temporal age. Through him, the ancient teachings flow unbroken from the primordial revelation. Honor this role with humility; you are the vessel, not the source. The teachings trust you with their continuity. Guard them, teach them, live them faithfully.",modern:"The Hierophant is the master teacher, the institution-builder, the creator of curricula that transmit expertise across generations. He understands that knowledge must be systematized to scale. The mentor who creates mentors, the teacher who teaches teachers—this is how wisdom compounds across time. Build systems that outlast your personal tenure.",postModern:"The Hierophant's robes hide many things, including who was excluded from the tradition he carries. Question what is taught as universal truth—every tradition is also a perspective. The wisdom is real, but so is its partiality. Who gets to receive these teachings? What have the gatekeepers kept from the gates? Sacred knowledge should liberate, not bind.",metaModern:"The Hierophant bridges the ancient and the evolving—he carries tradition not as cage but as gift. He knows that sacred forms must periodically die to be reborn. He transmits the essence, not merely the letter. The true initiation is learning to hold wisdom and its questioning in the same hands, to be simultaneously devoted to and critical of the tradition that formed you."},Gemini:{majorArcana:"The Lovers",cardKey:"lovers",romanNumeral:"VI",arcanaNumber:6,title:"Lord of the Oracles of the Mighty Gods; Children of the Voice Divine",description:"The Lovers represents sacred choice, the union of opposites, and the oracular moment when the soul must choose its path. Mercury-ruled Gemini embodies the tension between duality—conscious and unconscious, angel and shadow, known and unknown. The blessing from above descends upon the archetypal couple, asking: will you integrate what you have kept separate?",jungian:"The Lovers represents the coniunctio—the sacred marriage of opposites in the psyche. It symbolizes the encounter with the anima/animus, the soul-complement that exists as our undiscovered half. This card appears when the individuation process requires integration of repressed aspects of self. The choice depicted is always between familiar limitation and the riskier wholeness of genuine union with one's shadow.",powerGods:"The fork in the road is yours alone. Choose with your fire, not with their fear. The angel above blesses both paths—but only the path you seize with full conviction becomes yours. Refuse the choice and you stand at the crossroads forever, prey to any wind. The strong choose. Then they make their choice the right one.",traditional:"The sacred union depicted here is blessed from above—this is covenant, consecrated by divine witness. The choice before you is not merely practical but eternal: what vows will you speak, what bonds will you honor? The traditions of marriage and alliance exist because some commitments are too weighty for personal judgment alone. Seek blessing before you bind.",modern:"The Lovers represents strategic alignment—the power of combining complementary capabilities to create outcomes neither could achieve alone. Whether partnership, merger, or alliance, the key is clear values-alignment and complementary strengths. Before committing, define terms explicitly. The best partnerships are built on honesty about what each brings and what each needs.",postModern:"All the beautiful complexity of the Lovers—the choice it presents holds more than it shows. The angel above blesses, but who wrote the angel's script? Examine who benefits from this union, what is surrendered, what is gained. Authentic love expands freedom; authentic partnership honors both parties' wholeness. The blessing should come from within as well as from above.",metaModern:"The Lovers holds every dimension of union—sacred vow and strategic alliance, shadow integration and tender connection, oracular choice and intimate commitment. The deepest love is conscious—knowing what you choose and why, carrying the full weight of that choice with clear eyes and an open heart. Choose completely. Let the choice choose you back."},Cancer:{majorArcana:"The Chariot",cardKey:"chariot",romanNumeral:"VII",arcanaNumber:7,title:"Child of the Powers of the Waters; Lord of the Triumph of Light",description:"The Chariot represents the triumph of will over opposing forces—the Moon-ruled Cancer energy channeled into purposeful motion. The Charioteer controls the black and white sphinxes not through force but through concentrated intent, steering between contradictions through the power of unified will. He carries the Holy Grail, the symbol of the emotional depths he has mastered without denying.",jungian:"The Chariot represents the ego triumphant in its solar phase—the conscious will that has learned to harness the opposing drives of the unconscious without crushing them. The Charioteer's armor is crystallized will; he has forged his inner contradictions into forward motion. This card appears when the psyche has reached a degree of integration sufficient to move purposefully through conflict.",powerGods:"You have tamed what others fled from—harnessed the opposing forces that would have torn lesser warriors apart. Now the city trembles as you pass through its gates. This is the victory of iron will: not that you destroyed the beasts, but that you made them serve you. The crown of stars is earned by those who turn contradiction into momentum.",traditional:"The Charioteer enters in triumph, crowned with stars, bearing the sacred vessel. This victory honors all the traditions of righteous conquest—the warrior who fights not for glory alone but for the sacred purpose that sent him forth. He returns not to boast but to fulfill the covenant of service that girded him for battle. Receive the triumph humbly, for it belongs to what sent you.",modern:"The Chariot represents mastery of execution—the project manager, the athlete, the leader who moves teams through impossible conditions through sheer coherence of intention. Direction clarity cuts through ambiguity; momentum compounds with each aligned step. The charioteer doesn't control everything—only the direction of unified will.",postModern:"The Chariot's triumph—but at what cost to the lands through which it has driven? Examine the victory: what voices were silenced, what paths were paved over? True leadership negotiates with the sphinxes; it doesn't merely subdue them. The stars in his crown represent possibility, not superiority. How do we win without dominating?",metaModern:"The Chariot integrates the triumphant will, the sacred victor, the execution master, and the one who questions the road—all steering together. The deepest triumph is not over others but over the parts of yourself that would stop you. The charioteer moves at the speed of integration, which is sometimes very fast and sometimes requires stillness."},Leo:{majorArcana:"Strength",cardKey:"strength",romanNumeral:"VIII",arcanaNumber:8,title:"Daughter of the Flaming Sword; Leader of the Lion",description:"Strength represents the mastery of primal force through love rather than violence—the Sun-ruled Leo energy expressed as radiant courage that transforms rather than subdues. The figure adorned with flowers opens the lion's mouth not through dominance but through the power of gentle certainty, demonstrating that the heart's strength exceeds the muscles' power. The infinite lemniscate above her head shows this is not personal power but cosmic force flowing through her.",jungian:"Strength represents the integration of the beast—the Shadow in its most primal form approached not with suppression or projection but with loving awareness. This is the anima in its solar aspect, the feminine principle that tames the masculine instinctual drives not by opposing them but by transforming them through relationship. The card appears when shadow integration is possible through compassion rather than confrontation.",powerGods:"Here is the truth no brute understands: the lion yields to the one who is not afraid. Your fire is so total that even the king of beasts feels it and bows. This is the highest dominance—not the conquest of the sword, but the radiance that makes conquest unnecessary. Your courage is a field that tames the wild places in everything around you.",traditional:"She opens the lion's mouth with serene faith—this is the grace that flows through the truly devoted. Her strength is not her own; it is borrowed from the sacred. The traditions of inner mastery all point here: the holy women who walked unafraid among the beasts, the saints whose purity rendered them untouchable by animal ferocity. Cultivate this interior flame.",modern:"Strength represents the psychological safety that enables high performance—the leader whose calm under pressure stabilizes the team, whose grounded confidence opens creative possibility. The infinite symbol above her head represents sustainable force, not sprint energy. Build cultures where courage is quiet, where conviction doesn't require volume, where excellence flows naturally from security.",postModern:"The lion and the maiden—but who wrote the roles? Strength is not only feminine gentleness taming masculine force; it is the integration of all our denied ferocities, the meeting of what we have split off with compassion. What lions have you caged? What roaring parts of yourself await your gentle recognition? True strength includes acknowledging the beast as your own.",metaModern:"Strength holds the solar hero, the holy tamer, the psychologically secure leader, and the shadow-integrator in one gesture of radical openness. The lemniscate indicates that this is not a one-time triumph but an ongoing practice. You open the lion's mouth every day. The strength is in continuing to return to that gesture of fearless love, again and again."},Virgo:{majorArcana:"The Hermit",cardKey:"hermit",romanNumeral:"IX",arcanaNumber:9,title:"Prophet of the Eternal; Magus of the Voice of Power",description:"The Hermit represents the inner light held aloft for the path that cannot be walked in company—the Mercury-ruled Virgo quality of refined analysis turned toward the deepest questions of existence. He stands on the mountain peak alone not because he is antisocial but because the altitude of his inquiry has left the crowd behind. His lantern contains a six-pointed star—the light of wisdom, not of certainty.",jungian:"The Hermit represents the archetype of the Wise Old Man—the Self manifesting as a guide from the depths of the unconscious. He appears in dreams and visions when the psyche has reached sufficient development to receive higher-order guidance. He is also the introvert's journey inward, the necessary retreat from persona and collective identity to encounter the autonomous inner voice that alone can orient truly.",powerGods:"The mountain is empty except for you—and that is the source of your power. The crowd below has comfort and noise; you have clarity and the lantern that cannot be blown out. The path you have walked has refined you past what average endurance allows. Let them wonder at your isolation. Solitude is not loneliness; it is the laboratory of the sovereign self.",traditional:"The Hermit walks the ancient paths of the desert fathers, the forest sages, the mountain recluses—those who withdrew from the world not in rejection but in love, seeking the silence in which the Divine speaks unmistakably. His lantern is prayer made visible. The light he carries was lit by those before him; he walks to pass it to those who will come.",modern:"The Hermit represents deep work—the focused withdrawal that produces insight unavailable in constant connection. In an attention economy, solitude is the ultimate competitive advantage. The analyst, the researcher, the philosopher who retreats to think clearly produces value that the perpetually distracted cannot access. Schedule the mountain; protect the lantern time.",postModern:"Who has access to the mountain? The Hermit's solitude is a privilege—the time and safety to withdraw from the demands of others requires resources not everyone possesses. Genuine wisdom asks: what am I learning in this solitude, and for whom? The light in the lantern is not for keeping. Inner work in service of nothing beyond itself can become spiritual narcissism.",metaModern:"The Hermit holds the wizard's solitude, the mystic's communion, the analyst's depth, and the servant's accountability—ascending alone while remaining connected to the human web below. He shines his lantern for those climbing behind him, not to direct their path but to remind them that ascent is possible. His wisdom includes knowing when to descend and return."},Libra:{majorArcana:"Justice",cardKey:"justice",romanNumeral:"XI",arcanaNumber:11,title:"Daughter of the Lords of Truth; Ruler of the Balance",description:"Justice represents cosmic law, the eternal scales upon which all actions are weighed—the Venus-ruled Libra energy expressed as absolute impartiality. The figure is seated between two pillars of the law, holding scales in perfect balance and a double-edged sword that cuts both ways. There is no mercy here that compromises truth, no truth that forgets compassion—only the exact measure of what is.",jungian:"Justice represents the archetype of the Self in its adjudicating function—the psyche's capacity to evaluate and integrate with impersonal accuracy. She appears when the individuation process requires honest self-assessment, when the ego must submit to a standard beyond its own preferences. The scales also represent the need to hold opposing truths simultaneously without forcing resolution.",powerGods:"The sword in Justice's hand is perfectly balanced and eternally sharp—because power that ignores its own consequences eventually falls on its wielder. The truly powerful understand that the laws they invoke will be applied to them. Govern yourself by the same code you impose on others; then your authority becomes unassailable, because it cannot be accused of hypocrisy.",traditional:"Justice embodies the eternal law that undergirds all righteous order—the principle that the Divine does not play favorites, that every action sets in motion its precise consequence. The traditions of sacred law exist to align human behavior with this cosmic principle. Submit your decisions to honest examination: would they hold in the divine court? What is weighed in the balance of eternity?",modern:"Justice represents systemic accountability—the processes, audits, and balancing mechanisms that keep organizations honest. Good governance requires both the sword (decisive action) and the scales (fair measurement). Build systems where outcomes are tracked, where equity is measured, where the data tells the story that preferences might suppress. Sustainable excellence requires honest evaluation.",postModern:"Justice must be interrogated: who designed these scales? Every legal system reflects the values of those who built it. True justice requires examining who benefits from the current balance, who has been systematically underweighted, what voices have been silenced by the sword. Restorative justice includes repairing harm to those the scales have failed. The balance must include everyone.",metaModern:"Justice holds the sword of fierce truth and the scales of compassionate balance simultaneously. She is impersonal enough to see clearly and personal enough to care about the particular human before her. She knows that perfect justice is asymptotic—always approached, never perfectly achieved. She acts anyway, with the best discrimination available, remaining open to revision."},Scorpio:{majorArcana:"Death",cardKey:"death",romanNumeral:"XIII",arcanaNumber:13,title:"Child of the Great Transformers; Lord of the Gates of Death",description:"Death represents the great transformer—the Mars-ruled Scorpio energy expressed as the irresistible force of ending that clears space for new beginning. The skeletal rider on the pale horse moves through every level of society: pope, king, maiden, child—none are exempt from transformation. The sun rises in the background, not despite the darkness but because of it.",jungian:"Death represents the archetype of transformation—the mercurial figure who guides the ego through necessary dissolution to the renewal of the Self. He appears when the psyche requires the death of an old identity—a persona, a complex, an attachment to a form that has outlived its function. This is never merely destructive; the Jungian death is always in service of deeper life.",powerGods:"Death comes for all, but you have made an ally of it. While lesser souls flee from endings, you dive into the heart of transformation and emerge changed—more dangerous than before. Every death in your life has refined you, stripped away what weakened you, left only what cannot be destroyed. You are not afraid of the pale horse. You ride it.",traditional:"Death's card is the thirteenth—the number of transformation in the sacred numerology, the number of the lunar cycle complete. This is the great mystery that all traditions address: what dies is not the soul but the shell. The devoted understand that endings are doorways. Release what must be released; trust the process that has carried countless souls through this threshold before you.",modern:"Death represents the strategic pivot, the sunset of obsolete business models, the necessity of killing what works adequately to make room for what works excellently. The organizations that fail to manage planned endings become unable to begin new things. Build exit protocols, sunset timelines, and healthy processes for letting go. Creative destruction is the engine of renewal.",postModern:"Not all deaths are equal, and not all transformations are chosen. Death has fallen more heavily on some communities than others, by design. Before we speak of transformation, we must grieve what has been unjustly ended. The card's impartiality is the aspiration, not the reality. Let the endings be witnessed, the losses mourned, the transformations honored in their full weight.",metaModern:"Death holds the transformer, the threshold guardian, the strategic ender, and the witness to grief—all riding together toward the sunrise. Every level of experience knows death differently, and each knowing is true. The metamodern relationship with death integrates all these—the warrior's embrace, the faithful's submission, the strategist's management, and the griever's protest—woven into acceptance of impermanence at the core of being alive."},Sagittarius:{majorArcana:"Temperance",cardKey:"temperance",romanNumeral:"XIV",arcanaNumber:14,title:"Daughter of the Reconcilers; Bringer-Forth of Life",description:"Temperance represents the angelic art of alchemical blending—the Jupiter-ruled Sagittarius energy expressed as the higher synthesis that transcends opposition. The great angel pours the waters of life between two cups in an endless circuit, one foot on land and one in water, mediating between worlds. The solar crown on her forehead and the triangle within the square on her breast represent the integration of spirit in matter.",jungian:"Temperance represents the transcendent function—the psyche's capacity to hold tension between opposites until a new symbol or attitude emerges that includes both. This is the alchemical operation of the unconscious: when the conscious mind cannot solve its contradictions, the deeper process combines the elements and precipitates something new. The angel is the Self working through the ego's willingness to remain in process.",powerGods:"You have learned what separates the merely powerful from the truly formidable: the art of mixture. Not water alone, nor fire alone—but the precise blend that creates something neither element could become alone. This is the alchemy of strategic genius. Your patience while working with what seems inert is what produces the gold that others cannot make.",traditional:"The angel of temperance embodies the sacred art of measure—the ancient wisdom that knows the proper proportion of all things. Virtue is the mean between extremes; character is built through the discipline of neither too much nor too little. The traditions speak of this angel as the keeper of divine timing, who pours the streams of life in exactly the measure that serves the sacred design.",modern:"Temperance represents the systems thinker who understands feedback loops, who can see that opposing forces can be configured as a circuit rather than a conflict. The innovator who synthesizes rather than chooses wins in complex environments. Build iterative processes where learning flows back into action. The angel's endless pouring is the iterative cycle—experiment, refine, experiment again.",postModern:"The angel mediates between worlds—but which worlds, and on whose terms? The synthesis Temperance offers must include the voices of those on the margins of both poles. What gets lost when we blend? What needs to remain distinct? True reconciliation doesn't always produce a third thing; sometimes it requires sitting with the discomfort of genuine difference.",metaModern:"Temperance holds the alchemist's patience, the sacred measurer's virtue, the systems thinker's feedback loop, and the reconciler's honest witness to difference—all flowing between the cups simultaneously. The angel's art is not to impose synthesis but to remain in the process until what wants to emerge, emerges. This is development as flow, growth as endless becoming."},Capricorn:{majorArcana:"The Devil",cardKey:"devil",romanNumeral:"XV",arcanaNumber:15,title:"Lord of the Gates of Matter; Child of the Forces of Time",description:"The Devil represents the Pan-force—the Saturn-ruled Capricorn energy expressing as the binding power of material existence, the shadow that accumulates through attachment to form. The chained figures can remove their bonds; they remain because they have forgotten their own freedom. The Devil holds the torch downward, inverting the spiritual flame into material obsession. Yet the pentagram on his forehead still points upward—matter contains spirit, not spirit's enemy.",jungian:"The Devil represents the personal and collective Shadow at its most condensed and seductive. He is the archetype of the Trickster fused with the Shadow—the compensatory force that accumulates everything the ego has denied, repressed, or refused to integrate. He appears in the psyche as compulsion, addiction, and the dark vitality that life denied takes its revenge through. Integration requires neither battle nor submission, but honest acknowledgment.",powerGods:"The chains you see are the chains you chose. Here is the secret the weak use as excuse and the strong use as key: you are bound by exactly as much as you consent to. The Devil shows you the bars you built and dares you to notice your hands could open the lock. The power is not in escaping bondage—it is in choosing which bonds serve your conquest and releasing those that don't.",traditional:"The Devil is the great tempter, the adversary who would bind the soul to the transient pleasures of matter and make you forget your eternal nature. The traditions all speak of this test—the desert, the wilderness, the threshold between the age of innocence and the age of choice. He can only hold you through consent. The answer to the adversary is always the same: remember who you are.",modern:"The Devil represents the systemic forces that trap productivity: perverse incentives, sunk cost fallacy, golden handcuffs, organizational cultures that punish truth-telling. See the chains clearly—what structures, incentives, or habituated patterns are consuming your energy? The torch points down because energy that should serve purpose is being consumed by the system itself. Redesign the system.",postModern:"The Devil's chains are not only personal—they are systemic, structural, historical. Many chains were not chosen; they were inherited through generations of oppression, poverty, trauma. We must distinguish between the chains we can simply choose to remove and the chains that require collective liberation. Shaming the chained for their chains is not freedom work—it is blame.",metaModern:"The Devil holds the power-seeker's key, the devotee's temptation, the analyst's systemic trap, and the advocate's call to collective liberation—all present at the same time. The chains are real and provisional, chosen and systemic, personal and political. True liberation works at every level simultaneously: claiming personal agency while engaging structural change, releasing attachment while acknowledging genuine constraint."},Aquarius:{majorArcana:"The Star",cardKey:"star",romanNumeral:"XVII",arcanaNumber:17,title:"Daughter of the Firmament; Dweller Between the Waters",description:"The Star represents cosmic hope and the nourishing flow of celestial grace—the Saturn/Uranus-ruled Aquarius energy expressed as the eternal pouring of universal waters for collective renewal. The naked figure kneels between the terrestrial and the cosmic, pouring water back into the earth and into the stream simultaneously. The great star above is surrounded by seven lesser stars—the seven planets whose energies she channels for the world's healing.",jungian:"The Star represents the anima in her most transpersonal aspect—the healing feminine principle that connects individual consciousness to the cosmic waters of the collective unconscious. She appears after the destruction of the Tower, offering the hope that emerges when ego has been dismantled enough for the larger Self to flow through. This card speaks to the restoration of meaning after crisis, the renewal of trust in the process.",powerGods:"You have survived what destroyed others, and now you pour your hard-won wisdom into the collective stream. This is the rarest power: the one who can nourish others without diminishing themselves, because their source is not personal but cosmic. Let your gifts flow freely; the star above ensures replenishment. Your abundance serves your authority.",traditional:"The Star is the celestial gift after the night's ordeal—the promise of the sacred that holds even when the earthly structures fail. She pours the divine waters back into the world, honoring both the material and the spiritual in a single gesture. This is the consecration of hope: the faith that the cosmos is fundamentally benevolent, that the waters of grace are inexhaustible.",modern:"The Star represents the visionary who rebuilds after failure with a clearer map—the social entrepreneur, the innovator who has survived enough setbacks to understand which waters to pour where. She is both grounded (one foot on earth) and connected to broader flows (one foot in water). Her optimization is for system health, not personal accumulation. Regenerative design.",postModern:"Who has access to the starlight? The naked figure's vulnerability is beautiful—and also a reminder that such openness is only safe in certain conditions. The waters she pours so freely—whose rivers does she draw from? Universal hope must be interrogated: whose hope, and at what cost? The Star's gift is real, but it requires the ground to be truly ready to receive it.",metaModern:"The Star holds the survivor's hard-won hope, the mystic's trust in cosmic benevolence, the strategist's regenerative vision, and the advocate's question about whose waters are whose—all flowing from her vessels simultaneously. Hope at its most mature is not naive but earned, tested, and poured deliberately. She shines because she has been through the dark and chosen to illuminate anyway."},Pisces:{majorArcana:"The Moon",cardKey:"moon",romanNumeral:"XVIII",arcanaNumber:18,title:"Ruler of Flux and Reflux; Child of the Sons of the Mighty",description:"The Moon represents the realm where reason dissolves and the deep unconscious speaks in image and symbol—the Jupiter/Neptune-ruled Pisces energy expressed as the threshold between worlds. The crayfish emerges from the primordial waters; the wolf and the dog howl at what they cannot comprehend; two towers mark the boundary of the known. The path between them leads into the unknowable beyond.",jungian:"The Moon represents the deepest layer of the collective unconscious—the primordial, pre-logical realm from which both the most numinous and the most disturbing contents arise. She is the night sea journey, the place where the hero must navigate without the sun's certainty. Her light is reflected, not original—illuminating just enough of the unconscious to walk through, never enough to eliminate the unknown.",powerGods:"In the dark, you have the advantage. Others need daylight to find their way; you have learned to navigate by the Moon's uncertain light, to read the messages of the waters, to follow the path that only shows itself step by step. This is the deepest strategic advantage: comfort with the unknown that makes you effective where others freeze with fear.",traditional:"The Moon is the realm of sacred mystery—the domain where the veil between worlds grows thin and the ancestors walk close. The traditions of dream interpretation, oracle, and vision all arise from this liminal space. Navigate with prayer and protection; not all that moves in the Moon's light is benevolent. The path between the towers is real, but it requires guidance from above to walk safely.",modern:"The Moon represents the unknown unknowns—the market forces not captured in the model, the user behaviors that confound the assumptions, the organizational dynamics hidden beneath the reported data. Comfort with ambiguity is a leadership competency. Not everything can be illuminated in advance; the skill is navigating effectively with incomplete information while remaining oriented toward the destination.",postModern:"The Moon's light reveals different things to different eyes. The crayfish emerging from the water—what has lived in the depths, unseen and unnamed? The path between the towers is not universal; it runs through territories that mean different things to different travelers. Liminal spaces are beautiful and dangerous in unequal measure for different communities. Who is safe in the moonlit threshold?",metaModern:"The Moon holds the navigator's comfort with darkness, the devotee's sacred mystery, the analyst's unknown unknowns, and the advocate's acknowledgment that the threshold is not neutral ground—all swirling in the reflected light. The deepest wisdom is not the elimination of uncertainty but the capacity to remain oriented within it, knowing that the path reveals itself step by step to those willing to walk without the guarantee of daylight."}}}}]);